// ── diagnostic formatting ─────────────────────────────────────────────────────

/// Format a type-check error with a `^^^` underline under the offending source token.
///
/// Output format:
/// ```text
/// error[E001]: Type mismatch
///   --> file.fav:5:10
///    |
///  5 |     let x = foo
///    |             ^^^
/// ```
fn format_diagnostic(source: &str, error: &crate::middle::checker::TypeError) -> String {
    let span = &error.span;
    let line_num = span.line as usize;
    let col = span.col as usize;
    let token_len = if span.end > span.start {
        span.end - span.start
    } else {
        1
    };

    // Try to extract the source line
    let source_line = source.lines().nth(line_num.saturating_sub(1)).unwrap_or("");

    // Width of the line number prefix (e.g. "5" → 1 char, "42" → 2 chars)
    let line_prefix = line_num.to_string();
    let padding = " ".repeat(line_prefix.len());

    // Underline: col is 1-based, so offset = col-1 spaces
    let col_offset = " ".repeat(col.saturating_sub(1));
    // Cap underline to not exceed the line length
    let max_len = source_line
        .len()
        .saturating_sub(col.saturating_sub(1))
        .max(1);
    let underline = "^".repeat(token_len.min(max_len).max(1));

    let mut out = format!(
        "error[{}]: {}\n  --> {}:{}:{}\n{} |\n{} | {}\n{} | {}{}",
        error.code,
        error.message,
        span.file,
        span.line,
        span.col,
        padding,
        line_prefix,
        source_line,
        padding,
        col_offset,
        underline,
    );
    for hint in &error.hints {
        out.push_str(&format!("\n  = ヒント: {}", hint));
    }
    for hint in get_help_text(error.code) {
        out.push_str(&format!("\n  = help: {}", hint));
    }
    out.push_str(&format!("\n  = 参照: https://favnir.dev/errors/{}", error.code));
    out
}

fn format_warning(source: &str, warning: &crate::middle::checker::TypeWarning) -> String {
    let span = &warning.span;
    let line_num = span.line as usize;
    let col = span.col as usize;
    let token_len = if span.end > span.start {
        span.end - span.start
    } else {
        1
    };

    let source_line = source.lines().nth(line_num.saturating_sub(1)).unwrap_or("");
    let line_prefix = line_num.to_string();
    let padding = " ".repeat(line_prefix.len());
    let col_offset = " ".repeat(col.saturating_sub(1));
    let max_len = source_line
        .len()
        .saturating_sub(col.saturating_sub(1))
        .max(1);
    let underline = "^".repeat(token_len.min(max_len).max(1));

    let mut out = format!(
        "warning[{}]: {}\n  --> {}:{}:{}\n{} |\n{} | {}\n{} | {}{}",
        warning.code,
        warning.message,
        span.file,
        span.line,
        span.col,
        padding,
        line_prefix,
        source_line,
        padding,
        col_offset,
        underline,
    );
    for hint in get_help_text(warning.code) {
        out.push_str(&format!("\n  = help: {}", hint));
    }
    out
}

fn render_warnings(
    source: &str,
    warnings: &[crate::middle::checker::TypeWarning],
    no_warn: bool,
) -> Vec<String> {
    if no_warn {
        Vec::new()
    } else {
        warnings.iter().map(|w| format_warning(source, w)).collect()
    }
}

/// Computes the Levenshtein (edit) distance between two strings (v31.2.0).
fn levenshtein(s: &str, t: &str) -> usize {
    let s: Vec<char> = s.chars().collect();
    let t: Vec<char> = t.chars().collect();
    let m = s.len();
    let n = t.len();
    let mut dp = vec![vec![0usize; n + 1]; m + 1];
    for i in 0..=m { dp[i][0] = i; }
    for j in 0..=n { dp[0][j] = j; }
    for i in 1..=m {
        for j in 1..=n {
            dp[i][j] = if s[i-1] == t[j-1] {
                dp[i-1][j-1]
            } else {
                1 + dp[i-1][j].min(dp[i][j-1]).min(dp[i-1][j-1])
            };
        }
    }
    dp[m][n]
}

/// Returns candidates within Levenshtein distance ≤ 2, up to 3 results (v31.2.0).
/// Note: results are in input order, not distance order.
/// Callers should pass a pre-sorted (e.g. alphabetical) candidates slice for consistent UX.
/// TODO(v31.3+): wire into E0001/E0007/E0011 error output via TypeError.hints.
#[allow(dead_code)]
fn suggest_similar<'a>(name: &str, candidates: &[&'a str]) -> Vec<&'a str> {
    let mut result: Vec<&'a str> = candidates
        .iter()
        .copied()
        .filter(|c| levenshtein(name, c) <= 2)
        .collect();
    result.truncate(3);
    result
}

/// Returns static help hints for a given error/warning code (v12.10.0).
fn get_help_text(code: &str) -> &'static [&'static str] {
    match code {
        "E0001" => &[
            "check the variable name for typos",
            "introduce the variable with `bind x <- expr`",
        ],
        "E0002" => &[
            "the condition must be a Bool expression",
        ],
        "E0003" => &[
            "declare the effect in the function signature: `fn foo() -> T { ... }`",
        ],
        "E0004" => &[
            "add the missing match arms to cover all cases",
        ],
        "E0005" => &[
            "check that the type annotation matches the inferred type",
        ],
        "E0006" => &[
            "all match arms must return the same type",
        ],
        "E0007" => &[
            "see available primitives: `fav doc --builtins`",
        ],
        "E0008" => &[
            "check the number of arguments matches the function signature",
        ],
        "E0009" => &[
            "the declared return type and the inferred body type must match",
            "add a type annotation or adjust the return value",
        ],
        "E0010" => &[
            "implement all required methods declared in the interface",
        ],
        "E0011" => &[
            "check the type name for typos; use `fav doc --builtins` to list built-in types",
        ],
        "E0012" => &[
            "check that the expression type matches the expected type",
        ],
        "E0013" => &[
            "fix the `where` validator expression",
        ],
        "E0014" => &[
            "add the missing `fn` declaration to the interface",
        ],
        "E0015" => &[
            "implement all required `fn` entries listed in the interface",
        ],
        "E0016" => &[
            "add the missing effect to the function signature: `fn foo() -> T { ... }`",
        ],
        "E0017" => &[
            "remove the unused effect declaration from the function signature",
        ],
        "E0018" => &[
            "use a different name: `bind x2 <- ...`",
            "or discard the value: `bind _ <- ...`",
        ],
        "E0019" => &[
            "remove the circular interface inheritance",
        ],
        "W001" => &[
            "prefix the name with `_` to suppress: `_unused`",
        ],
        "W004" => &[
            "use `chain x <- expr` to propagate errors automatically",
        ],
        "W006" => &[
            "use `chain _ <- expr` to propagate errors automatically",
            "or handle explicitly: `match expr { Ok(_) => ... Err(e) => ... }`",
        ],
        "W007" => &[
            "the returned Result must be handled or propagated",
        ],
        "W008" => &[
            "pass the capability as a ctx argument: `ctx.io.println(...)`",
            "ambient effects are E0023 errors in non-legacy mode (v13.8.0+)",
        ],
        "E0023" => &[
            "pass an io/db/storage capability through the function signature",
            "use `ctx.io.println(...)` instead of `IO.println(...)`",
            "use `--legacy` flag to allow ambient calls during migration",
        ],
        "E0024" => &[
            "call the intermediate transformation function first",
            "type state sequence is inferred from function signatures in this file",
            "use `--legacy` flag to downgrade E0024 to a warning during migration",
        ],
        "E0025" => &[
            "migrate to capability-context style: `fn load(ctx: LoadCtx) -> Result<Loaded, String>`",
            "run `fav migrate --from-effects <file>` to auto-migrate all `!Effect` signatures",
            "use `--legacy` flag to suppress E0025 during migration",
        ],
        "W009" => &[
            "migrate to capability interface: `chain rows <- ctx.db.query(ctx, ...)`",
            "direct Rune calls will be an error in v14.0",
        ],
        "W010" => &["split the stage into smaller, focused stages"],
        "W011" => &[
            "add `!Io` (or the appropriate effect) to the stage signature",
            "or pass the capability through a ctx argument",
        ],
        "W012" => &[
            "remove the unused type definition",
            "or make it `pub` if it is referenced externally",
        ],
        "W013" => &["use `List.filter_map(|x| { ... })` instead of chaining map and filter"],
        "W014" => &["bind directly from the inner expression without the `Result.ok(...)` wrapper"],
        "W015" => &[
            "rename the second binding to avoid the rebind",
            "or use `bind _` to intentionally discard a value",
        ],
        "W016" => &["add specific patterns before `_ =>`; if intentional, this is fine"],
        "W017" => &["extract the inner logic to a separate helper function to reduce nesting"],
        "W018" => &["extract the magic number to a named constant: `bind MAX_AMOUNT <- 9999`"],
        "W019" => &["use an f-string instead: `f\"{a}{b}{c}\"`"],
        "W020" => &["bind all required slots in the flw binding, or mark it as abstract"],
        "E0020" => &[
            "pass a value that implements the required capability interface",
            "available implementations: PostgresDb, SnowflakeDb, S3Storage, MockDb",
        ],
        "E0021" => &[
            "switch to a context that includes this capability",
            "LoadCtx provides: db(DbRead), io, env",
            "WriteCtx provides: db(DbWrite), storage, io, env",
            "MigrateCtx provides: db_read, db_write, io, env",
        ],
        "E0253" => &[
            "f-string 内で別の f-string を使うことはできません",
            "中間変数に束縛してください: `bind s <- f\"...\"`",
        ],
        "E0254" | "E0322" => &[
            "f-string には String / Int / Float / Bool のみ使用可能です",
            "他の型は事前に文字列化してください: `bind s <- my_val.to_string()`",
        ],
        "E0323" => &[
            "record spread の base は Record 型でなければなりません",
            "`{ ...base, key: val }` の base が Record 型かどうか確認してください",
        ],
        "E0327" => &[
            "record spread で上書きするフィールドが base Record に存在しません",
            "フィールド名のスペルミスがないか確認してください",
        ],
        "E0328" => &[
            "record spread の update フィールドに重複があります",
            "同じフィールド名を複数指定することはできません",
        ],
        _ => &[],
    }
}

fn check_single_file_legacy(
    path: &str,
    refresh_schemas: bool,
) -> (
    String,
    Vec<crate::middle::checker::TypeError>,
    Vec<crate::middle::checker::FavWarning>,
) {
    let source = load_file(path);
    let program = Parser::parse_str(&source, path).unwrap_or_else(|e| {
        eprintln!("{}", e);
        process::exit(1);
    });
    let mut checker = Checker::new();
    checker.schema_refresh = refresh_schemas;
    let (errors, mut warnings) = checker.check_with_self(&program);
    warnings.extend(partial_flw_warnings(&program));
    (source, errors, warnings)
}

fn check_single_file(
    path: &str,
    legacy: bool,
    refresh_schemas: bool,
) -> (
    String,
    Vec<crate::middle::checker::TypeError>,
    Vec<crate::middle::checker::FavWarning>,
) {
    if legacy {
        return check_single_file_legacy(path, refresh_schemas);
    }
    let source = load_file(path);
    let program = Parser::parse_str(&source, path).unwrap_or_else(|e| {
        eprintln!("{}", e);
        process::exit(1);
    });
    let prog_vm = crate::middle::ast_lower_checker::lower_program(&program);
    match crate::checker_fav_runner::run_checker_fav(prog_vm) {
        Ok(()) => (source, vec![], vec![]),
        Err(msgs) => {
            let errors = crate::checker_fav_runner::msgs_to_type_errors(msgs);
            (source, errors, vec![])
        }
    }
}

// ── file loading ──────────────────────────────────────────────────────────────

fn load_file(path: &str) -> String {
    std::fs::read_to_string(path).unwrap_or_else(|e| {
        eprintln!("error: cannot read `{}`: {}", path, e);
        process::exit(1);
    })
}

pub fn cmd_new(name: &str, template: &str) {
    if let Err(err) = try_cmd_new(name, template) {
        eprintln!("error: {}", err);
        process::exit(1);
    }
    println!("created {}", name);
    println!("next:");
    println!("  cd {}", name);
    match template {
        "lib" => println!("  fav test src/lib.test.fav"),
        _ => println!("  fav run src/main.fav"),
    }
}

