// ── module loading ────────────────────────────────────────────────────────────

/// Load a program and all its transitive imports, returning a merged list of
/// items (dependencies first). Used so the evaluator can see all definitions.
fn load_all_items(entry_path: &str, toml: Option<&FavToml>, root: Option<&Path>) -> Vec<ast::Item> {
    use std::collections::HashSet;

    let mut visited: HashSet<String> = HashSet::new();
    let mut all_items: Vec<ast::Item> = Vec::new();

    fn load_rec(
        path: &str,
        toml: Option<&FavToml>,
        root: Option<&Path>,
        visited: &mut HashSet<String>,
        all_items: &mut Vec<ast::Item>,
    ) {
        if visited.contains(path) {
            return;
        }
        visited.insert(path.to_string());

        let source = std::fs::read_to_string(path).unwrap_or_else(|e| {
            eprintln!("error: cannot read `{}`: {}", path, e);
            process::exit(1);
        });
        let program = Parser::parse_str(&source, path).unwrap_or_else(|e| {
            eprintln!("{}", e);
            process::exit(1);
        });

        // Recurse into imports first (dependency order)
        if let (Some(toml), Some(root)) = (toml, root) {
            let src_dir = toml.src_dir(root);
            for use_path in &program.uses {
                if use_path.len() < 2 {
                    continue;
                }
                let mod_path = use_path[..use_path.len() - 1].join(".");
                if mod_path == "std.states" {
                    continue;
                }
                let rel: PathBuf = mod_path.split('.').collect();
                let dep_file = src_dir.join(rel).with_extension("fav");
                let dep_str = dep_file.to_string_lossy().to_string();
                load_rec(&dep_str, Some(toml), Some(root), visited, all_items);
            }
            for item in &program.items {
                match item {
                    ast::Item::ImportDecl {
                        path: import_name,
                        is_rune,
                        ..
                    } => {
                        let dep_file = if *is_rune {
                            // 1. rune_modules/ first (v5.4.0)
                            let rune_dir = root.join("rune_modules").join(import_name.as_str());
                            if rune_dir.is_dir() {
                                crate::toml::rune_entry_file(&rune_dir, import_name)
                            } else {
                                // 2. traditional runes/ path (v4.1.0 fallback)
                                let dir = toml.runes_dir(root).join(import_name.as_str());
                                if dir.is_dir() {
                                    dir.join(format!("{import_name}.fav"))
                                } else {
                                    toml.runes_dir(root).join(format!("{import_name}.fav"))
                                }
                            }
                        } else {
                            root.join(import_name).with_extension("fav")
                        };
                        let dep_str = dep_file.to_string_lossy().to_string();
                        load_rec(&dep_str, Some(toml), Some(root), visited, all_items);
                    }
                    ast::Item::RuneUse { module, .. } => {
                        // Load sibling file within the same rune directory (v4.1.0)
                        let current_dir = std::path::Path::new(path)
                            .parent()
                            .unwrap_or(std::path::Path::new("."));
                        let mod_file = current_dir.join(format!("{module}.fav"));
                        if mod_file.exists() {
                            let dep_str = mod_file.to_string_lossy().to_string();
                            load_rec(&dep_str, Some(toml), Some(root), visited, all_items);
                        }
                    }
                    _ => {}
                }
            }
        } else {
            // Standalone mode (no fav.toml): resolve rune imports from rune_modules/
            // relative to the source file's directory (v5.4.0).
            let source_dir = std::path::Path::new(path)
                .parent()
                .unwrap_or(std::path::Path::new("."));
            for item in &program.items {
                if let ast::Item::ImportDecl {
                    path: import_name,
                    is_rune: true,
                    ..
                } = item
                {
                    let rune_dir = source_dir.join("rune_modules").join(import_name.as_str());
                    if rune_dir.is_dir() {
                        let entry = crate::toml::rune_entry_file(&rune_dir, import_name);
                        let dep_str = entry.to_string_lossy().to_string();
                        load_rec(&dep_str, None, None, visited, all_items);
                    }
                }
            }
        }

        // Add this file's items (excluding namespace/use declarations)
        for item in program.items {
            match &item {
                ast::Item::NamespaceDecl(..)
                | ast::Item::UseDecl(..)
                | ast::Item::RuneUse { .. }
                | ast::Item::ImportDecl { .. }
                | ast::Item::InterfaceDecl(..)
                | ast::Item::InterfaceImplDecl(..) => {}
                _ => all_items.push(item),
            }
        }
    }

    load_rec(entry_path, toml, root, &mut visited, &mut all_items);
    all_items
}

fn find_partial_flw_bindings(program: &ast::Program) -> Vec<(String, Vec<String>)> {
    let templates: std::collections::HashMap<String, ast::AbstractFlwDef> = program
        .items
        .iter()
        .filter_map(|item| match item {
            ast::Item::AbstractFlwDef(def) => Some((def.name.clone(), def.clone())),
            _ => None,
        })
        .collect();

    let mut out = Vec::new();
    for item in &program.items {
        let ast::Item::FlwBindingDef(fd) = item else {
            continue;
        };
        let Some(template) = templates.get(&fd.template) else {
            continue;
        };
        let bound: std::collections::HashSet<&str> =
            fd.bindings.iter().map(|(slot, _)| slot.as_str()).collect();
        let unbound: Vec<String> = template
            .slots
            .iter()
            .filter(|slot| !bound.contains(slot.name.as_str()))
            .map(|slot| slot.name.clone())
            .collect();
        if !unbound.is_empty() {
            out.push((fd.name.clone(), unbound));
        }
    }
    out
}

fn partial_flw_warnings(program: &ast::Program) -> Vec<crate::middle::checker::TypeWarning> {
    find_partial_flw_bindings(program)
        .into_iter()
        .filter_map(|(name, slots)| {
            program.items.iter().find_map(|item| match item {
                ast::Item::FlwBindingDef(fd) if fd.name == name => {
                    Some(crate::middle::checker::TypeWarning::new(
                        "W020",
                        format!(
                            "`{}` is a partial flw binding with unbound slots: {}",
                            name,
                            slots.join(", ")
                        ),
                        fd.span.clone(),
                    ))
                }
                _ => None,
            })
        })
        .collect()
}

fn ensure_no_partial_flw(program: &ast::Program) -> Result<(), String> {
    let partials = find_partial_flw_bindings(program);
    if partials.is_empty() {
        return Ok(());
    }
    let (name, slots) = &partials[0];
    Err(format!(
        "error[E050]: `{}` has unbound slots: {}\n  hint: bind remaining slots before running or building",
        name,
        slots.join(", ")
    ))
}

// ── project helpers ───────────────────────────────────────────────────────────

/// Find project root and entry point. Returns (entry_file, Option<(toml, root)>).
fn find_entry(file: Option<&str>) -> (String, Option<(FavToml, PathBuf)>) {
    if let Some(f) = file {
        return (f.to_string(), None);
    }
    // Project mode: look for fav.toml
    let cwd = std::env::current_dir().unwrap_or_else(|_| PathBuf::from("."));
    let root = FavToml::find_root(&cwd).unwrap_or_else(|| {
        eprintln!("error: no fav.toml found. Provide a file path or run from a project directory.");
        process::exit(1);
    });
    let toml = FavToml::load(&root).unwrap_or_else(|| {
        eprintln!("error: could not read fav.toml");
        process::exit(1);
    });
    let src_dir = toml.src_dir(&root);
    // Try src/main.fav then main.fav
    let entry = [src_dir.join("main.fav"), root.join("main.fav")]
        .into_iter()
        .find(|p| p.exists())
        .unwrap_or_else(|| {
            eprintln!("error: no main.fav found in `{}`", src_dir.display());
            process::exit(1);
        });
    (entry.to_string_lossy().to_string(), Some((toml, root)))
}

fn checkpoint_backend_from_config(
    config: Option<&CheckpointConfig>,
    root: &Path,
) -> CheckpointBackend {
    match config.map(|c| c.backend.as_str()) {
        Some("sqlite") => {
            let rel = config
                .map(|c| c.path.as_str())
                .unwrap_or(".fav_checkpoints.db");
            CheckpointBackend::Sqlite {
                path: root.join(rel),
            }
        }
        _ => {
            let rel = config
                .map(|c| c.path.as_str())
                .unwrap_or(".fav_checkpoints");
            CheckpointBackend::File {
                dir: root.join(rel),
            }
        }
    }
}

/// Determine project root for schemas/*.yaml loading (v4.1.5).
/// Uses fav.toml discovery if available, otherwise falls back to the file's parent directory.
fn schemas_root(file: Option<&str>) -> PathBuf {
    let cwd = std::env::current_dir().unwrap_or_else(|_| PathBuf::from("."));
    let start = file
        .map(PathBuf::from)
        .and_then(|p| p.parent().map(|par| par.to_path_buf()))
        .unwrap_or(cwd.clone());
    if let Some(root) = FavToml::find_root(&start) {
        return root;
    }
    start
}

/// Load custom log codes from logs/*.yaml in the project root (v4.6.0).
fn load_log_codes(root: &std::path::Path) -> std::collections::HashMap<String, String> {
    let logs_dir = root.join("logs");
    let mut codes = std::collections::HashMap::new();
    let entries = match std::fs::read_dir(&logs_dir) {
        Ok(e) => e,
        Err(_) => return codes,
    };
    for entry in entries.flatten() {
        let path = entry.path();
        if path.extension().and_then(|e| e.to_str()) != Some("yaml") {
            continue;
        }
        if let Ok(content) = std::fs::read_to_string(&path) {
            if let Ok(yaml) = serde_yaml::from_str::<serde_yaml::Value>(&content) {
                if let Some(map) = yaml.as_mapping() {
                    for (k, v) in map {
                        if let (Some(code), Some(msg)) =
                            (k.as_str(), v.get("message").and_then(|m| m.as_str()))
                        {
                            codes.insert(code.to_string(), msg.to_string());
                        }
                    }
                }
            }
        }
    }
    codes
}

fn load_checkpoint_config_for_file(file: Option<&str>) {
    let cwd = std::env::current_dir().unwrap_or_else(|_| PathBuf::from("."));
    let start = file
        .map(PathBuf::from)
        .and_then(|p| p.parent().map(|parent| parent.to_path_buf()))
        .unwrap_or(cwd);
    if let Some(root) = FavToml::find_root(&start) {
        if let Some(toml) = FavToml::load(&root) {
            set_checkpoint_backend(checkpoint_backend_from_config(
                toml.checkpoint.as_ref(),
                &root,
            ));
            return;
        }
    }
    set_checkpoint_backend(CheckpointBackend::File {
        dir: PathBuf::from(".fav_checkpoints"),
    });
}

/// Collect all .fav files under a directory recursively.
fn collect_fav_files(dir: &Path) -> Vec<PathBuf> {
    let mut out = Vec::new();
    if let Ok(rd) = std::fs::read_dir(dir) {
        for entry in rd.flatten() {
            let path = entry.path();
            if path.is_dir() {
                out.extend(collect_fav_files(&path));
            } else if path.extension().and_then(|e| e.to_str()) == Some("fav") {
                out.push(path);
            }
        }
    }
    out.sort();
    out
}

fn make_resolver(toml: Option<FavToml>, root: Option<PathBuf>) -> Arc<Mutex<Resolver>> {
    Arc::new(Mutex::new(Resolver::new(toml, root)))
}

/// Returns true if the program contains any `import rune` declarations.
fn has_rune_imports(program: &ast::Program) -> bool {
    program
        .items
        .iter()
        .any(|item| matches!(item, ast::Item::ImportDecl { is_rune: true, .. }))
}

fn load_and_check_program(file: Option<&str>) -> (ast::Program, String) {
    let (path, proj) = find_entry(file);
    let source = load_file(&path);

    let program = Parser::parse_str(&source, &path).unwrap_or_else(|e| {
        eprintln!("{}", e);
        process::exit(1);
    });

    let uses_std_states = program
        .uses
        .iter()
        .any(|path| path.len() >= 2 && path[0] == "std" && path[1] == "states");
    let needs_resolver = uses_std_states || has_rune_imports(&program);

    let errors = if let Some((ref toml, ref root)) = proj {
        let r = make_resolver(Some(toml.clone()), Some(root.clone()));
        let mut checker = Checker::new_with_resolver(r, PathBuf::from(&path));
        checker.check_with_self(&program).0
    } else if needs_resolver {
        // Standalone with rune imports or std.states: use resolver with CWD-based rune_modules/.
        let r = make_resolver(None, None);
        let mut checker = Checker::new_with_resolver(r, PathBuf::from(&path));
        checker.check_with_self(&program).0
    } else {
        Checker::check_program(&program).0
    };
    if !errors.is_empty() {
        for e in &errors {
            eprintln!("{}", format_diagnostic(&source, e));
        }
        process::exit(1);
    }

    let merged = if let Some((ref toml, ref root)) = proj {
        let items = load_all_items(&path, Some(toml), Some(root));
        ast::Program {
            namespace: program.namespace.clone(),
            uses: program.uses.clone(),
            items,
        }
    } else if has_rune_imports(&program) {
        // Standalone: merge rune items from rune_modules/ (v5.4.0).
        let items = load_all_items(&path, None, None);
        ast::Program {
            namespace: program.namespace.clone(),
            uses: program.uses.clone(),
            items,
        }
    } else {
        program
    };

    (merged, path)
}

// ── fav run ───────────────────────────────────────────────────────────────────

/// Execute pre-compiled FVC bytecode via the Rust VM.
/// Shared by `run_with_favnir_pipeline` and `run_with_favnir_pipeline_project`.
fn run_fvc_bytes(bytes: &[u8], db_url: Option<&str>, source_path: Option<&str>) {
    let artifact =
        crate::backend::artifact::FvcArtifact::from_bytes(bytes).unwrap_or_else(|e| {
            eprintln!("artifact deserialization error: {:?}", e);
            process::exit(1);
        });
    exec_artifact_main_with_source(&artifact, db_url, source_path).unwrap_or_else(|message| {
        eprintln!("{message}");
        process::exit(1);
    });
}

/// Type-check a merged source string via checker.fav.
fn check_source_str(src: &str) -> Vec<crate::middle::checker::TypeError> {
    let program = Parser::parse_str(src, "project.fav").unwrap_or_else(|e| {
        eprintln!("error: {}", e);
        process::exit(1);
    });
    let prog_vm = crate::middle::ast_lower_checker::lower_program(&program);
    match crate::checker_fav_runner::run_checker_fav(prog_vm) {
        Ok(()) => vec![],
        Err(msgs) => crate::checker_fav_runner::msgs_to_type_errors(msgs),
    }
}

/// Favnir pipeline: checker.fav + compiler.fav + Rust VM.
/// Used for single-file programs not in project mode (rune imports are handled
/// by collect_merged_sources in compiler_fav_runner, v8.6.0).
fn run_with_favnir_pipeline(source_path: &str, db_url: Option<&str>) {
    // Type-check via checker.fav
    let (source, errors, _) = check_single_file(source_path, false, false);
    if !errors.is_empty() {
        for e in &errors {
            eprintln!("{}", format_diagnostic(&source, e));
        }
        #[cfg(not(target_arch = "wasm32"))]
        crate::otel::otel_flush_if_enabled();
        process::exit(1);
    }
    // Compile via compiler.fav (rune-import-aware, v8.6.0)
    let bytes =
        crate::compiler_fav_runner::compile_file_to_bytes_rune(source_path).unwrap_or_else(|e| {
            eprintln!("compiler.fav error: {}", e);
            #[cfg(not(target_arch = "wasm32"))]
            crate::otel::otel_flush_if_enabled();
            process::exit(1);
        });
    run_fvc_bytes(&bytes, db_url, Some(source_path));
}

/// Favnir pipeline for fav.toml project mode (v8.11.0).
/// Merges all project sources, type-checks, compiles via compiler.fav, and runs.
fn run_with_favnir_pipeline_project(
    source_path: &str,
    root: &std::path::Path,
    toml: &crate::toml::FavToml,
    db_url: Option<&str>,
) {
    // Inject fav.toml [snowflake] settings as env vars (v10.7.0)
    if let Some(sf_cfg) = &toml.snowflake {
        inject_snowflake_config(sf_cfg);
    }
    // Inject fav.toml [postgres] settings as env vars (v12.6.0)
    if let Some(pg_cfg) = &toml.postgres {
        inject_postgres_config(pg_cfg);
    }
    // Inject fav.toml [azure] settings as env vars (v14.2.0)
    if let Some(az_cfg) = &toml.azure {
        inject_azure_config(az_cfg);
    }
    // Inject fav.toml [gcp] settings as env vars (v15.2.0)
    if let Some(gcp_cfg) = &toml.gcp {
        inject_gcp_config(gcp_cfg);
    }
    // Inject fav.toml [kafka] settings as env vars (v15.4.0)
    if let Some(kafka_cfg) = &toml.kafka {
        inject_kafka_config(kafka_cfg);
    }

    // 1. Collect and merge all project sources
    let merged =
        crate::compiler_fav_runner::collect_project_merged(source_path, root, toml)
            .unwrap_or_else(|e| {
                eprintln!("error: {}", e);
                #[cfg(not(target_arch = "wasm32"))]
                crate::otel::otel_flush_if_enabled();
                process::exit(1);
            });

    // 2. Type-check the merged source via checker.fav
    let errors = check_source_str(&merged);
    if !errors.is_empty() {
        for e in &errors {
            eprintln!("{}", format_diagnostic(&merged, e));
        }
        #[cfg(not(target_arch = "wasm32"))]
        crate::otel::otel_flush_if_enabled();
        process::exit(1);
    }

    // 3. Compile merged source → FVC bytecode
    let bytes = crate::compiler_fav_runner::compile_src_str_to_bytes(&merged)
        .unwrap_or_else(|e| {
            eprintln!("compiler.fav error: {}", e);
            #[cfg(not(target_arch = "wasm32"))]
            crate::otel::otel_flush_if_enabled();
            process::exit(1);
        });

    // 4. Execute
    run_fvc_bytes(&bytes, db_url, Some(source_path));
}

/// Load fav.toml config and resolve verbose level (v12.5.0).
/// `verbose` / `trace` CLI flags override `[run] verbose / trace` in fav.toml.
/// Returns the effective verbose_level (0=off, 1=verbose, 2=trace).
fn load_run_config_verbose(file: Option<&str>, verbose: bool, trace: bool) -> u8 {
    load_run_config(file);
    // CLI flags take precedence; otherwise check fav.toml [run] section
    if trace {
        return 2;
    }
    if verbose {
        return 1;
    }
    // Check fav.toml
    if let Some(f) = file {
        if let Some(root) = crate::toml::FavToml::find_root(
            std::path::Path::new(f)
                .parent()
                .unwrap_or(std::path::Path::new(".")),
        ) {
            if let Some(toml) = crate::toml::FavToml::load(&root) {
                if let Some(ref run_cfg) = toml.run {
                    if run_cfg.trace   { return 2; }
                    if run_cfg.verbose { return 1; }
                }
            }
        }
    }
    0
}

/// Load fav.toml config (auth / log / env / aws) for the given source file.
/// Shared by both Favnir and Rust pipeline paths.
fn load_run_config(file: Option<&str>) {
    load_checkpoint_config_for_file(file);
    set_schema_registry(load_schemas(&schemas_root(file)));
    if let Some(f) = file {
        if let Some(root) = crate::toml::FavToml::find_root(
            std::path::Path::new(f)
                .parent()
                .unwrap_or(std::path::Path::new(".")),
        ) {
            if let Some(toml) = crate::toml::FavToml::load(&root) {
                if let Some(auth) = toml.auth.as_ref() {
                    set_auth_mode(&auth.mode);
                }
                if let Some(lc) = toml.log.as_ref() {
                    set_log_config(LogConfig {
                        level: lc.level.clone(),
                        format: lc.format.clone(),
                        output: lc.output.clone(),
                        service: lc.service.clone(),
                    });
                }
                set_log_codes(load_log_codes(&root));
                if let Some(ref ec) = toml.env {
                    if let Some(ref dotenv_path) = ec.dotenv {
                        let dp = root.join(dotenv_path);
                        if dp.exists() {
                            if let Ok(content) = std::fs::read_to_string(&dp) {
                                for (k, v) in parse_dotenv_content(&content) {
                                    if std::env::var(&k).is_err() {
                                        // SAFETY: single-threaded startup; no other threads read env here
                                        unsafe {
                                            std::env::set_var(&k, &v);
                                        }
                                    }
                                }
                            }
                        }
                    }
                    set_env_config(EnvConfig {
                        dotenv: ec.dotenv.clone(),
                        prefix: ec.prefix.clone(),
                    });
                }
                let mut aws_cfg = AwsConfig::from_env();
                if let Some(ac) = toml.aws.as_ref() {
                    if let Some(r) = &ac.region {
                        aws_cfg.region = r.clone();
                    }
                    if let Some(e) = &ac.endpoint_url {
                        aws_cfg.endpoint_url = Some(e.clone());
                    }
                }
                set_aws_config(aws_cfg);
                // Inject [snowflake] settings as env vars (v10.7.0)
                if let Some(sf_cfg) = toml.snowflake.as_ref() {
                    inject_snowflake_config(sf_cfg);
                }
                // Inject [postgres] settings as env vars (v12.6.0)
                if let Some(pg_cfg) = toml.postgres.as_ref() {
                    inject_postgres_config(pg_cfg);
                }
                // Inject [azure] settings as env vars (v14.2.0)
                if let Some(az_cfg) = toml.azure.as_ref() {
                    inject_azure_config(az_cfg);
                }
                // Inject [gcp] settings as env vars (v15.2.0)
                if let Some(gcp_cfg) = toml.gcp.as_ref() {
                    inject_gcp_config(gcp_cfg);
                }
                // Inject [kafka] settings as env vars (v15.4.0)
                if let Some(kafka_cfg) = toml.kafka.as_ref() {
                    inject_kafka_config(kafka_cfg);
                }
            }
        }
    }
}

/// Returns true if the Favnir value represents a `Result.err(...)` variant.
/// Used in cmd_run (--legacy) to detect failed main results and exit 1.
pub(crate) fn is_result_err_value(v: &Value) -> bool {
    matches!(v, Value::Variant(tag, _) if tag == "err")
}

/// `fav run [--legacy] [--verbose] [--trace] <file>`
///
/// Default (`legacy = false`): Favnir pipeline (checker.fav + compiler.fav)
/// for single-file programs.  Falls back to Rust pipeline automatically when:
///
/// - `--legacy` is set, OR
/// - the file is part of a fav.toml project, OR
/// - the file uses `import rune` declarations.
pub fn cmd_run(file: Option<&str>, db_url: Option<&str>, legacy: bool, verbose: bool, trace: bool, no_tap: bool, legacy_value_repr: bool, explain_pushdown: bool, checkpoint_dir: Option<&str>, resume_dir: Option<&str>) {
    let verbose_level = load_run_config_verbose(file, verbose, trace);

    if no_tap {
        crate::middle::compiler::set_no_tap_mode(true);
    }

    // v20.4.0: --explain-pushdown — enable pushdown logging
    if explain_pushdown {
        crate::backend::vm::set_pushdown_explain(true);
    }

    // v20.3.0: --legacy-value-repr は NaN-boxing 移行検証用フラグ（現時点は no-op）
    let _ = legacy_value_repr;

    // v22.1.0: Checkpoint / Resume setup
    {
        let checkpoint_stages = file
            .and_then(|f| std::fs::read_to_string(f).ok())
            .map(|src| {
                let file_name = file.unwrap_or("<input>");
                let tokens = crate::frontend::lexer::Lexer::new(&src, file_name)
                    .tokenize()
                    .unwrap_or_default();
                crate::frontend::parser::Parser::new(tokens)
                    .parse_program()
                    .map(|prog| {
                        prog.items.iter().filter_map(|item| {
                            if let crate::ast::Item::TrfDef(td) = item {
                                if td.checkpoint { Some(td.name.clone()) } else { None }
                            } else { None }
                        }).collect::<std::collections::HashSet<_>>()
                    })
                    .unwrap_or_default()
            })
            .unwrap_or_default();
        crate::backend::vm::set_checkpoint_stages(checkpoint_stages);
        crate::backend::vm::set_checkpoint_dir(checkpoint_dir);
        crate::backend::vm::set_resume_dir(resume_dir);
    }

    // v22.2.0: Worker endpoints from fav.toml [workers]
    {
        let worker_endpoints = file
            .and_then(|f| std::path::Path::new(f).parent())
            .and_then(|dir| crate::toml::FavToml::find_root(dir))
            .and_then(|root| crate::toml::FavToml::load(&root))
            .and_then(|toml| toml.workers)
            .map(|w| w.endpoints)
            .unwrap_or_default();
        crate::backend::vm::set_worker_endpoints(worker_endpoints);
    }

    // v22.3.0: State backend from fav.toml [state]
    {
        let state_backend = file
            .and_then(|f| std::path::Path::new(f).parent())
            .and_then(|dir| crate::toml::FavToml::find_root(dir))
            .and_then(|root| crate::toml::FavToml::load(&root))
            .and_then(|toml| toml.state)
            .map(|s| if s.backend.is_empty() { "memory".to_string() } else { s.backend })
            .unwrap_or_else(|| "memory".to_string());
        crate::backend::vm::set_state_backend(&state_backend);
    }

    // v9.0.0: --legacy is deprecated. Warn if used.
    if legacy {
        eprintln!("warning: --legacy is deprecated since v9.0.0 and will be removed in a future version.");
        eprintln!("         The Favnir pipeline (checker.fav + compiler.fav) handles all modes.");
    }

    // Decide which pipeline to use.
    // v8.11.0: project mode now uses Favnir pipeline via compile_project_to_bytes.
    // Only --legacy forces Rust pipeline.
    let (source_path, proj) = find_entry(file);
    let use_favnir = !legacy;

    // Set global verbose level before pipeline execution (v12.5.0)
    crate::backend::vm::set_verbose_level(verbose_level);
    // v22.7.0: OTel 初期化（trace フラグが立っているとき）
    #[cfg(not(target_arch = "wasm32"))]
    if trace {
        crate::otel::otel_init();
    }

    if use_favnir {
        if let Some((ref toml, ref root)) = proj {
            run_with_favnir_pipeline_project(&source_path, root, toml, db_url);
        } else {
            run_with_favnir_pipeline(&source_path, db_url);
        }
        // v20.4.0: --explain-pushdown — Favnir pipeline path
        if explain_pushdown {
            let log = crate::backend::vm::take_pushdown_log();
            if log.is_empty() {
                eprintln!("[pushdown] No pushdown patterns applied.");
            } else {
                for entry in &log {
                    eprintln!("{entry}");
                }
            }
        }
    } else {
        // Rust pipeline (--legacy)
        let (run_program, source_path2) = load_and_check_program(file);
        ensure_no_partial_flw(&run_program).unwrap_or_else(|message| {
            eprintln!("{message}");
            process::exit(1);
        });
        let artifact = build_artifact_legacy(&run_program);
        let result = exec_artifact_main_with_source(&artifact, db_url, Some(&source_path2))
            .unwrap_or_else(|message| {
                eprintln!("{message}");
                process::exit(1);
            });
        // If main returned Result.err(...), print the error and exit 1.
        if let Value::Variant(ref tag, ref payload) = result {
            if tag == "err" {
                let msg = payload.as_deref().map(|v| v.repr()).unwrap_or_default();
                eprintln!("error: {msg}");
                process::exit(1);
            }
        }

        // v20.4.0: --explain-pushdown — legacy pipeline path
        if explain_pushdown {
            let log = crate::backend::vm::take_pushdown_log();
            if log.is_empty() {
                eprintln!("[pushdown] No pushdown patterns applied.");
            } else {
                for entry in &log {
                    eprintln!("{entry}");
                }
            }
        }
    }
    // v22.7.0: OTel エクスポート（run 完了後）
    #[cfg(not(target_arch = "wasm32"))]
    if trace {
        match std::env::var("OTEL_EXPORTER_OTLP_ENDPOINT") {
            Ok(ep) => crate::otel::otel_export_http(&ep),
            Err(_) => crate::otel::otel_export_stdout(),
        }
        crate::otel::otel_reset();
    }
}

// ── fav run --self-host (backward-compat alias) ────────────────────────────────
// --self-host is now the default behaviour of `fav run` for single-file programs.
// This function is kept for backward compatibility; it simply delegates to cmd_run
// with legacy=false.

pub fn cmd_run_self_hosted(file: Option<&str>, db_url: Option<&str>) {
    cmd_run(file, db_url, false, false, false, false, false, false, None, None);
}

// ── v21.1.0: DAP デバッガー ───────────────────────────────────────────────────

/// DAP サーバーを指定ポートで起動する（`fav dap [--port N]`）。
/// VS Code 等の DAP クライアントが接続するのを待ち受ける。
#[cfg(not(target_arch = "wasm32"))]
pub fn cmd_dap(port: u16) -> Result<(), String> {
    use std::sync::{Arc, Condvar, Mutex};
    let session = Arc::new(Mutex::new(crate::dap::DapSession::new()));
    let vm_block = Arc::new((Mutex::new(false), Condvar::new()));
    crate::dap::run_dap_server(port, session, vm_block, None)
}

/// デバッグモードで .fav ファイルを実行する（`fav run --debug <file>`）。
/// DAP サーバーを別スレッドで起動し、VM と DapSession を共有する。
#[cfg(not(target_arch = "wasm32"))]
pub fn cmd_run_debug(file: &str, dap_port: u16) {
    // 1. ソースをコンパイルして FvcArtifact を生成
    let bytes =
        crate::compiler_fav_runner::compile_file_to_bytes_rune(file).unwrap_or_else(|e| {
            eprintln!("compiler.fav error: {e}");
            process::exit(1);
        });
    let artifact =
        crate::backend::artifact::FvcArtifact::from_bytes(&bytes).unwrap_or_else(|e| {
            eprintln!("artifact error: {:?}", e);
            process::exit(1);
        });

    // 2. DapAdapter を作成（Arc<Mutex<DapSession>> を内包）
    let adapter = crate::dap::DapAdapter::new();

    // 3. DAP サーバーを別スレッドで起動（session + vm_block を共有）
    //    ready_tx/rx で「サーバーが accept 待機に入った」ことを同期する（HIGH-3 競合回避）
    let shared_session = adapter.session.clone();
    let shared_vm_block = adapter.vm_block.clone();
    let (ready_tx, ready_rx) = std::sync::mpsc::sync_channel(0);
    std::thread::spawn(move || {
        let _ = crate::dap::run_dap_server(dap_port, shared_session, shared_vm_block, Some(ready_tx));
    });
    // サーバーが TcpListener::bind 完了 → accept 待機に入るまで待つ
    let _ = ready_rx.recv();

    // 4. VM を debug_mode で起動して実行
    let main_idx = match artifact.fn_idx_by_name("main") {
        Some(idx) => idx,
        None => {
            eprintln!("error: artifact does not contain a `main` function");
            process::exit(1);
        }
    };
    let mut vm = crate::backend::vm::VM::new_with_db_path(&artifact, None);
    vm.set_source_file(file);
    vm.debug_mode = true;
    vm.dap_adapter = Some(adapter);

    let args = if artifact.functions[main_idx].param_count == 1 {
        vec![crate::backend::vm::VMValue::Record(std::collections::HashMap::new())]
    } else {
        vec![]
    };

    if let Err(e) = vm.run_debug(&artifact, main_idx, args) {
        eprintln!("runtime error: {}", e.message);
        process::exit(1);
    }
}


pub fn cmd_build(file: Option<&str>, out: Option<&str>, target: Option<&str>) {
    if matches!(target, Some("graphql")) {
        let file = file.unwrap_or_else(|| {
            eprintln!("error: build --graphql requires a source file");
            process::exit(1);
        });
        cmd_build_graphql(file, out);
        return;
    }
    if matches!(target, Some("proto")) {
        let file = file.unwrap_or_else(|| {
            eprintln!("error: build --proto requires a source file");
            process::exit(1);
        });
        cmd_build_proto(file, out);
        return;
    }
    let (program, path) = load_and_check_program(file);
    ensure_no_partial_flw(&program).unwrap_or_else(|message| {
        eprintln!("{message}");
        process::exit(1);
    });
    let target = target.unwrap_or("fvc");
    match target {
        "fvc" => {
            let out_path = out
                .map(PathBuf::from)
                .unwrap_or_else(|| PathBuf::from(&path).with_extension("fvc"));

            // ── v19.3.0: インクリメンタルキャッシュ ──────────────────────────
            let no_cache = std::env::var("FAV_NO_CACHE").map(|v| v == "1").unwrap_or(false);
            let explain_cache =
                std::env::var("FAV_EXPLAIN_CACHE").map(|v| v == "1").unwrap_or(false);
            let file_hash = crate::incremental::fingerprint::file_hash(std::path::Path::new(&path))
                .unwrap_or_default();
            let cache_root = std::path::Path::new(&path)
                .parent()
                .unwrap_or(std::path::Path::new("."));
            let cache = crate::incremental::cache::IncrementalCache::new(cache_root);

            if !no_cache && !file_hash.is_empty() && cache.is_hit(&file_hash) {
                if explain_cache {
                    eprintln!("[cache HIT]  {}  ({}...)", path, &file_hash[..8]);
                }
                if let Ok(cached) = cache.read_artifact(&file_hash) {
                    write_artifact_to_path(&cached, &out_path).unwrap_or_else(|message| {
                        eprintln!("{message}");
                        process::exit(1);
                    });
                    println!("built {} (cached)", out_path.display());
                    return;
                }
            }

            if explain_cache {
                eprintln!("[cache MISS] {}  ({}...)", path, &file_hash[..8.min(file_hash.len())]);
            }
            let artifact = build_artifact(&program);
            if !no_cache && !file_hash.is_empty() {
                cache.write_artifact(&file_hash, &artifact).ok();
            }
            // ── キャッシュ統合ここまで ─────────────────────────────────────────

            write_artifact_to_path(&artifact, &out_path).unwrap_or_else(|message| {
                eprintln!("{message}");
                process::exit(1);
            });

            println!("built {}", out_path.display());
        }
        "wasm" => {
            let out_path = out
                .map(PathBuf::from)
                .unwrap_or_else(|| PathBuf::from(&path).with_extension("wasm"));
            let bytes = build_wasm_artifact(&program).unwrap_or_else(|message| {
                eprintln!("{message}");
                process::exit(1);
            });
            write_wasm_to_path(&bytes, &out_path).unwrap_or_else(|message| {
                eprintln!("{message}");
                process::exit(1);
            });
            println!("built {} (wasm)", out_path.display());
        }
        "native" => {
            let out_path = out.unwrap_or_else(|| {
                eprintln!("error: --target native requires -o <output>");
                process::exit(1);
            });
            let ir = compile_program(&program);
            crate::backend::cranelift_aot::CraneliftBackend::compile_to_binary(&ir, out_path)
                .unwrap_or_else(|e| {
                    eprintln!("error: AOT compilation failed: {e}");
                    process::exit(1);
                });
            println!("built {out_path} (native)");
        }
        other => {
            eprintln!("error: unsupported build target `{}`", other);
            process::exit(1);
        }
    }
}

/// Helper for tests: parse + compile + AOT link to a native binary.
pub(crate) fn cmd_build_native(src_path: &str, out_path: &str) -> Result<(), String> {
    let source =
        std::fs::read_to_string(src_path).map_err(|e| format!("read error: {e}"))?;
    let program = crate::frontend::parser::Parser::parse_str(&source, src_path)
        .map_err(|e| format!("parse error: {e}"))?;
    let ir = compile_program(&program);
    crate::backend::cranelift_aot::CraneliftBackend::compile_to_binary(&ir, out_path)
}

/// Helper for tests: compile multiple sources in parallel and return merged IRProgram.
pub(crate) fn cmd_build_parallel_sources(
    sources: Vec<(String, String)>,
    jobs: usize,
) -> Result<crate::middle::ir::IRProgram, String> {
    crate::parallel::compiler::compile_parallel(sources, jobs)
}

fn build_artifact(program: &ast::Program) -> FvcArtifact {
    let ir = compile_program(program);
    codegen_program(&ir)
}

/// v25.9.0: public wrapper for build_artifact (used by main.rs --compile mode)
pub fn build_artifact_pub(program: &ast::Program) -> FvcArtifact {
    build_artifact(program)
}

// ── v12.3.0: --legacy monadic bind transformation ─────────────────────────────

/// Walk an `IRExpr` and recursively apply `legacy_transform_stmt` to all
/// `Block` statement lists (and their nested sub-expressions).
fn legacy_transform_expr(expr: IRExpr) -> IRExpr {
    match expr {
        IRExpr::Block(stmts, final_expr, ty) => {
            let stmts = stmts.into_iter().map(legacy_transform_stmt).collect();
            let final_expr = Box::new(legacy_transform_expr(*final_expr));
            IRExpr::Block(stmts, final_expr, ty)
        }
        IRExpr::If(cond, then_e, else_e, ty) => IRExpr::If(
            Box::new(legacy_transform_expr(*cond)),
            Box::new(legacy_transform_expr(*then_e)),
            Box::new(legacy_transform_expr(*else_e)),
            ty,
        ),
        IRExpr::Match(scrutinee, arms, ty) => {
            let scrutinee = Box::new(legacy_transform_expr(*scrutinee));
            let arms = arms
                .into_iter()
                .map(|arm| IRArm {
                    pattern: arm.pattern,
                    guard: arm.guard.map(legacy_transform_expr),
                    body: legacy_transform_expr(arm.body),
                })
                .collect();
            IRExpr::Match(scrutinee, arms, ty)
        }
        IRExpr::Call(callee, args, ty) => IRExpr::Call(
            Box::new(legacy_transform_expr(*callee)),
            args.into_iter().map(legacy_transform_expr).collect(),
            ty,
        ),
        IRExpr::FieldAccess(expr, name, ty) => {
            IRExpr::FieldAccess(Box::new(legacy_transform_expr(*expr)), name, ty)
        }
        IRExpr::BinOp(op, left, right, ty) => IRExpr::BinOp(
            op,
            Box::new(legacy_transform_expr(*left)),
            Box::new(legacy_transform_expr(*right)),
            ty,
        ),
        IRExpr::Closure(idx, captures, ty) => IRExpr::Closure(
            idx,
            captures.into_iter().map(legacy_transform_expr).collect(),
            ty,
        ),
        IRExpr::Collect(expr, ty) => {
            IRExpr::Collect(Box::new(legacy_transform_expr(*expr)), ty)
        }
        IRExpr::Emit(expr, ty) => IRExpr::Emit(Box::new(legacy_transform_expr(*expr)), ty),
        IRExpr::RecordConstruct(fields, ty) => IRExpr::RecordConstruct(
            fields
                .into_iter()
                .map(|(name, expr)| (name, legacy_transform_expr(expr)))
                .collect(),
            ty,
        ),
        IRExpr::CallTrfLocal { local, arg, ty } => IRExpr::CallTrfLocal {
            local,
            arg: Box::new(legacy_transform_expr(*arg)),
            ty,
        },
        // Leaf nodes: Lit, Local, Global, TrfRef
        leaf => leaf,
    }
}

/// Replace `IRStmt::Bind(slot, expr)` with `IRStmt::Chain(slot, expr)` when
/// `expr` has type `Result<_, _>`, applying monadic bind semantics.
/// All other statement variants are walked recursively but left unchanged.
fn legacy_transform_stmt(stmt: IRStmt) -> IRStmt {
    match stmt {
        // Unconditionally promote every Bind to LegacyBind.
        // The LegacyBindCheck opcode handles non-Result values at runtime
        // by passing them through unchanged, so no compile-time type check is needed.
        IRStmt::Bind(slot, expr) => {
            IRStmt::LegacyBind(slot, legacy_transform_expr(expr))
        }
        IRStmt::LegacyBind(slot, expr) => IRStmt::LegacyBind(slot, legacy_transform_expr(expr)),
        IRStmt::Chain(slot, expr) => IRStmt::Chain(slot, legacy_transform_expr(expr)),
        IRStmt::SeqChain { slot, expr, stage_name, stage_idx, total } => IRStmt::SeqChain {
            slot,
            expr: legacy_transform_expr(expr),
            stage_name,
            stage_idx,
            total,
        },
        IRStmt::Yield(expr) => IRStmt::Yield(legacy_transform_expr(expr)),
        IRStmt::Expr(expr) => IRStmt::Expr(legacy_transform_expr(expr)),
        other => other, // TrackLine
    }
}

/// Post-process the compiled IR so that every `bind x <- Result_expr` in
/// `--legacy` mode behaves as a true monadic bind (unwrap Ok / short-circuit Err).
/// Favnir pipeline mode (compiler.fav path) is not affected.
fn apply_legacy_bind_semantics(ir: IRProgram) -> IRProgram {
    IRProgram {
        fns: ir
            .fns
            .into_iter()
            .map(|fn_def: IRFnDef| IRFnDef {
                body: legacy_transform_expr(fn_def.body),
                ..fn_def
            })
            .collect(),
        ..ir
    }
}

fn build_artifact_legacy(program: &ast::Program) -> FvcArtifact {
    let ir = compile_program(program);
    let ir = apply_legacy_bind_semantics(ir);
    codegen_program(&ir)
}

fn build_wasm_artifact(program: &ast::Program) -> Result<Vec<u8>, String> {
    let ir = compile_program(program);
    wasm_codegen_program(&ir).map_err(|e| e.to_string())
}

// ── v19.6.0: WasmBuildConfig / build_wasm_artifact_with_config ──────────────

#[derive(Debug, Clone, PartialEq)]
pub enum WasmTarget {
    Wasm32,      // --target wasm (default)
    Wasm32Wasi,  // --target wasm32-wasi
}

#[derive(Debug, Clone)]
pub struct WasmBuildConfig {
    pub target: WasmTarget,
    pub opt_level: crate::backend::wasm_opt_pass::WasmOptLevel,
    pub strip_debug: bool,
    pub size_report: bool,
    /// Apply dead code elimination before codegen (default: true).
    pub dce: bool,
}

impl Default for WasmBuildConfig {
    fn default() -> Self {
        Self {
            target: WasmTarget::Wasm32,
            opt_level: crate::backend::wasm_opt_pass::WasmOptLevel::O0,
            strip_debug: false,
            size_report: false,
            dce: true,
        }
    }
}

pub fn build_wasm_artifact_with_config(
    program: &ast::Program,
    config: &WasmBuildConfig,
) -> Result<Vec<u8>, String> {
    use crate::backend::wasm_dce::{apply_dce, collect_reachable_fns};
    use crate::backend::wasm_opt_pass::try_wasm_opt;

    let mut ir = compile_program(program);

    if config.dce {
        let reachable = collect_reachable_fns(&ir, "main");
        apply_dce(&mut ir, &reachable);
    }

    let bytes = if config.target == WasmTarget::Wasm32Wasi {
        crate::backend::wasm_codegen::wasm_codegen_program_wasi(&ir)
            .map_err(|e| e.to_string())?
    } else {
        wasm_codegen_program(&ir).map_err(|e| e.to_string())?
    };

    let (bytes, report) = try_wasm_opt(bytes, config.opt_level, config.strip_debug);

    if config.size_report {
        eprintln!(
            "[fav] WASM size: before={} bytes, after={} bytes, reduced={:.1}%",
            report.before,
            report.after,
            report.reduction_pct()
        );
    }

    Ok(bytes)
}

fn graphql_type_from_type_expr(ty: &ast::TypeExpr) -> String {
    match ty {
        ast::TypeExpr::Optional(inner, _) => graphql_type_from_type_expr_nullable(inner),
        ast::TypeExpr::Fallible(inner, _) => graphql_type_from_type_expr_nullable(inner),
        _ => graphql_type_from_type_expr_nonnull(ty),
    }
}

fn graphql_type_from_type_expr_nullable(ty: &ast::TypeExpr) -> String {
    match ty {
        ast::TypeExpr::Optional(inner, _) | ast::TypeExpr::Fallible(inner, _) => {
            graphql_type_from_type_expr_nullable(inner)
        }
        ast::TypeExpr::Named(name, args, _) if name == "List" && args.len() == 1 => {
            format!("[{}!]!", graphql_type_from_type_expr_nullable(&args[0]))
        }
        ast::TypeExpr::Named(name, _, _) => graphql_scalar_name(name).to_string(),
        other => graphql_type_from_type_expr_nonnull(other)
            .trim_end_matches('!')
            .to_string(),
    }
}

fn graphql_type_from_type_expr_nonnull(ty: &ast::TypeExpr) -> String {
    match ty {
        ast::TypeExpr::Named(name, args, _) if name == "List" && args.len() == 1 => {
            format!("[{}!]!", graphql_type_from_type_expr_nullable(&args[0]))
        }
        ast::TypeExpr::Named(name, args, _) if name == "Result" && args.len() == 2 => {
            graphql_type_from_type_expr_nullable(&args[0])
        }
        ast::TypeExpr::Named(name, _, _) => format!("{}!", graphql_scalar_name(name)),
        ast::TypeExpr::Arrow(_, _, _) => "String!".to_string(),
        ast::TypeExpr::TrfFn { .. } => "String!".to_string(),
        ast::TypeExpr::Optional(inner, _) | ast::TypeExpr::Fallible(inner, _) => {
            graphql_type_from_type_expr_nullable(inner)
        }
        ast::TypeExpr::Intersection(_, _, _) | ast::TypeExpr::RecordType(_, _) | ast::TypeExpr::Schema(_, _) | ast::TypeExpr::LinearArrow(_, _, _) => "String!".to_string(),
        ast::TypeExpr::ConstInt(_, _) => "Int!".to_string(),
    }
}

fn graphql_scalar_name(name: &str) -> &str {
    match name {
        "Bool" => "Boolean",
        other => other,
    }
}

fn flatten_interface_method_type<'a>(
    ty: &'a ast::TypeExpr,
    out: &mut Vec<&'a ast::TypeExpr>,
) -> &'a ast::TypeExpr {
    match ty {
        ast::TypeExpr::Arrow(left, right, _) => {
            out.push(left);
            flatten_interface_method_type(right, out)
        }
        other => other,
    }
}

fn render_graphql_sdl(program: &ast::Program) -> String {
    use std::fmt::Write as _;

    let mut out = String::new();
    for item in &program.items {
        if let ast::Item::TypeDef(td) = item {
            if let ast::TypeBody::Record(fields) = &td.body {
                let _ = writeln!(out, "type {} {{", td.name);
                for field in fields {
                    let _ = writeln!(
                        out,
                        "  {}: {}",
                        field.name,
                        graphql_type_from_type_expr(&field.ty)
                    );
                }
                let _ = writeln!(out, "}}\n");
            }
        }
    }

    let mut query_lines = Vec::new();
    for item in &program.items {
        if let ast::Item::InterfaceDecl(id) = item {
            for method in &id.methods {
                let mut parts = Vec::new();
                let ret = flatten_interface_method_type(&method.ty, &mut parts);
                let args: Vec<String> = if parts.len() == 1
                    && matches!(parts[0], ast::TypeExpr::Named(name, _, _) if name == "Unit")
                {
                    Vec::new()
                } else {
                    parts
                        .iter()
                        .enumerate()
                        .map(|(idx, ty)| {
                            format!("arg{}: {}", idx + 1, graphql_type_from_type_expr(ty))
                        })
                        .collect()
                };
                let args_text = if args.is_empty() {
                    String::new()
                } else {
                    format!("({})", args.join(", "))
                };
                query_lines.push(format!(
                    "  {}{}: {}",
                    method.name,
                    args_text,
                    graphql_type_from_type_expr(ret)
                ));
            }
        }
    }
    if !query_lines.is_empty() {
        let _ = writeln!(out, "type Query {{");
        for line in query_lines {
            let _ = writeln!(out, "{line}");
        }
        let _ = writeln!(out, "}}");
    }
    out
}

pub fn cmd_build_graphql(file: &str, out: Option<&str>) {
    let source = load_file(file);
    let program = Parser::parse_str(&source, file).unwrap_or_else(|e| {
        eprintln!("{}", e);
        process::exit(1);
    });
    let rendered = render_graphql_sdl(&program);
    if let Some(path) = out {
        std::fs::write(path, rendered).unwrap_or_else(|e| {
            eprintln!("error: cannot write `{}`: {}", path, e);
            process::exit(1);
        });
        println!("built {}", path);
    } else {
        print!("{rendered}");
    }
}

fn proto_scalar_name(name: &str) -> &str {
    match name {
        "Int" => "int64",
        "Float" => "double",
        "String" => "string",
        "Bool" => "bool",
        "Unit" => "google.protobuf.Empty",
        other => other,
    }
}

fn proto_type_from_type_expr(ty: &ast::TypeExpr, needs_empty: &mut bool) -> String {
    match ty {
        ast::TypeExpr::Optional(inner, _) | ast::TypeExpr::Fallible(inner, _) => {
            format!(
                "optional {}",
                proto_type_from_type_expr_nonwrapper(inner, needs_empty)
            )
        }
        ast::TypeExpr::Named(name, args, _) if name == "List" && args.len() == 1 => {
            format!(
                "repeated {}",
                proto_type_from_type_expr_nonwrapper(&args[0], needs_empty)
            )
        }
        ast::TypeExpr::Named(name, args, _) if name == "Result" && args.len() == 2 => {
            proto_type_from_type_expr(&args[0], needs_empty)
        }
        ast::TypeExpr::Named(name, args, _) if name == "Stream" && args.len() == 1 => {
            format!(
                "stream {}",
                proto_type_from_type_expr_nonwrapper(&args[0], needs_empty)
            )
        }
        other => proto_type_from_type_expr_nonwrapper(other, needs_empty),
    }
}

fn proto_type_from_type_expr_nonwrapper(ty: &ast::TypeExpr, needs_empty: &mut bool) -> String {
    match ty {
        ast::TypeExpr::Optional(inner, _) | ast::TypeExpr::Fallible(inner, _) => {
            proto_type_from_type_expr_nonwrapper(inner, needs_empty)
        }
        ast::TypeExpr::Named(name, _, _) => {
            if name == "Unit" {
                *needs_empty = true;
            }
            proto_scalar_name(name).to_string()
        }
        ast::TypeExpr::Arrow(_, _, _) | ast::TypeExpr::TrfFn { .. } => "string".to_string(),
        ast::TypeExpr::Intersection(_, _, _) | ast::TypeExpr::RecordType(_, _) | ast::TypeExpr::Schema(_, _) | ast::TypeExpr::LinearArrow(_, _, _) => "string".to_string(),
        ast::TypeExpr::ConstInt(_, _) => "int32".to_string(),
    }
}

fn flatten_proto_method_type<'a>(
    ty: &'a ast::TypeExpr,
    out: &mut Vec<&'a ast::TypeExpr>,
) -> &'a ast::TypeExpr {
    match ty {
        ast::TypeExpr::Arrow(left, right, _) => {
            out.push(left);
            flatten_proto_method_type(right, out)
        }
        other => other,
    }
}

fn snake_to_pascal(name: &str) -> String {
    let mut out = String::new();
    for part in name.split('_') {
        if part.is_empty() {
            continue;
        }
        let mut chars = part.chars();
        if let Some(first) = chars.next() {
            out.push(first.to_ascii_uppercase());
            out.extend(chars);
        }
    }
    out
}

fn pascal_to_snake(name: &str) -> String {
    let mut out = String::new();
    for (idx, ch) in name.chars().enumerate() {
        if ch.is_ascii_uppercase() {
            if idx > 0 {
                out.push('_');
            }
            out.push(ch.to_ascii_lowercase());
        } else {
            out.push(ch);
        }
    }
    out
}

fn render_proto_schema(program: &ast::Program) -> String {
    use std::fmt::Write as _;

    let mut out = String::new();
    let mut needs_empty = false;
    let mut generated_messages: Vec<(String, Vec<(String, String)>)> = Vec::new();

    let _ = writeln!(out, "syntax = \"proto3\";\n");

    for item in &program.items {
        if let ast::Item::TypeDef(td) = item {
            if let ast::TypeBody::Record(fields) = &td.body {
                let _ = writeln!(out, "message {} {{", td.name);
                for (idx, field) in fields.iter().enumerate() {
                    let ty = proto_type_from_type_expr(&field.ty, &mut needs_empty);
                    let _ = writeln!(out, "  {} {} = {};", ty, field.name, idx + 1);
                }
                let _ = writeln!(out, "}}\n");
            }
        }
    }

    for item in &program.items {
        if let ast::Item::InterfaceDecl(id) = item {
            for method in &id.methods {
                let mut params = Vec::new();
                let ret = flatten_proto_method_type(&method.ty, &mut params);
                if params.len() > 1 {
                    let req_name = format!("{}{}Request", id.name, snake_to_pascal(&method.name));
                    let fields = params
                        .iter()
                        .enumerate()
                        .map(|(idx, ty)| {
                            (
                                format!("arg{}", idx + 1),
                                proto_type_from_type_expr_nonwrapper(ty, &mut needs_empty),
                            )
                        })
                        .collect::<Vec<_>>();
                    generated_messages.push((req_name, fields));
                }
                if matches!(
                    params.first(),
                    Some(ast::TypeExpr::Named(name, _, _)) if name == "Unit"
                ) || params.is_empty()
                {
                    needs_empty = true;
                }
                if matches!(
                    ret,
                    ast::TypeExpr::Named(name, _, _) if name == "Unit"
                ) {
                    needs_empty = true;
                }
            }
        }
    }

    for (name, fields) in &generated_messages {
        let _ = writeln!(out, "message {} {{", name);
        for (idx, (field_name, field_ty)) in fields.iter().enumerate() {
            let _ = writeln!(out, "  {} {} = {};", field_ty, field_name, idx + 1);
        }
        let _ = writeln!(out, "}}\n");
    }

    if needs_empty {
        let _ = writeln!(out, "import \"google/protobuf/empty.proto\";\n");
    }

    for item in &program.items {
        if let ast::Item::InterfaceDecl(id) = item {
            let _ = writeln!(out, "service {} {{", id.name);
            for method in &id.methods {
                let mut params = Vec::new();
                let ret = flatten_proto_method_type(&method.ty, &mut params);
                let req_ty = if params.is_empty()
                    || matches!(
                        params.first(),
                        Some(ast::TypeExpr::Named(name, _, _)) if name == "Unit"
                    ) {
                    "google.protobuf.Empty".to_string()
                } else if params.len() == 1 {
                    proto_type_from_type_expr_nonwrapper(params[0], &mut needs_empty)
                } else {
                    format!("{}{}Request", id.name, snake_to_pascal(&method.name))
                };
                let mut resp_stream = false;
                let resp_ty = match ret {
                    ast::TypeExpr::Named(name, args, _) if name == "Result" && args.len() == 2 => {
                        match &args[0] {
                            ast::TypeExpr::Named(stream_name, stream_args, _)
                                if stream_name == "Stream" && stream_args.len() == 1 =>
                            {
                                resp_stream = true;
                                proto_type_from_type_expr_nonwrapper(
                                    &stream_args[0],
                                    &mut needs_empty,
                                )
                            }
                            other => proto_type_from_type_expr_nonwrapper(other, &mut needs_empty),
                        }
                    }
                    ast::TypeExpr::Named(name, args, _) if name == "Stream" && args.len() == 1 => {
                        resp_stream = true;
                        proto_type_from_type_expr_nonwrapper(&args[0], &mut needs_empty)
                    }
                    other => proto_type_from_type_expr_nonwrapper(other, &mut needs_empty),
                };
                let resp_rendered = if resp_stream {
                    format!("stream {}", resp_ty)
                } else {
                    resp_ty
                };
                let _ = writeln!(
                    out,
                    "  rpc {}({}) returns ({});",
                    snake_to_pascal(&method.name),
                    req_ty,
                    resp_rendered
                );
            }
            let _ = writeln!(out, "}}\n");
        }
    }

    out
}

pub fn cmd_build_proto(file: &str, out: Option<&str>) {
    let source = load_file(file);
    let program = Parser::parse_str(&source, file).unwrap_or_else(|e| {
        eprintln!("{}", e);
        process::exit(1);
    });
    let rendered = render_proto_schema(&program);
    if let Some(path) = out {
        std::fs::write(path, rendered).unwrap_or_else(|e| {
            eprintln!("error: cannot write `{}`: {}", path, e);
            process::exit(1);
        });
        println!("built {}", path);
    } else {
        print!("{rendered}");
    }
}

/// Generate SQL DDL from type definitions + schemas/*.yaml constraints (v4.1.5).
pub fn cmd_build_schema(file: &str, out: Option<&str>) {
    let source = load_file(file);
    let program = Parser::parse_str(&source, file).unwrap_or_else(|e| {
        eprintln!("{}", e);
        process::exit(1);
    });
    let root = schemas_root(Some(file));
    let schemas = load_schemas(&root);

    // Collect type definitions from the program
    let mut ddl = String::new();
    for item in &program.items {
        if let crate::ast::Item::TypeDef(td) = item {
            let type_name = &td.name;
            let crate::ast::TypeBody::Record(fields) = &td.body else {
                continue;
            };
            let table_name = to_snake_plural(type_name);
            let type_schema = schemas.get(type_name);
            let mut cols: Vec<String> = Vec::new();
            for field in fields {
                let fname = &field.name;
                let fc = type_schema.and_then(|ts| ts.get(fname));
                let sql_col = build_sql_column(fname, &field.ty, fc);
                cols.push(format!("    {sql_col}"));
            }
            ddl.push_str(&format!(
                "CREATE TABLE {} (\n{}\n);\n\n",
                table_name,
                cols.join(",\n")
            ));
        }
    }

    if let Some(path) = out {
        std::fs::write(path, &ddl).unwrap_or_else(|e| {
            eprintln!("E0516: cannot write '{}': {}", path, e);
            process::exit(1);
        });
        println!("built {}", path);
    } else {
        print!("{ddl}");
    }
}

/// Convert PascalCase type name to snake_case plural table name.
fn to_snake_plural(name: &str) -> String {
    let mut snake = String::new();
    for (i, ch) in name.chars().enumerate() {
        if ch.is_uppercase() && i > 0 {
            snake.push('_');
        }
        snake.push(ch.to_ascii_lowercase());
    }
    if snake.ends_with('s') {
        snake
    } else {
        format!("{snake}s")
    }
}

/// Build a single SQL column definition from field name, type, and constraints.
fn build_sql_column(
    fname: &str,
    ty: &crate::ast::TypeExpr,
    fc: Option<&crate::schemas::FieldConstraints>,
) -> String {
    use crate::ast::TypeExpr;
    let nullable = fc.map(|f| f.nullable).unwrap_or(false);
    let is_option = matches!(ty, TypeExpr::Optional(_, _));
    let not_null = if nullable || is_option {
        ""
    } else {
        " NOT NULL"
    };

    let sql_type = match ty {
        TypeExpr::Named(n, _, _) => match n.as_str() {
            "Int" => "INTEGER",
            "Float" => "REAL",
            "Bool" => "INTEGER",
            _ => "TEXT",
        },
        TypeExpr::Optional(inner, _) => match inner.as_ref() {
            TypeExpr::Named(n, _, _) => match n.as_str() {
                "Int" => "INTEGER",
                "Float" => "REAL",
                "Bool" => "INTEGER",
                _ => "TEXT",
            },
            _ => "TEXT",
        },
        _ => "TEXT",
    };

    // Override TEXT with VARCHAR if max_length specified
    let sql_type_str = if let Some(fc) = fc {
        if let Some(max_len) = fc.max_length {
            format!("VARCHAR({max_len})")
        } else {
            sql_type.to_string()
        }
    } else {
        sql_type.to_string()
    };

    let mut parts = vec![fname.to_string(), sql_type_str];

    // PRIMARY KEY
    if fc
        .map(|f| f.constraints.iter().any(|c| c == "primary_key"))
        .unwrap_or(false)
    {
        parts.push("PRIMARY KEY AUTOINCREMENT".to_string());
    }
    // UNIQUE
    if fc
        .map(|f| f.constraints.iter().any(|c| c == "unique"))
        .unwrap_or(false)
    {
        parts.push("UNIQUE".to_string());
    }
    // NOT NULL
    if !not_null.is_empty() {
        parts.push("NOT NULL".to_string());
    }
    // CHECK constraints
    if let Some(fc) = fc {
        if fc.constraints.iter().any(|c| c == "positive") {
            parts.push(format!("CHECK ({fname} > 0)"));
        }
        if fc.constraints.iter().any(|c| c == "non_negative") {
            parts.push(format!("CHECK ({fname} >= 0)"));
        }
        if let Some(min) = fc.min {
            parts.push(format!("CHECK ({fname} >= {min})"));
        }
        if let Some(max) = fc.max {
            parts.push(format!("CHECK ({fname} <= {max})"));
        }
        if let Some(pat) = &fc.pattern {
            parts.push(format!("CHECK ({fname} REGEXP '{pat}')"));
        }
    }

    parts.join(" ")
}

fn fav_type_from_proto(proto_ty: &str, label: Option<&str>) -> String {
    let base = match proto_ty.trim() {
        "int32" | "int64" | "sint64" => "Int".to_string(),
        "float" | "double" => "Float".to_string(),
        "string" | "bytes" => "String".to_string(),
        "bool" => "Bool".to_string(),
        "google.protobuf.Empty" => "Unit".to_string(),
        other => other.to_string(),
    };
    match label {
        Some("repeated") => format!("List<{base}>"),
        Some("optional") => format!("Option<{base}>"),
        _ => base,
    }
}

pub fn cmd_infer_proto(proto_path: &str, out_path: Option<&str>) {
    let src = load_file(proto_path);
    let mut lines = src.lines().peekable();
    let mut messages: Vec<(String, Vec<(String, String)>)> = Vec::new();
    let mut services: Vec<(String, Vec<String>)> = Vec::new();

    while let Some(raw_line) = lines.next() {
        let line = raw_line.trim();
        if let Some(name) = line
            .strip_prefix("message ")
            .and_then(|rest| rest.strip_suffix(" {"))
        {
            let mut fields = Vec::new();
            for raw_field in lines.by_ref() {
                let field = raw_field.trim();
                if field == "}" {
                    break;
                }
                if field.is_empty() {
                    continue;
                }
                let field = field.trim_end_matches(';');
                let parts: Vec<&str> = field.split_whitespace().collect();
                if parts.len() < 4 {
                    continue;
                }
                let (label, ty_idx) = match parts[0] {
                    "optional" | "repeated" => (Some(parts[0]), 1usize),
                    _ => (None, 0usize),
                };
                let proto_ty = parts[ty_idx];
                let field_name = parts[ty_idx + 1];
                fields.push((field_name.to_string(), fav_type_from_proto(proto_ty, label)));
            }
            messages.push((name.to_string(), fields));
            continue;
        }

        if let Some(name) = line
            .strip_prefix("service ")
            .and_then(|rest| rest.strip_suffix(" {"))
        {
            let mut methods = Vec::new();
            for raw_rpc in lines.by_ref() {
                let rpc = raw_rpc.trim();
                if rpc == "}" {
                    break;
                }
                if !rpc.starts_with("rpc ") {
                    continue;
                }
                let rpc = rpc.trim_end_matches(';');
                let Some((head, returns_part)) = rpc.split_once(" returns ") else {
                    continue;
                };
                let head = head.trim_start_matches("rpc ").trim();
                let Some((rpc_name, req_part)) = head.split_once('(') else {
                    continue;
                };
                let req_ty = req_part.trim_end_matches(')').trim();
                let returns_part = returns_part
                    .trim()
                    .trim_start_matches('(')
                    .trim_end_matches(')');
                let (resp_stream, resp_ty_raw) =
                    if let Some(inner) = returns_part.strip_prefix("stream ") {
                        (true, inner.trim())
                    } else {
                        (false, returns_part)
                    };
                let req_fav = if req_ty == "google.protobuf.Empty" {
                    "Unit".to_string()
                } else {
                    req_ty.to_string()
                };
                let resp_base = if resp_ty_raw == "google.protobuf.Empty" {
                    "Unit".to_string()
                } else {
                    resp_ty_raw.to_string()
                };
                let ret = if resp_stream {
                    format!("Stream<{resp_base}>")
                } else {
                    format!("Result<{resp_base}, RpcError>")
                };
                methods.push(format!(
                    "    {}: {} -> {}",
                    pascal_to_snake(rpc_name),
                    req_fav,
                    ret
                ));
            }
            services.push((name.to_string(), methods));
        }
    }

    let mut rendered = String::from("// auto-generated by `fav infer --proto`\n\n");
    rendered.push_str("type RpcError = { code: Int message: String }\n\n");
    for (name, fields) in messages {
        rendered.push_str(&format!("type {} = {{\n", name));
        for (field_name, field_ty) in fields {
            rendered.push_str(&format!("    {}: {}\n", field_name, field_ty));
        }
        rendered.push_str("}\n\n");
    }
    for (name, methods) in services {
        rendered.push_str(&format!("interface {} {{\n", name));
        for method in methods {
            rendered.push_str(&format!("{method}\n"));
        }
        rendered.push_str("}\n\n");
    }

    if let Some(path) = out_path {
        std::fs::write(path, rendered).unwrap_or_else(|e| {
            eprintln!("error: cannot write `{}`: {}", path, e);
            process::exit(1);
        });
        println!("built {}", path);
    } else {
        print!("{rendered}");
    }
}

fn write_artifact_to_path(artifact: &FvcArtifact, out_path: &Path) -> Result<(), String> {
    if let Some(parent) = out_path.parent() {
        if !parent.as_os_str().is_empty() {
            std::fs::create_dir_all(parent).map_err(|e| {
                format!(
                    "error: cannot create output directory `{}`: {}",
                    parent.display(),
                    e
                )
            })?;
        }
    }

    let mut file = std::fs::File::create(out_path).map_err(|e| {
        format!(
            "error: cannot create artifact `{}`: {}",
            out_path.display(),
            e
        )
    })?;
    backend::artifact::FvcWriter {
        str_table: artifact.str_table.clone(),
        globals: artifact.globals.clone(),
        functions: artifact.functions.clone(),
        type_metas: artifact.type_metas.clone(),
        explain_json: artifact.explain_json.clone(),
        meta: artifact.meta.clone(),
    }
    .write_to(&mut file)
    .map_err(|e| {
        format!(
            "error: cannot write artifact `{}`: {}",
            out_path.display(),
            e
        )
    })
}

pub fn cmd_exec(path: &str, show_info: bool, db_path: Option<&str>) {
    if path.ends_with(".wasm") {
        let bytes = read_wasm_from_path(Path::new(path)).unwrap_or_else(|message| {
            eprintln!("{message}");
            process::exit(1);
        });
        match exec_wasm_bytes(&bytes, show_info, db_path) {
            Ok(Some(info)) => {
                print!("{info}");
                return;
            }
            Ok(None) => return,
            Err(message) => {
                eprintln!("{message}");
                process::exit(1);
            }
        }
    }

    let artifact = read_artifact_from_path(Path::new(path)).unwrap_or_else(|message| {
        eprintln!("{message}");
        process::exit(1);
    });

    if show_info {
        print!("{}", artifact_info_string(&artifact));
        return;
    }

    exec_artifact_main(&artifact, db_path).unwrap_or_else(|message| {
        eprintln!("{message}");
        process::exit(1);
    });
}

fn checkpoint_list_string() -> Result<String, String> {
    let metas = checkpoint_list()?;
    if metas.is_empty() {
        return Ok("no checkpoints".to_string());
    }
    let mut lines = Vec::new();
    for meta in metas {
        lines.push(format!(
            "{}\t{}\t{}",
            meta.name, meta.value, meta.updated_at
        ));
    }
    Ok(lines.join("\n"))
}

