/// Exposed for test access.
#[cfg(test)]
pub fn builtin_primitives_for_test() -> Vec<BuiltinPrimitive> {
    builtin_primitives()
}

fn render_builtins_markdown(primitives: &[BuiltinPrimitive]) -> String {
    let mut out = String::from("# Favnir Built-in Primitives\n\n");
    let mut current_ns = "";
    for p in primitives {
        if p.namespace != current_ns {
            if !current_ns.is_empty() {
                out.push_str("---\n\n");
            }
            current_ns = p.namespace;
            out.push_str(&format!("## {}\n\n", p.namespace));
        }
        out.push_str(&format!("### {}\n", p.name));
        if p.effects.is_empty() {
            out.push_str(&format!("`{}`\n\n", p.signature));
        } else {
            out.push_str(&format!("`{}` {}\n\n", p.signature, p.effects.join(" ")));
        }
        out.push_str(p.description);
        out.push_str("\n\n");
    }
    out
}

pub fn cmd_doc_builtins(format: &str, out: Option<&str>) {
    let prims = builtin_primitives();
    let content = if format == "json" {
        serde_json::to_string_pretty(&prims).expect("builtin primitives json serialization")
    } else {
        render_builtins_markdown(&prims)
    };
    match out {
        Some(path) => {
            std::fs::write(path, &content)
                .unwrap_or_else(|e| { eprintln!("error: {}", e); process::exit(1); });
        }
        None => print!("{}", content),
    }
}

// ── fav explain <code> (v12.7.0) ─────────────────────────────────────────────

pub(crate) fn get_explain_text(code: &str) -> Option<&'static str> {
    match code {
        "E0001" => Some(
"E0001: Undefined variable

変数が定義される前に使用されています。
スペルミスか、定義より前に参照しているケースが多いです。

修正例:
  誤: bind result <- transform(rows)   ← rows が未定義

  正: bind rows   <- load_data()
      bind result <- transform(rows)   ← OK

関連: E0007（未定義関数）"
        ),
        "E0002" => Some(
"E0002: Condition type error

条件式（if / while）のガードが Bool 型ではありません。

修正例:
  誤: if 1 { ... }   ← Int は Bool でない → E0002

  正: if n > 0 { ... }   ← OK

関連: E0005（型注釈と推論型の不一致）"
        ),
        "E0003" => Some(
"E0003: Effect not declared

stage / fn でエフェクト（!IO 等）を使っているが、シグネチャに !Effect が宣言されていません。
（checker.fav（self-hosted checker）が検出。Rust checker が検出する同種エラーは E0016。）

修正例:
  誤: stage Load: String -> String = |s| {
        bind _ <- IO.println(s)   ← !IO が宣言にない → E0003
        s
      }

  正: stage Load: String -> String = |s| {
        bind _ <- IO.println(s)   ← OK
        s
      }

関連: E0016（Rust checker 相当）"
        ),
        "E0004" => Some(
"E0004: Non-exhaustive pattern match

match 式がすべてのケースをカバーしていません。

修正例:
  誤: match opt {
        Some(v) => v   ← None が未処理 → E0004
      }

  正: match opt {
        Some(v) => v
        None    => \"default\"
      }

関連: E0006（match arm 型不一致）"
        ),
        "E0005" => Some(
"E0005: Type annotation mismatch

型注釈と実際の式の型が一致しません。

修正例:
  誤: fn count() -> String { 42 }   ← Int を返している → E0005

  正: fn count() -> Int { 42 }   ← OK

関連: E0009（戻り型不一致）"
        ),
        "E0006" => Some(
"E0006: Match arm type mismatch

match の各 arm が異なる型を返しています。

修正例:
  誤: match flag {
        true  => 1        ← Int
        false => \"zero\"   ← String → E0006
      }

  正: match flag {
        true  => \"one\"
        false => \"zero\"   ← 両方 String → OK
      }

関連: E0004（非網羅的パターン）"
        ),
        "E0007" => Some(
"E0007: Undefined function

呼び出している関数が見つかりません。
Namespace の指定ミス、import 漏れが原因のことが多いです。

修正例:
  誤: bind r <- Csv.Parse(text)    ← 大文字・スペルミス

  正: bind r <- Csv.parse_raw(text, \",\", true)   ← OK

関連: E0001（未定義変数）"
        ),
        "E0008" => Some(
"E0008: Wrong number of arguments

関数呼び出しの引数の数が定義と一致しません。

修正例:
  誤: bind r <- Csv.parse_raw(text)       ← 引数が 1 つ（3 つ必要）

  正: bind r <- Csv.parse_raw(text, \",\", true)   ← OK"
        ),
        "E0009" => Some(
"E0009: Return type mismatch

関数・stage の宣言した戻り型と実際の戻り値の型が一致しません。

修正例:
  誤: stage MyStage: String -> Int = |s| { s }   ← String を返している

  正: stage MyStage: String -> String = |s| { s }   ← OK"
        ),
        "E0010" => Some(
"E0010: Interface not fully implemented

interface のすべてのメソッドを実装していません。

修正例:
  interface Runnable { fn run(self) -> Unit }

  誤: impl Runnable for MyJob { }   ← run が未実装 → E0010

  正: impl Runnable for MyJob {
        fn run(self) -> Unit = IO.println(\"running\")
      }

関連: E0014（interface not implemented）"
        ),
        "E0011" => Some(
"E0011: Undefined type

存在しない型名を参照しています。

修正例:
  誤: fn load() -> MyRecord { ... }   ← MyRecord が未定義 → E0011

  正: type MyRecord = { id: Int, name: String }
      fn load() -> MyRecord { ... }   ← OK

関連: E0001（未定義変数）"
        ),
        "E0012" => Some(
"E0012: Type mismatch

式の型が期待される型と一致しません。

修正例:
  誤: bind n <- Int.add(\"hello\", 1)   ← String を Int に渡している

  正: bind n <- Int.add(42, 1)   ← OK"
        ),
        "E0013" => Some(
"E0013: Where constraint violation

`where` バリデーターの条件を満たしていません。

修正例:
  type Age(Int) where v > 0 and v < 150

  誤: bind age <- Age(-1)   ← E0013

  正: bind age <- Age(25)   ← OK"
        ),
        "E0014" => Some(
"E0014: Interface not implemented

型が `interface` の実装（`impl`）を持っていません。

修正例:
  interface Printable { fn print(self) -> Unit }

  誤: 実装なしで Printable として使用   ← E0014

  正: impl Printable for MyType { fn print(self) -> Unit = ... }   ← OK"
        ),
        "E0015" => Some(
"E0015: Method not found

型に指定のメソッドが定義されていません。

修正例:
  誤: bind r <- my_val.unknown_method()   ← E0015

  正: bind r <- my_val.to_string()   ← OK（定義済みのメソッド）"
        ),
        "E0016" => Some(
"E0016: Effect not declared

stage / fn 宣言の `!Effect` に含まれないエフェクトを内部で使用しています。

修正例:
  誤: stage MyStage: String -> String = |s| {
        bind _ <- IO.println(s)   ← !IO が宣言にない → E0016
        s
      }

  正: stage MyStage: String -> String = |s| {
        bind _ <- IO.println(s)   ← OK
        s
      }

関連: E0017（不要なエフェクト宣言）"
        ),
        "E0017" => Some(
"E0017: Unused effect declaration

宣言した `!Effect` が実際に使われていません。

修正例:
  誤: stage MyStage: String -> String = |s| { s }
      ← !IO と !Postgres を宣言しているが使っていない → E0017

  正: stage MyStage: String -> String = |s| { s }   ← OK

関連: E0016（エフェクト宣言漏れ）"
        ),
        "E0018" => Some(
"E0018: Variable already bound

Favnir では変数は一度だけ束縛できます（イミュータブル）。
同一スコープで bind x を 2 回書くことはできません。

修正例:
  誤: bind x <- step1()
      bind x <- step2(x)   ← E0018

  正: bind x  <- step1()
      bind x2 <- step2(x)  ← OK
      または:
      bind _ <- step2(x)   ← 結果を捨てる場合（W006 に注意）

関連: W006（Result を bind _ で捨てる）"
        ),
        "E0019" => Some(
"E0019: Circular interface inheritance

interface の継承が循環しています。

修正例:
  誤: interface A : B { }
      interface B : A { }   ← 循環 → E0019

  正: interface Base { fn id(self) -> Int }
      interface A : Base { fn name(self) -> String }   ← OK"
        ),
        "E0020" => Some(
"E0020: Capability not available

ctx に渡された型が必要な capability interface を実装していません。

修正例:
  誤: fn load(ctx: LoadCtx) -> Result<Rows, String> {
        ctx.db.execute(ctx, \"DELETE ...\")   ← LoadCtx.db は DbRead のみ → E0020
      }

  正: fn delete(ctx: WriteCtx) -> Result<Unit, String> {
        ctx.db.execute(ctx, \"DELETE ...\")   ← WriteCtx.db は DbWrite → OK
      }

関連: E0021（wrong context type）"
        ),
        "E0021" => Some(
"E0021: Wrong context type

ctx に必要なフィールドが存在しません。

修正例:
  誤: fn run(ctx: LoadCtx) {
        ctx.storage.put(...)   ← LoadCtx に storage フィールドがない → E0021
      }

  正: fn run(ctx: WriteCtx) {
        ctx.storage.put(...)   ← WriteCtx に storage フィールドがある → OK
      }

関連: E0020（capability not available）"
        ),
        "W001" => Some(
"W001: Unused variable

束縛した変数が一度も使われていません。

修正例:
  誤: bind unused <- compute()   ← W001

  正: bind _ <- compute()   ← 意図的に捨てる場合
      または変数を実際に使う"
        ),
        "W002" => Some(
"W002: Unreachable code

到達しないコードが存在します。

修正例:
  誤: bind x <- step()
      x
      \"never reached\"   ← W002

  正: コードを削除するか、フロー制御を見直す"
        ),
        "W003" => Some(
"W003: Redundant match arm

match のあるアームが他のアームと重複しています。"
        ),
        "W004" => Some(
"W004: Magic string / number

ハードコードされた文字列・数値が複数箇所に出現しています。
定数や設定に切り出すことを検討してください。"
        ),
        "W005" => Some(
"W005: Deep nesting

match や if のネストが深すぎます。
ヘルパー stage / fn に切り出すことを検討してください。"
        ),
        "W006" => Some(
"W006: Discarding Result value

bind _ <- Postgres.execute_raw(...) のように、
エフェクトが返す Result を bind _ で捨てると警告が出ます。
失敗がサイレントに通過し、パイプラインが誤動作する原因になります。

修正例:
  誤: bind _ <- Postgres.execute_raw(sql, params)   ← W006

  正: chain _ <- Postgres.execute_raw(sql, params)  ← エラーを自動伝播
      または:
      match Postgres.execute_raw(sql, params) {
        Ok(_)  => \"ok\"
        Err(e) => e
      }

関連: E0018（変数の再束縛）"
        ),
        "W007" => Some(
"W007: Shadowed binding

外側のスコープと同じ名前の変数を内側で束縛しています。
意図しない名前衝突の可能性があります。

修正例:
  誤: bind x <- outer()
      match x {
        Ok(x) => x   ← 外側の x を shadow → W007
        Err(e) => e
      }

  正: match x {
        Ok(v) => v   ← 別名を使う
        Err(e) => e
      }"
        ),
        "E0413" => Some(
"E0413: Opaque type coerce forbidden

opaque type の内部型の値を直接 opaque type として返すことはできません。
opaque type は明示的なコンストラクタを経由してのみ生成できます。

修正例:
  誤: opaque type Token = String
      fn make() -> Token { \"secret\" }   ← String を Token として直接返す → E0413

  正: opaque type Token = String
      fn make(raw: String) -> Token { Token.wrap(raw) }   ← コンストラクタを使用

関連: E0001（未定義変数）"
        ),
        _ => None,
    }
}

pub fn cmd_explain_code(code: &str) {
    match get_explain_text(code) {
        Some(text) => println!("{}", text),
        None => {
            eprintln!("error: unknown error code `{}`", code);
            eprintln!();
            eprintln!("Available codes (E0001-E0021):");
            for c in &["E0001","E0002","E0003","E0004","E0005","E0006","E0007",
                        "E0008","E0009","E0010","E0011","E0012","E0013","E0014",
                        "E0015","E0016","E0017","E0018","E0019","E0020","E0021"] {
                eprintln!("  {}", c);
            }
            eprintln!();
            eprintln!("  use `fav explain <code>` to see details");
            std::process::exit(1);
        }
    }
}

// ── fav scaffold ──────────────────────────────────────────────────────────────

fn scaffold_stage(name: &str, in_type: &str, out_type: &str, effect: Option<&str>) -> String {
    let effect_ann = match effect {
        Some(e) => format!(" !{}", e),
        None => String::new(),
    };
    let body = match effect {
        Some(_) => "    bind _result <- IO.println(input)\n    input\n".to_string(),
        None => "    input\n".to_string(),
    };
    format!(
        "// {name}: {in_type} -> {out_type}{effect_ann}\n\
         // TODO: implement {name}\n\
         public stage {name}: {in_type} -> {out_type}{effect_ann} = |input| {{\n\
         {body}}}\n"
    )
}

fn scaffold_seq(name: &str, stages: &[&str]) -> String {
    let mut out = format!(
        "// {name}: String -> String\n// {}-stage sequential pipeline\n",
        stages.len()
    );
    for (i, stage) in stages.iter().enumerate() {
        let is_first = i == 0;
        let is_last = i == stages.len() - 1;
        let effect_ann = if is_first || is_last { " !IO" } else { "" };
        let param = if is_first { "input" } else { "data" };
        let todo = if is_first {
            "// TODO: load data"
        } else if is_last {
            "// TODO: save results"
        } else {
            "// TODO: transform data"
        };
        out.push_str(&format!(
            "\npublic stage {stage}: String -> String{effect_ann} = |{param}| {{\n    {todo}\n    {param}\n}}\n"
        ));
    }
    let pipe_chain = stages.join(" |> ");
    out.push_str(&format!("\npublic seq {name} = {pipe_chain}\n"));
    out
}

fn scaffold_postgres_etl() -> String {
    r#"// Postgres ETL pipeline — best practice template (v12.8.0)
// Uses chain for error propagation and seq for fail-fast execution.

public stage LoadCsv: String -> String = |path| {
    match IO.read_file_raw(path) {
        Ok(text) => text
        Err(e)   => e
    }
}

public stage InsertRows: String -> String = |csv_text| {
    match Csv.parse_raw(csv_text, ",", true) {
        Ok(rows) => {
            bind json <- Schema.to_json_array(rows, "Row")
            bind sql  <- $"INSERT INTO my_table (data) VALUES ('{json}')"
            match Postgres.execute_raw(sql, "[]") {
                Ok(_)  => $"inserted rows"
                Err(e) => e
            }
        }
        Err(e) => e
    }
}

public stage SaveResult: String -> String = |result| {
    chain _ <- IO.write_file_raw("/tmp/result.txt", result)
    result
}

public seq EtlPipeline = LoadCsv |> InsertRows |> SaveResult
"#
    .to_string()
}

