fn write_scaffold(content: &str, out: Option<&str>) {
    match out {
        Some(path) => {
            std::fs::write(path, content)
                .unwrap_or_else(|e| { eprintln!("error: cannot write {}: {}", path, e); process::exit(1); });
        }
        None => print!("{}", content),
    }
}

/// `fav scaffold stage/seq <Name>` — プロジェクトの src/ にコードを追記する。
/// `root`: fav.toml が存在するプロジェクトルート。
/// `sub`: "stage" または "seq"。
/// 戻り値: 書き込んだファイルの PathBuf、またはエラーメッセージ。
pub(crate) fn scaffold_to_src(
    root: &Path,
    sub: &str,
    name: &str,
    content: &str,
) -> Result<PathBuf, String> {
    let src_dir = FavToml::load(root)
        .map(|t| root.join(&t.src))
        .unwrap_or_else(|| root.join("src"));
    std::fs::create_dir_all(&src_dir)
        .map_err(|e| format!("cannot create {}: {}", src_dir.display(), e))?;
    let filename = match sub {
        "stage" => "stages.fav",
        "seq"   => "pipelines.fav",
        other   => return Err(format!("scaffold_to_src: unknown sub '{}'", other)),
    };
    let target = src_dir.join(filename);
    let header = format!("\n// generated by fav scaffold {} {}\n", sub, name);
    let full = format!("{}{}", header, content);
    use std::io::Write;
    std::fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(&target)
        .and_then(|mut f| f.write_all(full.as_bytes()))
        .map_err(|e| format!("cannot write {}: {}", target.display(), e))?;
    Ok(target)
}

pub fn cmd_scaffold(sub: &str, args: &[String]) {
    // parse common flags
    let mut in_type = "String";
    let mut out_type = "String";
    let mut effect: Option<&str> = Some("IO");
    let mut no_effect = false;
    let mut out_file: Option<&str> = None;
    let mut stages_str: Option<&str> = None;
    let mut i = 1usize; // args[0] = Name (positional), args[1..] = flags
    while i < args.len() {
        match args[i].as_str() {
            "--in"        => { in_type   = args.get(i+1).map(|s| s.as_str()).unwrap_or("String"); i += 2; }
            "--out-type"  => { out_type  = args.get(i+1).map(|s| s.as_str()).unwrap_or("String"); i += 2; }
            "--effect"    => { effect    = Some(args.get(i+1).map(|s| s.as_str()).unwrap_or("IO")); i += 2; }
            "--no-effect" => { no_effect = true; i += 1; }
            "--out"       => { out_file  = args.get(i+1).map(|s| s.as_str()); i += 2; }
            "--stages"    => { stages_str = args.get(i+1).map(|s| s.as_str()); i += 2; }
            _             => { i += 1; }
        }
    }
    if no_effect { effect = None; }

    match sub {
        "stage" => {
            let name = args.first().map(|s| s.as_str()).unwrap_or("MyStage");
            let content = scaffold_stage(name, in_type, out_type, effect);
            if out_file.is_none() {
                let cwd = std::env::current_dir().unwrap_or_else(|_| PathBuf::from("."));
                if let Some(root) = FavToml::find_root(&cwd) {
                    match scaffold_to_src(&root, "stage", name, &content) {
                        Ok(path) => println!("scaffold: wrote {}", path.display()),
                        Err(e) => { eprintln!("warning: {}", e); print!("{}", content); }
                    }
                } else {
                    print!("{}", content);
                }
            } else {
                write_scaffold(&content, out_file);
            }
        }
        "seq" => {
            let name = args.first().map(|s| s.as_str()).unwrap_or("MyPipeline");
            let default_stages = vec!["Load", "Transform", "Save"];
            let custom: Vec<String>;
            let stage_refs: Vec<&str> = if let Some(s) = stages_str {
                custom = s.split(',').map(|x| x.trim().to_string()).collect();
                custom.iter().map(|x| x.as_str()).collect()
            } else {
                default_stages
            };
            let content = scaffold_seq(name, &stage_refs);
            if out_file.is_none() {
                let cwd = std::env::current_dir().unwrap_or_else(|_| PathBuf::from("."));
                if let Some(root) = FavToml::find_root(&cwd) {
                    match scaffold_to_src(&root, "seq", name, &content) {
                        Ok(path) => println!("scaffold: wrote {}", path.display()),
                        Err(e) => { eprintln!("warning: {}", e); print!("{}", content); }
                    }
                } else {
                    print!("{}", content);
                }
            } else {
                write_scaffold(&content, out_file);
            }
        }
        "postgres-etl" => {
            let content = scaffold_postgres_etl();
            write_scaffold(&content, out_file);
        }
        "rune" => {
            let name = args.first().map(|s| s.as_str()).unwrap_or("MyLib");
            let content = scaffold_rune(name);
            write_scaffold(&content, out_file);
        }
        other => {
            eprintln!("error: unknown scaffold template '{}' (expected stage|seq|postgres-etl|rune)", other);
            process::exit(1);
        }
    }
}

// ── fav doc ───────────────────────────────────────────────────────────────────

/// Generate Markdown documentation from .fav source files.
///
/// * `path`    — a `.fav` file or a directory (scanned recursively).
/// * `out_dir` — output directory for `.md` files (created if absent).
pub fn cmd_doc(path: &str, out_dir: &str) {
    let entries: Vec<PathBuf> = {
        let p = Path::new(path);
        if p.is_file() {
            vec![p.to_path_buf()]
        } else if p.is_dir() {
            collect_fav_files_recursive(p)
        } else {
            eprintln!("error: '{}' is not a file or directory", path);
            process::exit(1);
        }
    };

    if let Err(e) = std::fs::create_dir_all(out_dir) {
        eprintln!("error: cannot create output directory '{}': {}", out_dir, e);
        process::exit(1);
    }

    for entry in &entries {
        let src = match std::fs::read_to_string(entry) {
            Ok(s) => s,
            Err(e) => {
                eprintln!("error: cannot read '{}': {}", entry.display(), e);
                process::exit(1);
            }
        };

        let md = match crate::compiler_fav_runner::doc_source_str(&src) {
            Ok(m) => m,
            Err(e) => {
                eprintln!("error: doc failed for '{}': {}", entry.display(), e);
                process::exit(1);
            }
        };

        let stem = entry
            .file_stem()
            .map(|s| s.to_string_lossy().to_string())
            .unwrap_or_else(|| "out".to_string());
        let out_path = Path::new(out_dir).join(format!("{}.md", stem));
        if let Err(e) = std::fs::write(&out_path, &md) {
            eprintln!("error: cannot write '{}': {}", out_path.display(), e);
            process::exit(1);
        }
        println!("doc: {} → {}", entry.display(), out_path.display());
    }
}

