// ── v22.4.0: Event-driven trigger deployment ──────────────────────────────────

/// JSON 文字列として安全にエスケープする（`"` → `\"`, `\` → `\\`, 制御文字 → `\uXXXX`）。
fn escape_json_str(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    for ch in s.chars() {
        match ch {
            '"'  => out.push_str("\\\""),
            '\\' => out.push_str("\\\\"),
            '\n' => out.push_str("\\n"),
            '\r' => out.push_str("\\r"),
            '\t' => out.push_str("\\t"),
            c if (c as u32) < 0x20 => {
                out.push_str(&format!("\\u{:04x}", c as u32));
            }
            c => out.push(c),
        }
    }
    out
}

pub(crate) fn build_trigger_config_json(entries: &[(&str, &crate::ast::TriggerAnnotation)]) -> String {
    let items: Vec<String> = entries.iter().map(|(name, t)| {
        let extra = match (t.bucket.as_deref(), t.topic.as_deref()) {
            (Some(b), _) => format!(",\n      \"bucket\": \"{}\"", escape_json_str(b)),
            (_, Some(tp)) => format!(",\n      \"topic\": \"{}\"", escape_json_str(tp)),
            _ => String::new(),
        };
        format!(
            "  {{\n    \"pipeline\": \"{}\",\n    \"trigger\": {{\n      \"event\": \"{}\"{}\n    }}\n  }}",
            escape_json_str(name), escape_json_str(&t.event), extra
        )
    }).collect();
    format!("[\n{}\n]", items.join(",\n"))
}

pub fn cmd_deploy_trigger(file: &str, out: Option<&str>) {
    let src = load_file(file);
    let prog = Parser::parse_str(&src, file).unwrap_or_else(|e| {
        eprintln!("{}", e);
        process::exit(1);
    });
    let entries: Vec<(&str, &crate::ast::TriggerAnnotation)> = prog.items.iter()
        .filter_map(|item| {
            if let crate::ast::Item::FlwDef(fd) = item {
                fd.trigger.as_ref().map(|t| (fd.name.as_str(), t))
            } else {
                None
            }
        })
        .collect();
    if entries.is_empty() {
        eprintln!("warning: no #[trigger(...)] annotations found in {}", file);
        return;
    }
    let json = build_trigger_config_json(&entries);
    match out {
        Some(path) => std::fs::write(path, &json).unwrap_or_else(|e| {
            eprintln!("error: failed to write {}: {}", path, e);
            process::exit(1);
        }),
        None => println!("{}", json),
    }
}

// ── v22.6.0: fav explain --sla ───────────────────────────────────────────────

/// `fav explain --sla [file]` — stage の SLA アノテーションと最悪実行時間を出力する。
/// アノテーションなし stage も行に含めるが worst_case を `—` とし合計には含めない。
pub fn cmd_explain_sla(file: Option<&str>) {
    use crate::ast::Item;
    let src = match file {
        Some(f) => load_file(f),
        None => {
            eprintln!("error: fav explain --sla requires a file argument");
            process::exit(1);
        }
    };
    let file_name = file.unwrap_or("<stdin>");
    let prog = Parser::parse_str(&src, file_name).unwrap_or_else(|e| {
        eprintln!("{}", e);
        process::exit(1);
    });

    let separator = "━".repeat(60);
    println!("SLA Summary — {}", file_name);
    println!("{}", separator);
    println!("{:<20} {:<10} {:<8} {:<20} {}", "stage", "timeout", "retry", "circuit_breaker", "worst_case");

    let mut total_worst_secs = 0.0f64;
    let mut found_any = false;

    for item in &prog.items {
        if let Item::TrfDef(td) = item {
            let timeout_str = td.timeout.as_ref()
                .map(|t| format!("{}s", t.seconds))
                .unwrap_or_else(|| "\u{2014}".to_string());
            let retry_str = td.retry_ann.as_ref()
                .map(|r| format!("{}\u{00d7}", r.max))
                .unwrap_or_else(|| "\u{2014}".to_string());
            let cb_str = td.circuit_breaker.as_ref()
                .map(|cb| format!("{}/{}", cb.threshold, cb.window))
                .unwrap_or_else(|| "\u{2014}".to_string());

            // 最悪実行時間: timeout_secs * retry.max（アノテーションなしは加算しない）
            let worst: Option<f64> = match (&td.timeout, &td.retry_ann) {
                (Some(t), Some(r)) => Some(t.seconds * f64::from(r.max)),
                (Some(t), None)    => Some(t.seconds),
                _                  => None,
            };
            let worst_str = worst
                .map(|s| format!("{:.0}s", s))
                .unwrap_or_else(|| "\u{2014}".to_string());

            println!("{:<20} {:<10} {:<8} {:<20} {}", td.name, timeout_str, retry_str, cb_str, worst_str);
            if let Some(w) = worst {
                total_worst_secs += w;
            }
            found_any = true;
        }
    }

    println!("{}", separator);
    if !found_any {
        println!("(no stage definitions found)");
    } else {
        println!("Total worst-case (SLA-annotated stages only): {:.0}s", total_worst_secs);
    }
}

// ── v22.5.0: Pipeline Orchestration ──────────────────────────────────────────

/// JSON 文字列値に含まれる `"` と `\` をエスケープする（v22.5.0 JSON injection 対策）。
fn escape_json_orch(s: &str) -> String {
    s.replace('\\', "\\\\").replace('"', "\\\"")
}

/// Kahn's algorithm でステップのトポロジカルソート順（インデックス配列）を返す。
/// 循環依存がある場合は `Err(メッセージ)` を返す。
pub(crate) fn build_topo_order(steps: &[crate::ast::PipelineStep]) -> Result<Vec<usize>, String> {
    use std::collections::HashMap;
    let n = steps.len();
    // name → index
    let idx: HashMap<&str, usize> = steps.iter().enumerate()
        .map(|(i, s)| (s.name.as_str(), i))
        .collect();
    // in-degree と adjacency list を構築
    let mut in_deg = vec![0usize; n];
    let mut adj: Vec<Vec<usize>> = vec![Vec::new(); n];
    for (i, step) in steps.iter().enumerate() {
        for dep in &step.after {
            match idx.get(dep.as_str()) {
                Some(&j) => {
                    adj[j].push(i);
                    in_deg[i] += 1;
                }
                None => return Err(format!(
                    "step `{}` depends on unknown step `{}`", step.name, dep
                )),
            }
        }
    }
    // BFS (Kahn)
    let mut queue: std::collections::VecDeque<usize> = in_deg.iter().enumerate()
        .filter(|(_, d)| **d == 0)
        .map(|(i, _)| i)
        .collect();
    let mut order = Vec::with_capacity(n);
    while let Some(cur) = queue.pop_front() {
        order.push(cur);
        for &next in &adj[cur] {
            in_deg[next] -= 1;
            if in_deg[next] == 0 {
                queue.push_back(next);
            }
        }
    }
    if order.len() != n {
        let in_order: std::collections::HashSet<usize> = order.iter().cloned().collect();
        let cycle_steps: Vec<&str> = steps.iter().enumerate()
            .filter(|(i, _)| !in_order.contains(i))
            .map(|(_, s)| s.name.as_str())
            .collect();
        return Err(format!(
            "circular dependency detected among steps: {}", cycle_steps.join(", ")
        ));
    }
    Ok(order)
}

fn find_pipeline_def<'a>(
    prog: &'a crate::ast::Program,
    name: &str,
) -> Option<&'a crate::ast::PipelineDef> {
    prog.items.iter().find_map(|item| {
        if let crate::ast::Item::PipelineDef(pd) = item {
            if pd.name == name { Some(pd) } else { None }
        } else {
            None
        }
    })
}

pub fn cmd_orchestrate_run(file: &str, pipeline_name: &str, dry_run: bool) {
    let src = load_file(file);
    let prog = Parser::parse_str(&src, file).unwrap_or_else(|e| {
        eprintln!("{}", e);
        process::exit(1);
    });
    let pd = find_pipeline_def(&prog, pipeline_name).unwrap_or_else(|| {
        eprintln!("error: pipeline `{}` not found in {}", pipeline_name, file);
        process::exit(1);
    });
    let order = build_topo_order(&pd.steps).unwrap_or_else(|e| {
        eprintln!("error: {}", e);
        process::exit(1);
    });
    println!("[orchestrate] pipeline: {}", pipeline_name);
    println!("[orchestrate] execution order ({} steps):", order.len());
    for (rank, &idx) in order.iter().enumerate() {
        let step = &pd.steps[idx];
        println!("  {}. \"{}\" → seq {}", rank + 1, step.name, step.seq_name);
    }
    if dry_run {
        println!("[orchestrate] dry-run mode — no steps executed");
        return;
    }
    // ステータス追跡（HashSet<String> でライフタイム問題を回避）
    let mut step_results: Vec<(String, String, String, u64)> = Vec::new();
    let mut failed: std::collections::HashSet<String> = std::collections::HashSet::new();
    let run_at = chrono::Utc::now().format("%Y-%m-%dT%H:%M:%SZ").to_string();
    for &idx in &order {
        let step = &pd.steps[idx];
        if step.after.iter().any(|dep| failed.contains(dep.as_str())) {
            println!("[orchestrate] skip \"{}\" (dependency failed)", step.name);
            step_results.push((step.name.clone(), step.seq_name.clone(), "skip".into(), 0));
            failed.insert(step.name.clone());
            continue;
        }
        println!("[orchestrate] run \"{}\" → seq {}", step.name, step.seq_name);
        let t0 = std::time::Instant::now();
        // v22.5.0: seq 実行は stdout 表示のみ（実際の統合は v22.6+）
        let elapsed = t0.elapsed().as_millis() as u64;
        println!("[orchestrate] ok \"{}\" ({}ms)", step.name, elapsed);
        step_results.push((step.name.clone(), step.seq_name.clone(), "ok".into(), elapsed));
    }
    // ステータス JSON を .fav_orchestrate/ に保存
    let dir = ".fav_orchestrate";
    let _ = std::fs::create_dir_all(dir);
    let ts = chrono::Utc::now().format("%Y%m%d%H%M%S");
    let path = format!("{}/{}_{}.json", dir, pipeline_name, ts);
    let steps_json: Vec<String> = step_results.iter().map(|(n, s, st, e)| {
        format!(
            "    {{ \"name\": \"{}\", \"seq\": \"{}\", \"status\": \"{}\", \"elapsed_ms\": {} }}",
            escape_json_orch(n), escape_json_orch(s), st, e
        )
    }).collect();
    let json = format!(
        "{{\n  \"pipeline\": \"{}\",\n  \"run_at\": \"{}\",\n  \"steps\": [\n{}\n  ]\n}}",
        escape_json_orch(pipeline_name),
        escape_json_orch(&run_at),
        steps_json.join(",\n")
    );
    let _ = std::fs::write(&path, &json);
    println!("[orchestrate] status saved → {}", path);
}

pub fn cmd_orchestrate_status(pipeline_name: &str) {
    let dir = ".fav_orchestrate";
    let prefix = format!("{}_", pipeline_name);
    let mut entries: Vec<std::path::PathBuf> = std::fs::read_dir(dir)
        .unwrap_or_else(|_| {
            eprintln!("error: .fav_orchestrate/ not found — run `fav orchestrate run` first");
            process::exit(1);
        })
        .filter_map(|e| e.ok().map(|e| e.path()))
        .filter(|p| {
            p.file_name()
                .and_then(|n| n.to_str())
                .map(|n| n.starts_with(&prefix) && n.ends_with(".json"))
                .unwrap_or(false)
        })
        .collect();
    entries.sort();
    let latest = entries.last().unwrap_or_else(|| {
        eprintln!("error: no status found for pipeline `{}`", pipeline_name);
        process::exit(1);
    });
    let content = std::fs::read_to_string(latest).unwrap_or_else(|e| {
        eprintln!("error: {}", e);
        process::exit(1);
    });
    println!("{}", content);
}

pub fn cmd_orchestrate_retry(step_name: &str, file: &str, pipeline_name: &str) {
    let src = load_file(file);
    let prog = Parser::parse_str(&src, file).unwrap_or_else(|e| {
        eprintln!("{}", e);
        process::exit(1);
    });
    let pd = find_pipeline_def(&prog, pipeline_name).unwrap_or_else(|| {
        eprintln!("error: pipeline `{}` not found in {}", pipeline_name, file);
        process::exit(1);
    });
    let step = pd.steps.iter().find(|s| s.name == step_name).unwrap_or_else(|| {
        eprintln!("error: step `{}` not found in pipeline `{}`", step_name, pipeline_name);
        process::exit(1);
    });
    println!("[orchestrate] retry \"{}\" → seq {}", step.name, step.seq_name);
    // v22.5.0: スタブ — 実際の seq 実行統合は v22.6+
    println!("[orchestrate] ok (retry stub)");
}

fn package_project_zip(root: &Path, zip_path: &str) {
    use std::io::Write;
    use zip::write::FileOptions;
    let zip_file = match std::fs::File::create(zip_path) {
        Ok(f) => f,
        Err(e) => {
            eprintln!("error: failed to create zip: {}", e);
            process::exit(1);
        }
    };
    let mut zip = zip::ZipWriter::new(zip_file);
    let options: FileOptions =
        FileOptions::default().compression_method(zip::CompressionMethod::Deflated);
    for entry in walkdir::WalkDir::new(root.join("src")) {
        let entry = match entry {
            Ok(e) => e,
            Err(_) => continue,
        };
        let path = entry.path();
        if path.extension().and_then(|e| e.to_str()) == Some("fav") {
            let rel = path
                .strip_prefix(root)
                .unwrap_or(path)
                .to_string_lossy()
                .replace('\\', "/");
            if zip.start_file(&rel, options).is_ok() {
                if let Ok(content) = std::fs::read(path) {
                    let _ = zip.write_all(&content);
                }
            }
        }
    }
    let toml_path = root.join("fav.toml");
    if toml_path.exists() {
        if zip.start_file("fav.toml", options).is_ok() {
            if let Ok(content) = std::fs::read(toml_path) {
                let _ = zip.write_all(&content);
            }
        }
    }
    let _ = zip.finish();
}

/// v35.1.0: ネイティブバイナリを Lambda 用 bootstrap.zip にパッケージングする。
/// zip 内エントリ名は "bootstrap" 固定（provided.al2 規約）。
pub fn package_lambda(binary_path: &Path, output_zip: &Path) -> Result<(), String> {
    use std::io::Write;
    use zip::write::FileOptions;
    let binary_data = std::fs::read(binary_path)
        .map_err(|e| format!("failed to read binary {}: {}", binary_path.display(), e))?;
    if binary_data.is_empty() {
        return Err(format!(
            "binary at {} is empty — run `fav build --target native` first",
            binary_path.display()
        ));
    }
    let zip_file = std::fs::File::create(output_zip)
        .map_err(|e| format!("failed to create zip {}: {}", output_zip.display(), e))?;
    let mut zip = zip::ZipWriter::new(zip_file);
    // provided.al2 規約: "bootstrap" エントリは Unix 実行権限 0o755 が必須
    let options: FileOptions = FileOptions::default()
        .compression_method(zip::CompressionMethod::Deflated)
        .unix_permissions(0o755);
    zip.start_file("bootstrap", options)
        .map_err(|e| format!("failed to start zip entry: {}", e))?;
    zip.write_all(&binary_data)
        .map_err(|e| format!("failed to write zip entry: {}", e))?;
    zip.finish()
        .map_err(|e| format!("failed to finalize zip: {}", e))?;
    Ok(())
}

/// v35.1.0: AWS CLI 経由で Lambda 関数を更新する。
/// 戻り値: Ok(true) = デプロイ実行済み、Ok(false) = AWS CLI 不在でスキップ、Err = 失敗。
/// 注意: Lambda デプロイは Linux/CI 環境での実行を想定（Windows では fileb:// パスに注意）。
fn deploy_lambda(zip_path: &Path, function: &str, region: &str) -> Result<bool, String> {
    let cli_ok = std::process::Command::new("aws")
        .arg("--version")
        .output()
        .map(|o| o.status.success())
        .unwrap_or(false);
    if !cli_ok {
        eprintln!("warning: AWS CLI not found — skipping Lambda upload (use --package-only to avoid this warning)");
        return Ok(false);
    }
    // fileb:// パスはスラッシュ区切りで指定する（AWS CLI の要件）
    let zip_str = zip_path.to_string_lossy().replace('\\', "/");
    let zip_arg = format!("fileb://{}", zip_str);
    let status = std::process::Command::new("aws")
        .args([
            "lambda", "update-function-code",
            "--function-name", function,
            "--zip-file", &zip_arg,
            "--region", region,
        ])
        .status()
        .map_err(|e| format!("failed to run aws cli: {}", e))?;
    if !status.success() {
        return Err(format!(
            "aws lambda update-function-code failed (exit {})",
            status.code().unwrap_or(-1)
        ));
    }
    Ok(true)
}

fn deploy_upload_to_s3(bucket: &str, key: &str, zip_path: &str, region: &str) {
    let config = crate::backend::vm::get_aws_config_pub();
    let url = if let Some(ep) = &config.endpoint_url {
        format!("{}/{}/{}", ep.trim_end_matches('/'), bucket, key)
    } else {
        format!("https://{}.s3.{}.amazonaws.com/{}", bucket, region, key)
    };
    let body = match std::fs::read(zip_path) {
        Ok(b) => b,
        Err(e) => {
            eprintln!("error: failed to read zip for upload: {}", e);
            process::exit(1);
        }
    };
    let h = crate::backend::vm::sigv4_sign_pub(&config, "s3", "PUT", &url, &body);
    let result = ureq::put(&url)
        .set("Authorization", &h.authorization)
        .set("x-amz-date", &h.x_amz_date)
        .set("x-amz-content-sha256", &h.x_amz_content_sha256)
        .set("Content-Type", "application/zip")
        .send_bytes(&body);
    if let Err(e) = result {
        eprintln!("error: S3 upload failed: {}", e);
        process::exit(1);
    }
}

fn deploy_update_lambda(
    func_name: &str,
    s3_bucket: &str,
    s3_key: &str,
    region: &str,
    role_arn: &str,
    deploy_cfg: &DeployConfig,
) {
    let config = crate::backend::vm::get_aws_config_pub();
    let url = if let Some(ep) = &config.endpoint_url {
        format!(
            "{}/2015-03-31/functions/{}/code",
            ep.trim_end_matches('/'),
            func_name
        )
    } else {
        format!(
            "https://lambda.{}.amazonaws.com/2015-03-31/functions/{}/code",
            region, func_name
        )
    };
    let body = format!(r#"{{"S3Bucket":"{}","S3Key":"{}"}}"#, s3_bucket, s3_key);
    let h = crate::backend::vm::sigv4_sign_pub(&config, "lambda", "PUT", &url, body.as_bytes());
    let result = ureq::put(&url)
        .set("Authorization", &h.authorization)
        .set("x-amz-date", &h.x_amz_date)
        .set("x-amz-content-sha256", &h.x_amz_content_sha256)
        .set("Content-Type", "application/json")
        .send_string(&body);
    if let Err(ureq::Error::Status(404, _)) = result {
        // Function does not exist → create it
        let create_url = if let Some(ep) = &config.endpoint_url {
            format!("{}/2015-03-31/functions", ep.trim_end_matches('/'))
        } else {
            format!(
                "https://lambda.{}.amazonaws.com/2015-03-31/functions",
                region
            )
        };
        let create_body = format!(
            r#"{{"FunctionName":"{}","Runtime":"{}","Handler":"{}","Role":"{}","Code":{{"S3Bucket":"{}","S3Key":"{}"}},"MemorySize":{},"Timeout":{}}}"#,
            func_name,
            deploy_cfg.runtime,
            deploy_cfg.handler,
            role_arn,
            s3_bucket,
            s3_key,
            deploy_cfg.memory,
            deploy_cfg.timeout
        );
        let h2 = crate::backend::vm::sigv4_sign_pub(
            &config,
            "lambda",
            "POST",
            &create_url,
            create_body.as_bytes(),
        );
        let _ = ureq::post(&create_url)
            .set("Authorization", &h2.authorization)
            .set("x-amz-date", &h2.x_amz_date)
            .set("x-amz-content-sha256", &h2.x_amz_content_sha256)
            .set("Content-Type", "application/json")
            .send_string(&create_body);
    } else if let Err(e) = result {
        eprintln!("error: Lambda update failed: {}", e);
        process::exit(1);
    }
}

// ── fav notebook ─────────────────────────────────────────────────────────────

pub fn cmd_notebook_new(name: &str) {
    use crate::notebook::Notebook;
    let filename = format!("{}.fav.nb", name);
    if std::path::Path::new(&filename).exists() {
        eprintln!("error: {} already exists", filename);
        std::process::exit(1);
    }
    let nb = Notebook::new_notebook(name);
    if let Err(e) = nb.save(&filename) {
        eprintln!("error: {}", e);
        std::process::exit(1);
    }
    println!("created {}", filename);
    println!("next: fav notebook run {}", filename);
}

pub fn cmd_notebook_run(path: &str, no_cache: bool) {
    use crate::notebook::{Notebook, OutputKind, run_all};
    let mut nb = Notebook::load(path).unwrap_or_else(|e| {
        eprintln!("error: {}", e);
        std::process::exit(1);
    });

    if no_cache {
        for cell in &mut nb.cells {
            cell.output = None;
        }
    }

    let results = run_all(&mut nb);

    let mut code_cells = 0usize;
    let mut passed = 0usize;
    let mut failed = 0usize;

    for (id, output) in &results {
        let cell = nb.cells.iter().find(|c| c.id == *id);
        let cell_type = cell.map(|c| &c.cell_type);
        let content_preview = cell
            .map(|c| {
                let first_line = c.content.lines().next().unwrap_or("").to_string();
                if first_line.len() > 60 {
                    format!("{}...", &first_line[..60])
                } else {
                    first_line
                }
            })
            .unwrap_or_default();

        match cell_type {
            Some(crate::notebook::CellType::Markdown) => {
                println!("[{}] markdown — skipped", id);
            }
            Some(crate::notebook::CellType::Code) => {
                code_cells += 1;
                match output.kind {
                    OutputKind::None => println!("[{}] {}\n  → (no output)", id, content_preview),
                    OutputKind::Error => {
                        failed += 1;
                        println!("[{}] {}\n  ERROR: {}", id, content_preview, output.text);
                    }
                    _ => {
                        passed += 1;
                        println!("[{}] {}\n  → {}", id, content_preview, output.text);
                    }
                }
            }
            None => {}
        }
    }

    println!();
    println!(
        "{} cells, {} code cells, {} with output, {} failed",
        results.len(),
        code_cells,
        passed,
        failed
    );

    if let Err(e) = nb.save(path) {
        eprintln!("warning: could not save notebook: {}", e);
    }

    if failed > 0 {
        std::process::exit(1);
    }
}

pub fn cmd_notebook_serve(path: &str, port: u16, no_open: bool) {
    crate::notebook::serve_notebook(path, port, no_open);
}

pub fn cmd_notebook_export(path: &str, out: Option<&str>) {
    use crate::notebook::{Notebook, export_markdown};
    let nb = Notebook::load(path).unwrap_or_else(|e| {
        eprintln!("error: {}", e);
        std::process::exit(1);
    });
    let md = export_markdown(&nb);
    match out {
        Some(out_path) => {
            if let Err(e) = std::fs::write(out_path, &md) {
                eprintln!("error: cannot write {}: {}", out_path, e);
                std::process::exit(1);
            }
            println!("exported to {}", out_path);
        }
        None => print!("{}", md),
    }
}

pub fn cmd_notebook_check(path: &str) {
    use crate::notebook::{Notebook, check_notebook};
    let nb = Notebook::load(path).unwrap_or_else(|e| {
        eprintln!("error: {}", e);
        std::process::exit(1);
    });
    let errors = check_notebook(&nb);
    if errors.is_empty() {
        println!("OK: all code cells type-check successfully");
    } else {
        for (cell_id, msgs) in &errors {
            for msg in msgs {
                eprintln!("[{}] {}", cell_id, msg);
            }
        }
        std::process::exit(1);
    }
}

// ── fav migrate ───────────────────────────────────────────────────────────────

/// Rewrite a single line, replacing v1.x keywords with v2.0.0 equivalents.
/// Returns the rewritten line.
fn migrate_line(line: &str) -> String {
    // Process replacements in order (longest match first to avoid partial hits).
    // Use word-boundary-like logic: only replace at start of line or after whitespace.
    let replacements: &[(&str, &str)] = &[
        ("abstract trf ", "abstract stage "),
        ("abstract flw ", "abstract seq "),
        ("trf ", "stage "),
        ("flw ", "seq "),
    ];

    let mut result = line.to_string();
    for (from, to) in replacements {
        // Replace at start of line
        if result.starts_with(from) {
            result = format!("{}{}", to, &result[from.len()..]);
            continue;
        }
        // Replace after leading whitespace
        let trimmed = result.trim_start();
        let indent_len = result.len() - trimmed.len();
        if trimmed.starts_with(from) {
            result = format!("{}{}{}", &result[..indent_len], to, &trimmed[from.len()..]);
        }
    }
    result
}

/// Migrate source text from v1.x to v2.0.0 syntax.
pub fn migrate_source(src: &str) -> String {
    src.lines()
        .map(|line| migrate_line(line))
        .collect::<Vec<_>>()
        .join("\n")
        + if src.ends_with('\n') { "\n" } else { "" }
}

/// Check whether source text needs migration.
#[allow(dead_code)]
pub fn source_needs_migration(src: &str) -> bool {
    src != migrate_source(src)
}

/// `fav migrate` — migrate .fav files from v1.x to v2.0.0 syntax.
///

// ── migrate_effects_in_source (v13.10.0) ─────────────────────────────────────

/// Infer a ctx type name from a set of `!Effect` names (strings).
fn infer_ctx_type_from_effect_names(effects: &[&str]) -> (&'static str, bool) {
    let has_postgres = effects.iter().any(|&e| matches!(e, "Postgres" | "Db" | "DbRead" | "DbWrite" | "DbAdmin" | "Snowflake"));
    let has_aws = effects.iter().any(|&e| matches!(e, "AWS" | "S3"));
    let has_io = effects.contains(&"Io");
    let has_http = effects.iter().any(|&e| matches!(e, "Http" | "Rpc" | "Network"));
    let has_llm = effects.contains(&"Llm");
    // W010 when multiple distinct capability categories are mixed (manual review needed)
    let needs_w010 = (has_io || has_aws) && has_postgres
        || has_http
        || has_llm
        || effects.len() > 2;
    if needs_w010 {
        return ("AppCtx", true);
    }
    if has_postgres && !has_aws {
        let db_write = effects.iter().any(|&e| matches!(e, "DbWrite" | "DbAdmin"));
        if db_write {
            return ("WriteCtx", false);
        }
        return ("LoadCtx", false);
    }
    if has_aws && !has_postgres {
        return ("WriteCtx", false);
    }
    if has_io && !has_postgres && !has_aws {
        return ("CommonCtx", false);
    }
    ("AppCtx", true)
}

/// Migrate `!Effect` notation in a function signature line to ctx-based style.
/// Returns `(migrated_line, w010_warning_message)`.
fn migrate_effects_in_line(line: &str) -> (String, Option<String>) {
    let trimmed = line.trim_end();

    // Strip optional trailing `{` for fn body opening
    let (scan_str, brace_suffix) = if trimmed.ends_with('{') {
        (trimmed[..trimmed.len()-1].trim_end(), " {")
    } else {
        (trimmed, "")
    };

    // Collect trailing `!Effect` tokens from scan_str
    let mut pos = scan_str.len();
    let mut effects: Vec<&str> = Vec::new();
    loop {
        let s = &scan_str[..pos];
        let s_trim = s.trim_end();
        if s_trim.ends_with(|c: char| c.is_alphanumeric() || c == '_') {
            let word_start = s_trim.rfind(|c: char| !(c.is_alphanumeric() || c == '_'))
                .map(|i| i + 1)
                .unwrap_or(0);
            let word = &s_trim[word_start..];
            if word_start > 0 && s_trim.as_bytes().get(word_start.saturating_sub(1)) == Some(&b'!') {
                effects.push(word);
                pos = word_start - 1; // step back before `!`
                // skip whitespace before `!`
                while pos > 0 && scan_str.as_bytes()[pos - 1] == b' ' {
                    pos -= 1;
                }
                continue;
            }
        }
        break;
    }
    if effects.is_empty() {
        return (line.to_string(), None);
    }

    let base = scan_str[..pos].trim_end();

    // Only migrate fn/stage definitions (must contain `->`)
    if !base.contains("->") {
        return (line.to_string(), None);
    }
    let base_trim = base.trim_start();
    let is_fn_def = base_trim.starts_with("fn ")
        || base_trim.starts_with("pub fn ")
        || base_trim.starts_with("public fn ")
        || base_trim.starts_with("stage ")
        || base_trim.starts_with("pub stage ")
        || base_trim.starts_with("abstract stage ");
    if !is_fn_def {
        return (line.to_string(), None);
    }

    let (ctx_type, needs_w010) = infer_ctx_type_from_effect_names(&effects);
    let indent = &line[..line.len() - line.trim_start().len()];
    let migrated = format!("{}{}{}", indent, base_trim, brace_suffix);

    let w010 = if needs_w010 {
        Some(format!(
            "W010: effect migration requires manual review — removed `{}` (consider adding `ctx: {}` param manually)",
            effects.iter().map(|e| format!("!{}", e)).collect::<Vec<_>>().join(" "),
            ctx_type
        ))
    } else {
        None
    };

    (migrated, w010)
}

/// Migrate `!Effect` notations in a complete source file.
/// Returns `(migrated_source, w010_warnings)`.
pub fn migrate_effects_in_source(src: &str) -> (String, Vec<String>) {
    let mut w010s = Vec::new();
    let lines: Vec<String> = src.lines().enumerate().map(|(i, line)| {
        let (migrated, w010) = migrate_effects_in_line(line);
        if let Some(w) = w010 {
            w010s.push(format!("line {}: {}", i + 1, w));
        }
        migrated
    }).collect();
    let result = lines.join("\n") + if src.ends_with('\n') { "\n" } else { "" };
    (result, w010s)
}

/// Resolve whether to use effects migration based on --from version and --from-effects flag.
/// Extracted as a separate function for testability.
pub fn resolve_use_effects(from_version: Option<&str>, from_effects: bool) -> bool {
    from_effects || matches!(from_version, Some("v13") | Some("13"))
}

/// Migrate old-format fav.toml to current format.
/// Transforms:
///   [rune_dependencies]  →  [dependencies]
///   rune_version = "..." →  version = "..."
///   rune_path = "..."    →  path = "..."
pub fn migrate_fav_toml_source(src: &str) -> String {
    let mut out = String::new();
    for line in src.lines() {
        let trimmed = line.trim_start();
        if trimmed == "[rune_dependencies]" {
            let indent_len = line.len() - trimmed.len();
            out.push_str(&line[..indent_len]);
            out.push_str("[dependencies]\n");
        } else {
            // Handle rune_version/rune_path anywhere in the line (line-start or inline tables)
            let modified = line
                .replace("rune_version = ", "version = ")
                .replace("rune_path = ", "path = ");
            out.push_str(&modified);
            out.push('\n');
        }
    }
    // Preserve trailing newline behaviour (same as migrate_source)
    if !src.ends_with('\n') && out.ends_with('\n') {
        out.pop();
    }
    out
}

// ── fav explain-error ────────────────────────────────────────────────────────

pub fn cmd_explain_error(code: &str) {
    match crate::error_catalog::lookup(code) {
        Some(e) => {
            println!("  Code:  {}", e.code);
            println!("  Title: {}", e.title);
            println!();
            println!("  Description");
            println!("  {}", e.description);
            println!();
            println!("  Example");
            for line in e.example.lines() {
                println!("    {}", line);
            }
            println!();
            println!("  Fix");
            for line in e.fix.lines() {
                println!("    {}", line);
            }
        }
        None => {
            eprintln!("error: unknown error code `{}`", code);
            eprintln!("run `fav explain-error --list` to see all known codes");
            std::process::exit(1);
        }
    }
}

pub fn cmd_explain_error_list() {
    println!("{:<8}  {}", "Code", "Title");
    println!("{}", "-".repeat(60));
    for e in crate::error_catalog::list_all() {
        println!("{:<8}  {}", e.code, e.title);
    }
}

pub fn cmd_explain_error_list_json() {
    let entries = crate::error_catalog::list_all();
    match serde_json::to_string_pretty(entries) {
        Ok(json) => println!("{}", json),
        Err(e) => {
            eprintln!("error: failed to serialize catalog: {}", e);
            std::process::exit(1);
        }
    }
}

