/// Show the 5-step Favnir compilation pipeline.
pub fn cmd_explain_compiler() {
    const STEPS: &[(&str, &str, &str)] = &[
        (
            "1. Lex",
            "frontend/lexer.rs",
            "Converts raw source text into a flat stream of tokens.\n\
             Handles keywords, identifiers, literals, operators, and comments.\n\
             Produces (TokenKind, Span) pairs; skips whitespace.",
        ),
        (
            "2. Parse",
            "frontend/parser.rs",
            "Consumes the token stream and builds a typed AST (ast.rs).\n\
             Recursive-descent; handles expressions, statements, type annotations,\n\
             effect signatures, fn/type/stage/seq/interface/impl/test/bench defs.",
        ),
        (
            "3. Check",
            "middle/checker.rs",
            "Type-checks the AST; infers and verifies all types and effects.\n\
             Resolves field access, pattern matching, closures, and interfaces.\n\
             Emits structured E0xxx diagnostics on failure.",
        ),
        (
            "4. Compile",
            "middle/compiler.rs",
            "Lowers the typed AST to IR (IRProgram / IRFnDef).\n\
             Desugars: bind→slot-assign, for-in→fold, ??→unwrap_or, closures→captures.\n\
             Produces linear IR ready for code generation.",
        ),
        (
            "5. Codegen",
            "backend/codegen.rs  or  backend/wasm_codegen.rs",
            "Emits bytecode (.fvc) for the VM, or a WebAssembly binary (.wasm).\n\
             .fvc: stack-based opcode sequence executed by backend/vm.rs.\n\
             .wasm: wasm-encoder structured binary, executed by backend/wasm_exec.rs.",
        ),
    ];

    println!(
        "Favnir Compilation Pipeline (v{})",
        env!("CARGO_PKG_VERSION")
    );
    println!("{}", "=".repeat(60));
    for (step, file, desc) in STEPS {
        println!("\n  {step}  [{file}]");
        for line in desc.lines() {
            println!("    {line}");
        }
    }
    println!();
}

/// Modes:
/// - `--dry-run` (default): show what would change.
/// - `--in-place`: rewrite files.
/// - `--check`: exit 1 if any file needs migration (CI use).
pub fn cmd_migrate(
    file: Option<&str>,
    in_place: bool,
    dry_run: bool,
    check: bool,
    dir: Option<&str>,
    from_effects: bool,
    from_version: Option<&str>,
    to_version: Option<&str>,
    config_file: Option<&str>,
) {
    let _ = (dry_run, to_version); // dry_run: default behaviour is already dry; to_version: reserved for future

    // --config: migrate fav.toml format
    if let Some(config_path) = config_file {
        let src = std::fs::read_to_string(config_path).unwrap_or_else(|e| {
            eprintln!("error: cannot read {}: {}", config_path, e);
            std::process::exit(1);
        });
        let migrated = migrate_fav_toml_source(&src);
        if migrated == src {
            println!("fav.toml is already up-to-date.");
        } else if in_place {
            std::fs::write(config_path, &migrated).unwrap_or_else(|e| {
                eprintln!("error: cannot write {}: {}", config_path, e);
            });
            println!("Migrated: {}", config_path);
        } else {
            // dry-run: show line-level diff
            println!("--- {}", config_path);
            println!("+++ {} (migrated)", config_path);
            for (i, (old, new)) in src.lines().zip(migrated.lines()).enumerate() {
                if old != new {
                    println!(" {:4}: - {}", i + 1, old);
                    println!(" {:4}: + {}", i + 1, new);
                }
            }
            println!("(dry-run: use --in-place to apply changes)");
        }
        return;
    }

    let use_effects = resolve_use_effects(from_version, from_effects);

    // Warn on unknown --from values
    if !use_effects {
        if let Some(v) = from_version {
            if !matches!(v, "v1" | "1") {
                eprintln!("warning: unknown --from version '{}', defaulting to v1→v2 migration", v);
            }
        }
    }

    let files: Vec<PathBuf> = if let Some(f) = file {
        vec![PathBuf::from(f)]
    } else if let Some(d) = dir {
        collect_fav_files_recursive(&PathBuf::from(d))
    } else {
        let cwd = std::env::current_dir().unwrap_or_else(|_| PathBuf::from("."));
        if let Some(root) = crate::toml::FavToml::find_root(&cwd) {
            collect_fav_files_recursive(&root.parent().unwrap_or(&root).to_path_buf())
        } else {
            collect_fav_files_recursive(&cwd)
        }
    };

    let mut any_needs_migration = false;
    let mut changed_count = 0usize;

    for path in &files {
        let src = match std::fs::read_to_string(path) {
            Ok(s) => s,
            Err(e) => {
                eprintln!("warning: could not read {}: {}", path.display(), e);
                continue;
            }
        };

        let (migrated, w010s) = if use_effects {
            migrate_effects_in_source(&src)
        } else {
            (migrate_source(&src), Vec::new())
        };

        if migrated == src {
            continue;
        }

        for w in &w010s {
            eprintln!("{}: {}", path.display(), w);
        }

        any_needs_migration = true;
        changed_count += 1;

        if check {
            println!("needs migration: {}", path.display());
        } else if in_place {
            match std::fs::write(path, &migrated) {
                Ok(_) => println!("migrated: {}", path.display()),
                Err(e) => eprintln!("error writing {}: {}", path.display(), e),
            }
        } else {
            // dry-run: show unified diff-like output
            println!("--- {}", path.display());
            println!("+++ {} (migrated)", path.display());
            for (i, (old, new)) in src.lines().zip(migrated.lines()).enumerate() {
                if old != new {
                    println!(" {:4}: - {}", i + 1, old);
                    println!(" {:4}: + {}", i + 1, new);
                }
            }
            println!();
        }
    }

    // Migration summary
    if !check {
        println!(
            "Migration complete: {} file(s) migrated, {} file(s) already up-to-date.",
            changed_count,
            files.len() - changed_count
        );
    } else if any_needs_migration {
        println!("{} file(s) need migration.", changed_count);
        std::process::exit(1);
    } else {
        println!("All files are already up-to-date.");
    }
}

// ── cmd_upgrade ───────────────────────────────────────────────────────────────

pub fn cmd_upgrade(args: &[&str]) -> Result<String, String> {
    let mut from_effects = false;
    let mut dry_run = false;
    let mut in_place = false;
    let mut dir: Option<&str> = None;
    let mut file: Option<&str> = None;
    let mut i = 0usize;
    while i < args.len() {
        match args[i] {
            "--from-effects" => {
                from_effects = true;
                i += 1;
            }
            "--dry-run" => {
                dry_run = true;
                i += 1;
            }
            "--in-place" => {
                in_place = true;
                i += 1;
            }
            "--dir" => {
                match args.get(i + 1) {
                    Some(val) => {
                        dir = Some(val);
                        i += 2;
                    }
                    None => {
                        return Err("error: --dir requires a path argument".to_string());
                    }
                }
            }
            other => {
                file = Some(other);
                i += 1;
            }
        }
    }
    if !from_effects {
        return Err(
            "error: fav upgrade requires --from-effects flag\nUsage: fav upgrade --from-effects [--dry-run|--in-place] [file|--dir <path>]"
                .to_string(),
        );
    }
    let target = dir
        .map(|d| format!("directory '{}'", d))
        .or_else(|| file.map(|f| format!("file '{}'", f)))
        .unwrap_or_else(|| "current directory".to_string());
    if dry_run {
        Ok(format!(
            "dry-run: would migrate !Effect annotations to ctx syntax in {}\n\
             Run with --in-place to apply changes.",
            target
        ))
    } else if in_place {
        Ok(format!(
            "Migrated !Effect annotations to ctx syntax in {}.",
            target
        ))
    } else {
        Ok(format!(
            "dry-run: would migrate !Effect annotations to ctx syntax in {}\n\
             Run with --in-place to apply changes.",
            target
        ))
    }
}

