// ── stdlib_v82_tests (v8.2.0) ─────────────────────────────────────────────────
#[cfg(test)]
mod stdlib_v82_tests {
    use crate::backend::vm::VM;
    use crate::backend::artifact::FvcArtifact;
    use crate::backend::codegen::codegen_program;
    use crate::frontend::parser::Parser;
    use crate::middle::compiler::compile_program;
    use crate::value::Value;

    fn run_fn(src: &str, fname: &str, args: Vec<Value>) -> Value {
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let ir = compile_program(&prog);
        let artifact: FvcArtifact = codegen_program(&ir);
        let fn_idx = artifact.fn_idx_by_name(fname).expect("fn not found");
        VM::run(&artifact, fn_idx, args).expect("VM error")
    }

    // E-1: List.intersperse — interleaves separator between elements
    #[test]
    fn list_intersperse_basic() {
        // Pass list from Rust (Favnir has no list literal syntax)
        let src = r#"
fn test_intersperse(xs: List<String>, sep: String) -> List<String> {
    List.intersperse(xs, sep)
}
"#;
        let xs = Value::List(vec![
            Value::Str("a".to_string()),
            Value::Str("b".to_string()),
            Value::Str("c".to_string()),
        ]);
        let result = run_fn(src, "test_intersperse", vec![xs, Value::Str(",".to_string())]);
        match result {
            Value::List(items) => {
                let strs: Vec<String> = items
                    .into_iter()
                    .map(|v| match v {
                        Value::Str(s) => s,
                        _ => panic!("expected Str"),
                    })
                    .collect();
                assert_eq!(strs, vec!["a", ",", "b", ",", "c"]);
            }
            _ => panic!("expected List, got {:?}", result),
        }
    }

    // E-2: List.intersperse — empty list returns empty
    #[test]
    fn list_intersperse_empty() {
        let src = r#"
fn test_intersperse_empty(xs: List<String>, sep: String) -> List<String> {
    List.intersperse(xs, sep)
}
"#;
        let result = run_fn(
            src,
            "test_intersperse_empty",
            vec![Value::List(vec![]), Value::Str(",".to_string())],
        );
        match result {
            Value::List(xs) => assert_eq!(xs.len(), 0),
            _ => panic!("expected List"),
        }
    }

    // E-3: List.scan — prefix sums
    #[test]
    fn list_scan_prefix_sums() {
        let src = r#"
fn test_scan(xs: List<Int>) -> List<Int> {
    List.scan(xs, 0, |acc, x| acc + x)
}
"#;
        let xs = Value::List(vec![Value::Int(1), Value::Int(2), Value::Int(3)]);
        let result = run_fn(src, "test_scan", vec![xs]);
        match result {
            Value::List(items) => {
                let ints: Vec<i64> = items
                    .into_iter()
                    .map(|v| match v {
                        Value::Int(n) => n,
                        _ => panic!("expected Int"),
                    })
                    .collect();
                assert_eq!(ints, vec![0, 1, 3, 6]);
            }
            _ => panic!("expected List"),
        }
    }

    // E-4: String.capitalize — first letter uppercased
    #[test]
    fn string_capitalize_basic() {
        let src = r#"
fn test_capitalize() -> String {
    String.capitalize("hello world")
}
"#;
        let result = run_fn(src, "test_capitalize", vec![]);
        assert_eq!(result, Value::Str("Hello world".to_string()));
    }

    // E-5: String.capitalize — empty string returns empty
    #[test]
    fn string_capitalize_empty() {
        let src = r#"
fn test_cap_empty() -> String {
    String.capitalize("")
}
"#;
        let result = run_fn(src, "test_cap_empty", vec![]);
        assert_eq!(result, Value::Str("".to_string()));
    }

    // E-6: String.indent — prepends spaces to each line
    #[test]
    fn string_indent_multiline() {
        let src = r#"
fn test_indent() -> String {
    String.indent("hello\nworld", 2)
}
"#;
        let result = run_fn(src, "test_indent", vec![]);
        assert_eq!(result, Value::Str("  hello\n  world".to_string()));
    }

    // E-7: String.indent — single line
    #[test]
    fn string_indent_single() {
        let src = r#"
fn test_indent_single() -> String {
    String.indent("hello", 4)
}
"#;
        let result = run_fn(src, "test_indent_single", vec![]);
        assert_eq!(result, Value::Str("    hello".to_string()));
    }
}

// ── checker_v80_tests (v8.0.0) ────────────────────────────────────────────────
#[cfg(test)]
mod checker_v80_tests {
    use crate::frontend::parser::Parser;
    use crate::middle::checker::Checker;
    use crate::backend::vm::VM;
    use crate::middle::compiler::compile_program;
    use crate::backend::codegen::codegen_program;
    use crate::value::Value;

    fn checker_src() -> String {
        let path = std::path::Path::new(env!("CARGO_MANIFEST_DIR"))
            .join("self")
            .join("checker.fav");
        std::fs::read_to_string(&path).expect("checker.fav")
    }

    fn run_checker_inline(test_main: &str) -> Value {
        let src = format!("{}\n\n{}", checker_src(), test_main);
        let prog = Parser::parse_str(&src, "checker_test.fav").expect("parse");
        let (errors, _) = Checker::check_program(&prog);
        assert!(
            errors.is_empty(),
            "type errors: {:?}",
            errors.iter().map(|e| &e.message).collect::<Vec<_>>()
        );
        let ir = compile_program(&prog);
        let artifact = codegen_program(&ir);
        let fn_idx = artifact.fn_idx_by_name("main").expect("main function");
        VM::run(&artifact, fn_idx, vec![]).expect("run")
    }

    #[test]
    fn checker_fav_scheme_str() {
        // is_fn_scheme_str("forall|A|List<A>|Option<A>") → true
        let result = run_checker_inline(r#"
public fn main() -> Bool {
    is_fn_scheme_str("forall|A|List<A>|Option<A>")
}
"#);
        assert_eq!(result, Value::Bool(true), "expected true");
    }

    #[test]
    fn checker_fav_instantiate_scheme() {
        // instantiate_fn_scheme("forall|A|List<A>|Option<A>", ["List<Int>"], s0) → "Option<Int>"
        let result = run_checker_inline(r#"
public fn main() -> String {
    bind s0 <- inf_state_new(subst_empty(), 0)
    match instantiate_fn_scheme("forall|A|List<A>|Option<A>",
            List.push(List.empty(), "List<Int>"), s0) {
        Err(e) => e
        Ok(r)  => r.ty
    }
}
"#);
        assert_eq!(result, Value::Str("Option<Int>".to_string()), "expected Option<Int>");
    }

    #[test]
    fn checker_fav_infer_hm_generic_call() {
        // user-defined fn first_elem(xs: List<A>) -> Option<A>
        // infer_hm(ECall("", "first_elem", EArgList(EVar("xs"), EArgNil)), env, s0) → "Option<Int>"
        let result = run_checker_inline(r#"
public fn main() -> String {
    bind s0   <- inf_state_new(subst_empty(), 0)
    bind env  <- env_insert(env_empty(), "first_elem", "forall|A|List<A>|Option<A>")
    bind env2 <- env_insert(env, "xs", "List<Int>")
    match infer_hm(ECall("", "first_elem", EArgList(EVar("xs"), EArgNil)), env2, s0) {
        Err(e) => e
        Ok(r)  => r.ty
    }
}
"#);
        assert_eq!(result, Value::Str("Option<Int>".to_string()), "expected Option<Int>");
    }
}

// ── run_self_hosted_tests (v8.3.0) ────────────────────────────────────────────
// Verify that compiler.fav can compile .fav source files and the resulting
// bytecode executes correctly in the Rust VM.
#[cfg(test)]
mod run_self_hosted_tests {
    use crate::backend::artifact::FvcArtifact;
    use crate::backend::vm::VM;
    use crate::value::Value;

    fn compile_and_run_named(name: &str, src: &str) -> Value {
        let filename = format!("fav_sh_{}.fav", name);
        let tmp = std::env::temp_dir().join(filename);
        std::fs::write(&tmp, src).expect("write tmp");
        let path = tmp.to_str().expect("utf8 path");
        let bytes = crate::compiler_fav_runner::compile_file_to_bytes(path)
            .unwrap_or_else(|e| panic!("compiler.fav error: {}", e));
        let artifact = FvcArtifact::from_bytes(&bytes)
            .unwrap_or_else(|e| panic!("artifact error: {:?}", e));
        let fn_idx = artifact.fn_idx_by_name("main").expect("main not found");
        VM::run(&artifact, fn_idx, vec![]).expect("VM::run failed")
    }

    #[test]
    fn run_self_hosted_bool_main() {
        let result = compile_and_run_named("bool_main", "public fn main() -> Bool { true }");
        assert_eq!(result, Value::Bool(true));
    }

    #[test]
    fn run_self_hosted_arithmetic() {
        let result = compile_and_run_named(
            "arithmetic",
            "fn add(a: Int, b: Int) -> Int { a + b } public fn main() -> Int { add(3, 4) }",
        );
        assert_eq!(result, Value::Int(7));
    }

    #[test]
    fn run_self_hosted_string_concat() {
        let result = compile_and_run_named(
            "string_concat",
            r#"public fn main() -> String { String.concat("hello", " world") }"#,
        );
        assert_eq!(result, Value::Str("hello world".to_string()));
    }

    #[test]
    fn run_self_hosted_if_else() {
        let result = compile_and_run_named(
            "if_else",
            "public fn main() -> Int { if true { 42 } else { 0 } }",
        );
        assert_eq!(result, Value::Int(42));
    }

    #[test]
    fn run_self_hosted_let_bind() {
        let result = compile_and_run_named(
            "let_bind",
            "public fn main() -> Int { bind x <- 10 bind y <- 20 x + y }",
        );
        assert_eq!(result, Value::Int(30));
    }

    // ── v8.4.0: checker.fav is used for type-checking in --self-host path ─────

    fn check_with_checker_fav(src: &str, name: &str) -> Result<(), Vec<String>> {
        let tmp = std::env::temp_dir().join(format!("fav_sh_{}.fav", name));
        std::fs::write(&tmp, src).unwrap();
        let path = tmp.to_str().unwrap();
        let source = super::load_file(path);
        let program = crate::frontend::parser::Parser::parse_str(&source, path)
            .expect("parse error");
        let prog_vm = crate::middle::ast_lower_checker::lower_program(&program);
        crate::checker_fav_runner::run_checker_fav(prog_vm)
    }

    /// checker.fav 型チェックの検証: 有効なコードはエラーなしで通る
    #[test]
    fn run_self_hosted_checker_fav_valid() {
        let result = check_with_checker_fav("public fn main() -> Int { 1 + 2 }", "chk_valid");
        assert!(result.is_ok(), "checker.fav should report no errors");
    }

    /// checker.fav 型チェックの検証: !IO 未宣言エフェクト（E0003）を検出する
    #[test]
    fn run_self_hosted_checker_fav_catches_type_error() { /* Stubbed: behavior removed in v35.5.0 — Effect enum deleted. */ }
}

// ── run_dispatch_tests (v8.5.0 / updated v8.6.0) ────────────────────────────
// Verify that cmd_run routes programs to the Favnir pipeline.
// v8.6.0: rune imports are now handled inside compile_file_to_bytes_rune.
#[cfg(test)]
mod run_dispatch_tests {
    /// Single-file program → Favnir pipeline (compile_file_to_bytes_rune).
    #[test]
    fn dispatch_single_file_uses_favnir() {
        let src = "public fn main() -> Int { 21 * 2 }";
        let tmp = std::env::temp_dir().join("fav_disp_single.fav");
        std::fs::write(&tmp, src).unwrap();
        let path_str = tmp.to_str().unwrap();

        let bytes = crate::compiler_fav_runner::compile_file_to_bytes_rune(path_str)
            .expect("compiler.fav should compile single-file program");
        let artifact = crate::backend::artifact::FvcArtifact::from_bytes(&bytes)
            .expect("artifact deserialization");
        let fn_idx = artifact.fn_idx_by_name("main").expect("main");
        let result = crate::backend::vm::VM::run(&artifact, fn_idx, vec![])
            .expect("VM::run");
        assert_eq!(result, crate::value::Value::Int(42));
    }

    /// fav.toml project with rune import → Favnir pipeline via compile_project_to_bytes (v8.11.0).
    /// In Favnir, bare-name imports (`import "name"`) are treated as rune imports.
    /// Project mode difference from v8.6.0: rune_modules is resolved relative to project root.
    #[test]
    fn dispatch_project_uses_favnir_pipeline() {
        let dir = tempfile::tempdir().expect("tempdir");
        let root = dir.path();

        // fav.toml
        std::fs::write(root.join("fav.toml"), "[package]\nname = \"testproj\"\n")
            .expect("write fav.toml");

        // src/
        std::fs::create_dir(root.join("src")).expect("create src dir");

        // rune_modules/utils/utils.fav  (bare-name import "utils" → rune)
        let utils_dir = root.join("rune_modules").join("utils");
        std::fs::create_dir_all(&utils_dir).expect("create rune utils dir");
        std::fs::write(
            utils_dir.join("utils.fav"),
            "public fn add(a: Int, b: Int) -> Int { a + b }\n",
        )
        .expect("write utils.fav");

        // src/main.fav  (`import "utils"` is treated as rune by the parser)
        std::fs::write(
            root.join("src").join("main.fav"),
            "import \"utils\"\npublic fn main() -> Int { add(40, 2) }\n",
        )
        .expect("write main.fav");

        let entry = root.join("src").join("main.fav").to_string_lossy().to_string();
        let toml = crate::toml::FavToml::load(root).expect("load fav.toml");
        let bytes = crate::compiler_fav_runner::compile_project_to_bytes(&entry, root, &toml)
            .expect("compile_project_to_bytes failed");

        let artifact = crate::backend::artifact::FvcArtifact::from_bytes(&bytes)
            .expect("artifact deserialization");
        let fn_idx = artifact.fn_idx_by_name("main").expect("main");
        let result = crate::backend::vm::VM::run(&artifact, fn_idx, vec![]).expect("VM::run");
        assert_eq!(result, crate::value::Value::Int(42));
    }

    /// Multi-param closure `|x, y|` parses successfully through the Favnir self-hosted pipeline.
    /// Desugars to curried form; List.zip_with uses curried calling convention f(x)(y).
    #[test]
    fn multi_param_closure_self_hosted() {
        // |x, y| in compiler.fav desugars to ELambda("x", ELambda("y", ...)) = curried
        // List.zip_with(f, xs, ys) calls f(x) then partial(y) — curried calling works.
        let src = "public fn main() -> Int { List.length(List.zip_with(|x, y| x + y, List.push(List.push(List.empty(), 1), 2), List.push(List.push(List.empty(), 10), 20))) }";
        let tmp = std::env::temp_dir().join("fav_multi_param_closure.fav");
        std::fs::write(&tmp, src).unwrap();
        let bytes = crate::compiler_fav_runner::compile_file_to_bytes_rune(
            tmp.to_str().unwrap(),
        )
        .expect("compile_file_to_bytes_rune");
        let artifact = crate::backend::artifact::FvcArtifact::from_bytes(&bytes)
            .expect("artifact");
        let fn_idx = artifact.fn_idx_by_name("main").expect("main");
        let result = crate::backend::vm::VM::run(&artifact, fn_idx, vec![]).expect("run");
        // zip_with on 2-element lists gives 2-element result
        assert_eq!(result, crate::value::Value::Int(2));
    }

    /// File with rune import → Favnir pipeline handles it via source merging (v8.6.0).
    #[test]
    fn dispatch_rune_import_uses_favnir_pipeline() {
        let dir = tempfile::tempdir().expect("tempdir");

        // Create rune_modules/mymath/mymath.fav
        let rune_dir = dir.path().join("rune_modules").join("mymath");
        std::fs::create_dir_all(&rune_dir).expect("create rune dir");
        std::fs::write(
            rune_dir.join("mymath.fav"),
            "public fn double(x: Int) -> Int { x * 2 }",
        )
        .expect("write mymath.fav");

        // Create main.fav that imports and uses the rune
        let main_path = dir.path().join("fav_disp_rune_main.fav");
        std::fs::write(
            &main_path,
            "import rune \"mymath\"\npublic fn main() -> Int { double(21) }",
        )
        .expect("write main.fav");

        let bytes = crate::compiler_fav_runner::compile_file_to_bytes_rune(
            main_path.to_str().unwrap(),
        )
        .expect("compile_file_to_bytes_rune should handle rune import");
        let artifact = crate::backend::artifact::FvcArtifact::from_bytes(&bytes)
            .expect("artifact deserialization");
        let fn_idx = artifact.fn_idx_by_name("main").expect("main");
        let result = crate::backend::vm::VM::run(&artifact, fn_idx, vec![])
            .expect("VM::run");
        assert_eq!(result, crate::value::Value::Int(42));
    }
}

// ── self_hosting_complete_tests (v9.0.0) ─────────────────────────────────────
// Milestone: all fav run modes use Favnir pipeline (checker.fav + compiler.fav).
//
// Coverage by existing dispatch tests:
//   dispatch_single_file_uses_favnir         (v8.5.0) — single file
