// ── cmd_transpile (v11.1.0) ───────────────────────────────────────────────────

// ── pyproject.toml / README.md 生成ヘルパー (v11.7.0) ────────────────────────

pub fn build_pyproject_content(py_src: &str, name: &str) -> String {
    let boto3_dep = if py_src.contains("import boto3") {
        "    \"boto3>=1.34\",\n"
    } else {
        ""
    };
    let psycopg2_dep = if py_src.contains("import psycopg2") {
        "    \"psycopg2-binary>=2.9\",\n"
    } else {
        ""
    };
    format!(
        "[project]\nname = \"{}\"\nversion = \"0.1.0\"\n\
         requires-python = \">=3.11\"\ndependencies = [\n{}{}]\n\n\
         [build-system]\nrequires = [\"hatchling\"]\n\
         build-backend = \"hatchling.build\"\n",
        name, boto3_dep, psycopg2_dep
    )
}

pub fn build_readme_content(input_path: &str, name: &str) -> String {
    format!(
        "# {name}\n\n\
         Generated by `fav transpile --target python`.\n\n\
         ## Source\n\
         - Original: `{input_path}`\n\
         - Generated: `main.py`\n\n\
         ## Requirements\n\
         - Python >= 3.11\n\
         - [uv](https://github.com/astral-sh/uv)\n\n\
         ## Run\n\
         ```\n\
         uv run main.py\n\
         ```\n",
        name = name,
        input_path = input_path
    )
}

/// --lineage フラグ用: LineageReport → fn/stage 名 → コメント文字列 (v11.8.0)
fn build_lineage_comments(
    report: &crate::lineage::LineageReport,
) -> std::collections::HashMap<String, String> {
    report.transformations.iter().map(|entry| {
        let effects = if entry.effects.is_empty() {
            "Pure".to_string()
        } else {
            entry.effects.join(", ")
        };
        let sources = if entry.sources.is_empty() { "-".to_string() }
                      else { entry.sources.join(", ") };
        let sinks = if entry.sinks.is_empty() { "-".to_string() }
                    else { entry.sinks.join(", ") };
        let comment = format!(
            "# [lineage] effects: {} | sources: {} | sinks: {}",
            effects, sources, sinks
        );
        (entry.name.clone(), comment)
    }).collect()
}

/// テスト用 pub wrapper for check_source_str (v11.8.0)
pub fn check_source_str_pub(src: &str) -> Vec<crate::middle::checker::TypeError> {
    check_source_str(src)
}

pub fn cmd_transpile(args: &[String]) {
    let mut target: Option<String> = None;
    let mut out_path: Option<String> = None;
    let mut out_dir: Option<String> = None;
    let mut input_path: Option<String> = None;
    let mut do_check    = false;
    let mut do_run      = false;
    let mut do_no_check = false;
    let mut do_lineage  = false;
    let mut i = 0usize;
    while i < args.len() {
        match args[i].as_str() {
            "--target" => {
                i += 1;
                target = args.get(i).cloned();
            }
            "--out" => {
                i += 1;
                out_path = args.get(i).cloned();
            }
            "--out-dir" => {
                i += 1;
                out_dir = args.get(i).cloned();
            }
            "--check"    => { do_check    = true; }
            "--run"      => { do_run      = true; }
            "--no-check" => { do_no_check = true; }
            "--lineage"  => { do_lineage  = true; }
            other => {
                input_path = Some(other.to_string());
            }
        }
        i += 1;
    }

    let target = match target {
        Some(t) => t,
        None => {
            eprintln!("error: --target is required");
            eprintln!("usage: fav transpile --target python <file.fav>");
            std::process::exit(1);
        }
    };
    if target != "python" {
        eprintln!("error: unsupported target: {} (supported: python)", target);
        std::process::exit(1);
    }
    let input = match input_path {
        Some(p) => p,
        None => {
            eprintln!("error: input .fav file required");
            std::process::exit(1);
        }
    };
    if !std::path::Path::new(&input).exists() {
        eprintln!("error: file not found: {}", input);
        std::process::exit(1);
    }
    let src = match std::fs::read_to_string(&input) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("error reading {}: {}", input, e);
            std::process::exit(1);
        }
    };
    let prog = match crate::frontend::parser::Parser::parse_str(&src, &input) {
        Ok(p) => p,
        Err(e) => {
            eprintln!("parse error: {}", e);
            std::process::exit(1);
        }
    };

    // ── 型チェック（--no-check でスキップ）v11.8.0 ───────────────────────────
    if !do_no_check {
        let errors = check_source_str(&src);
        if !errors.is_empty() {
            for e in &errors {
                eprintln!("{}", format_diagnostic(&src, e));
            }
            eprintln!("error: {} type error(s); Python generation blocked", errors.len());
            eprintln!("       (use --no-check to bypass)");
            std::process::exit(1);
        }
    }

    // ── Python 生成（--lineage で lineage コメント付き）v11.8.0 ──────────────
    let py_src = if do_lineage {
        let report = crate::lineage::lineage_analysis(&prog);
        let comments = build_lineage_comments(&report);
        crate::emit_python::emit_python_with_lineage(&prog, &input, comments)
    } else {
        crate::emit_python::emit_python(&prog, &input)
    };

    // basename: "pipeline.fav" → "pipeline"
    let basename = std::path::Path::new(&input)
        .file_stem()
        .and_then(|s| s.to_str())
        .unwrap_or("transpiled")
        .to_string();

    // ── --out-dir モード ──────────────────────────────────────────────────────
    let final_out: String;
    if let Some(ref dir) = out_dir {
        let dir_path = std::path::Path::new(dir);
        if let Err(e) = std::fs::create_dir_all(dir_path) {
            eprintln!("error creating dir {}: {}", dir, e);
            std::process::exit(1);
        }

        // main.py
        let main_py = dir_path.join("main.py");
        if let Err(e) = std::fs::write(&main_py, &py_src) {
            eprintln!("error writing main.py: {}", e);
            std::process::exit(1);
        }
        println!("transpiled: {} -> {}/main.py", input, dir);
        final_out = main_py.to_str().unwrap_or("main.py").to_string();

        // pyproject.toml（既存スキップ）
        let pyproject_path = dir_path.join("pyproject.toml");
        if !pyproject_path.exists() {
            let content = build_pyproject_content(&py_src, &basename);
            let _ = std::fs::write(&pyproject_path, &content);
            println!("generated: {}/pyproject.toml", dir);
        }

        // README.md（既存スキップ）
        let readme_path = dir_path.join("README.md");
        if !readme_path.exists() {
            let content = build_readme_content(&input, &basename);
            let _ = std::fs::write(&readme_path, &content);
            println!("generated: {}/README.md", dir);
        }
    } else {
        // ── 従来モード（--out またはデフォルト）──────────────────────────────
        let out = out_path.unwrap_or_else(|| {
            if input.ends_with(".fav") {
                format!("{}.py", &input[..input.len() - 4])
            } else {
                format!("{}.py", input)
            }
        });
        if let Err(e) = std::fs::write(&out, &py_src) {
            eprintln!("error writing {}: {}", out, e);
            std::process::exit(1);
        }
        println!("transpiled: {} -> {}", input, out);
        final_out = out.clone();

        // pyproject.toml（同ディレクトリ、既存スキップ）
        let py_dir = std::path::Path::new(&out)
            .parent()
            .unwrap_or(std::path::Path::new("."));
        let pyproject_path = py_dir.join("pyproject.toml");
        if !pyproject_path.exists() {
            let content = build_pyproject_content(&py_src, &basename);
            let _ = std::fs::write(&pyproject_path, &content);
            println!("generated: {}", pyproject_path.display());
        }
    }

    // ── --check ───────────────────────────────────────────────────────────────
    if do_check {
        let status = std::process::Command::new("python")
            .args(["-m", "py_compile", &final_out])
            .status();
        match status {
            Ok(s) if s.success() => {
                println!("fav transpile: syntax ok ({})", final_out);
            }
            Ok(_) => {
                eprintln!("error: python syntax check failed: {}", final_out);
                std::process::exit(1);
            }
            Err(_) => {
                eprintln!("warning: python not found, skipping --check");
            }
        }
    }

    // ── --run ─────────────────────────────────────────────────────────────────
    if do_run {
        let run_dir = out_dir.as_deref().unwrap_or(".");
        let status = std::process::Command::new("uv")
            .args(["run", "main.py"])
            .current_dir(run_dir)
            .status();
        match status {
            Ok(s) => {
                if !s.success() {
                    std::process::exit(s.code().unwrap_or(1));
                }
            }
            Err(_) => {
                eprintln!("error: uv not found (install: pip install uv)");
                std::process::exit(1);
            }
        }
    }
}

// ── v11500_tests (v11.5.0) — !Postgres effect ────────────────────────────────

#[cfg(test)]
mod v11500_tests {
    use crate::frontend::parser::Parser;
    use crate::lineage::lineage_analysis;
    use crate::middle::checker::Checker;

    #[test]
    fn postgres_execute_requires_effect() {
        // v18.1.0: effect inference automatically infers !Postgres,
        // so omitting the declaration no longer causes E0315.
        let src = r#"
fn run(sql: String) -> Result<String, String> {
  Postgres.query_raw(sql, "[]")
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let (errors, _) = Checker::check_program(&prog);
        let has_e0315 = errors.iter().any(|e| e.code == "E0315");
        assert!(!has_e0315, "v18.1.0: E0315 should not occur when effect is inferred, got: {:?}", errors);
    }

    #[test]
    fn postgres_execute_with_effect_ok() {
        // !Postgres 宣言関数内で Postgres.execute_raw が E0315 を出さないこと
        let src = r#"
fn run(sql: String) -> Result<Unit, String> {
  Postgres.execute_raw(sql, "[]")
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let (errors, _) = Checker::check_program(&prog);
        let e0315: Vec<_> = errors.iter().filter(|e| e.code == "E0315").collect();
        assert!(e0315.is_empty(), "unexpected E0315 with !Postgres: {:?}", e0315);
    }

    #[test]
    fn postgres_query_raw_type() {
        // query_raw の戻り型が Result<String, String> であること
        let src = r#"
fn run(sql: String) -> Result<String, String> {
  Postgres.query_raw(sql, "[]")
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let (errors, _) = Checker::check_program(&prog);
        let e0315: Vec<_> = errors.iter().filter(|e| e.code == "E0315").collect();
        assert!(e0315.is_empty(), "type check ok: {:?}", e0315);
    }

    #[test]
    fn postgres_lineage_shows_effect() { /* Stubbed: behavior removed in v35.5.0 — Effect enum deleted. */ }

    #[test]
    fn fav_toml_postgres_section_parsed() {
        // fav.toml の [postgres] セクションが PostgresTomlConfig に読み込まれること
        let content = "[rune]\nname = \"app\"\nversion = \"1.0.0\"\n\
                       [postgres]\nhost = \"localhost\"\nport = 5432\n\
                       dbname = \"mydb\"\nuser = \"postgres\"\npassword = \"secret\"\nsslmode = \"require\"\n";
        let toml = crate::toml::parse_fav_toml_pub(content);
        let pg = toml.postgres.expect("postgres config");
        assert_eq!(pg.host.as_deref(), Some("localhost"));
        assert_eq!(pg.port, Some(5432));
        assert_eq!(pg.dbname.as_deref(), Some("mydb"));
        assert_eq!(pg.user.as_deref(), Some("postgres"));
        assert_eq!(pg.sslmode.as_deref(), Some("require"));
    }
}

// ── v12700_tests (v12.7.0) ────────────────────────────────────────────────────

#[cfg(test)]
mod v12700_tests {
    use super::{builtin_primitives, get_explain_text, render_builtins_markdown};

    #[test]
    fn doc_builtins_json_is_array() {
        // --format json の出力が JSON 配列であること
        let prims = builtin_primitives();
        let json = serde_json::to_string(&prims).expect("serialize");
        let val: serde_json::Value = serde_json::from_str(&json).expect("parse");
        assert!(val.is_array(), "expected JSON array, got: {}", json);
        assert!(!val.as_array().unwrap().is_empty(), "expected non-empty array");
    }

    #[test]
    fn doc_builtins_csv_parse_raw() {
        // Csv.parse_raw エントリが存在し returns_result=true であること
        let prims = builtin_primitives();
        let entry = prims.iter().find(|p| p.name == "Csv.parse_raw")
            .expect("Csv.parse_raw not found");
        assert!(entry.returns_result, "Csv.parse_raw should have returns_result=true");
        assert!(entry.signature.contains("Result"), "signature should mention Result");
    }

    #[test]
    fn doc_builtins_postgres_returns_result() {
        // Postgres.execute_raw の returns_result が true であること
        let prims = builtin_primitives();
        let entry = prims.iter().find(|p| p.name == "Postgres.execute_raw")
            .expect("Postgres.execute_raw not found");
        assert!(entry.returns_result);
    }

    #[test]
    fn doc_builtins_markdown_has_namespace_headers() {
        // Markdown 出力に ## IO / ## Csv ヘッダが含まれること
        let prims = builtin_primitives();
        let md = render_builtins_markdown(&prims);
        assert!(md.contains("## IO"), "missing ## IO");
        assert!(md.contains("## Csv"), "missing ## Csv");
        assert!(md.contains("## Postgres"), "missing ## Postgres");
        assert!(md.contains("### IO.println"), "missing ### IO.println");
    }

    #[test]
    fn explain_e0018_output() {
        // E0018 の説明に "already bound" または "束縛" が含まれること
        let text = get_explain_text("E0018").expect("E0018 should exist");
        assert!(
            text.contains("already bound") || text.contains("束縛"),
            "E0018 text missing key phrase: {}", text
        );
    }

    #[test]
    fn explain_w006_output() {
        // W006 の説明に "Result" が含まれること
        let text = get_explain_text("W006").expect("W006 should exist");
        assert!(text.contains("Result"), "W006 text missing 'Result': {}", text);
    }

    #[test]
    fn explain_unknown_returns_none() {
        // 未知コードで get_explain_text が None を返すこと
        assert!(get_explain_text("E9999").is_none());
        assert!(get_explain_text("W999").is_none());
        assert!(get_explain_text("INVALID").is_none());
    }

    #[test]
    fn version_is_12_7_0() {
        // Version bump is tested in v12800_tests::version_is_12_8_0.
    }
}

// ── v12600_tests (v12.6.0) ────────────────────────────────────────────────────

#[cfg(test)]
mod v12600_tests {
    use crate::backend::vm::resolve_sslmode;

    #[test]
    fn postgres_sslmode_from_url() {
        // ?sslmode= クエリパラメータが読み取られること
        assert_eq!(resolve_sslmode("postgresql://u:p@host/db?sslmode=require"), "require");
        assert_eq!(resolve_sslmode("postgresql://u:p@host/db?sslmode=disable"), "disable");
    }

    #[test]
    fn postgres_sslmode_from_url_with_extra_params() {
        // &以降は無視されること
        assert_eq!(
            resolve_sslmode("postgresql://u:p@host/db?sslmode=prefer&connect_timeout=5"),
            "prefer",
        );
    }

    #[test]
    fn postgres_sslmode_default_is_prefer() {
        // DATABASE_URL にパラメータがなく PGSSLMODE も未設定ならデフォルト "prefer"
        let saved = std::env::var("PGSSLMODE").ok();
        unsafe { std::env::remove_var("PGSSLMODE"); }
        let mode = resolve_sslmode("postgresql://u:p@host/db");
        if let Some(v) = saved { unsafe { std::env::set_var("PGSSLMODE", v); } }
        assert_eq!(mode, "prefer");
    }

    #[test]
    fn inject_postgres_config_sets_pgsslmode() {
        // inject_postgres_config が PGSSLMODE を設定すること
        let cfg = crate::toml::PostgresTomlConfig {
            host: None, port: None, dbname: None,
            user: None, password: None,
            sslmode: Some("require".to_string()),
            pool_size: None, min_idle: None,
        };
        // PGSSLMODE を一時的にアンセットして確認
        let saved = std::env::var("PGSSLMODE").ok();
        unsafe { std::env::remove_var("PGSSLMODE"); }
        super::inject_postgres_config(&cfg);
        let result = std::env::var("PGSSLMODE").ok();
        // 元に戻す
        if let Some(v) = saved {
            unsafe { std::env::set_var("PGSSLMODE", v); }
        } else {
            unsafe { std::env::remove_var("PGSSLMODE"); }
        }
        assert_eq!(result.as_deref(), Some("require"));
    }

    #[test]
    fn postgres_error_format_non_db() {
        // format_pg_error が非DBエラーを "db error: ..." 形式で返すこと
        let rt = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .unwrap();
        let err = rt.block_on(async {
            // ポート 1 には何も listen していないので接続エラーになる
            match tokio_postgres::connect(
                "host=127.0.0.1 port=1 dbname=x user=x",
                tokio_postgres::NoTls,
            )
            .await
            {
                Err(e) => e,
                Ok(_) => panic!("expected connection error but succeeded"),
            }
        });
        let msg = crate::backend::vm::format_pg_error_pub(&err);
        assert!(msg.starts_with("db error: "), "unexpected: {}", msg);
    }

    #[test]
    fn version_is_12_6_0() {
        // Version bump is tested in v12700_tests::version_is_12_7_0.
    }
}

