// ── v11600_tests (v11.6.0) — !Postgres → psycopg2 transpile ─────────────────

#[cfg(test)]
mod v11600_tests {
    use crate::emit_python::emit_python_str;

    fn pg_src(body: &str) -> String {
        format!(
            "fn run(sql: String) -> Result<String, String> {{\n{}\n}}",
            body
        )
    }

    #[test]
    fn transpile_postgres_execute_raw() {
        let src = pg_src("  Postgres.execute_raw(sql, \"[]\")");
        let out = emit_python_str(&src);
        assert!(out.contains("_pg_execute("), "expected _pg_execute:\n{}", out);
    }

    #[test]
    fn transpile_postgres_query_raw() {
        let src = pg_src("  Postgres.query_raw(sql, \"[]\")");
        let out = emit_python_str(&src);
        assert!(out.contains("_pg_query("), "expected _pg_query:\n{}", out);
    }

    #[test]
    fn transpile_postgres_imports_psycopg2() {
        let src = pg_src("  Postgres.execute_raw(sql, \"[]\")");
        let out = emit_python_str(&src);
        assert!(out.contains("import psycopg2"), "expected import psycopg2:\n{}", out);
    }

    #[test]
    fn transpile_postgres_pg_connect_helper() {
        let src = pg_src("  Postgres.execute_raw(sql, \"[]\")");
        let out = emit_python_str(&src);
        assert!(out.contains("def _pg_connect()"), "expected _pg_connect helper:\n{}", out);
    }

    #[test]
    fn transpile_postgres_pyproject_psycopg2_dep() {
        // pyproject.toml 生成は cmd_transpile (ファイル I/O) のため、
        // Python ソース文字列に "import psycopg2" が含まれることで間接確認
        let src = pg_src("  Postgres.query_raw(sql, \"[]\")");
        let out = emit_python_str(&src);
        assert!(out.contains("import psycopg2"), "psycopg2 import present → pyproject dep added:\n{}", out);
    }

    #[test]
    fn transpile_postgres_pipeline_smoke() {
        let src = "type Row = {\n  id: Int\n  name: String\n}\nfn insert_row(sql: String) -> Result<String, String> {\n  Postgres.execute_raw(sql, \"[]\")\n}\nfn select_rows(sql: String) -> Result<String, String> {\n  Postgres.query_raw(sql, \"[]\")\n}\n";
        let out = emit_python_str(src);
        assert!(out.contains("import psycopg2"), "psycopg2:\n{}", out);
        assert!(out.contains("_pg_execute("), "execute:\n{}", out);
        assert!(out.contains("_pg_query("), "query:\n{}", out);
        assert!(out.contains("def _pg_connect()"), "connect helper:\n{}", out);
        assert!(out.contains("def _pg_execute("), "execute helper:\n{}", out);
        assert!(out.contains("def _pg_query("), "query helper:\n{}", out);
    }
}

// ── v11700_tests (v11.7.0) — uv 統合: --out-dir / --check / --run ────────────

#[cfg(test)]
mod v11700_tests {
    use crate::driver::{build_pyproject_content, build_readme_content};
    use crate::emit_python::emit_python_str;
    use std::fs;
    use tempfile::TempDir;

    fn write_fav(dir: &TempDir, name: &str, src: &str) -> String {
        let path = dir.path().join(name);
        fs::write(&path, src).unwrap();
        path.to_str().unwrap().to_string()
    }

    fn run_transpile(args: &[&str]) {
        let str_args: Vec<String> = args.iter().map(|s| s.to_string()).collect();
        crate::driver::cmd_transpile(&str_args);
    }

    #[test]
    fn transpile_out_dir_creates_main_py() {
        let tmp = TempDir::new().unwrap();
        let fav_path = write_fav(&tmp, "hello.fav", "fn greet(name: String) -> String {\n  name\n}");
        let out_dir = tmp.path().join("out");
        run_transpile(&[
            "--target", "python",
            &fav_path,
            "--out-dir", out_dir.to_str().unwrap(),
        ]);
        assert!(out_dir.join("main.py").exists(), "main.py should exist");
        let py = fs::read_to_string(out_dir.join("main.py")).unwrap();
        assert!(py.contains("def greet("), "greet fn:\n{}", py);
    }

    #[test]
    fn transpile_out_dir_creates_pyproject() {
        let tmp = TempDir::new().unwrap();
        let fav_path = write_fav(&tmp, "app.fav", "fn run() -> String {\n  \"ok\"\n}");
        let out_dir = tmp.path().join("out");
        run_transpile(&[
            "--target", "python",
            &fav_path,
            "--out-dir", out_dir.to_str().unwrap(),
        ]);
        assert!(out_dir.join("pyproject.toml").exists(), "pyproject.toml should exist");
    }

    #[test]
    fn transpile_out_dir_creates_readme() {
        let tmp = TempDir::new().unwrap();
        let fav_path = write_fav(&tmp, "app.fav", "fn run() -> String {\n  \"ok\"\n}");
        let out_dir = tmp.path().join("out");
        run_transpile(&[
            "--target", "python",
            &fav_path,
            "--out-dir", out_dir.to_str().unwrap(),
        ]);
        assert!(out_dir.join("README.md").exists(), "README.md should exist");
        let readme = fs::read_to_string(out_dir.join("README.md")).unwrap();
        assert!(readme.contains("uv run main.py"), "readme content:\n{}", readme);
    }

    #[test]
    fn transpile_check_valid_python() {
        // --check フラグは python がなければ warning のみ（CI 環境でも安全）
        // emit_python_str で valid Python が生成されることを確認
        let src = "fn add(a: Int, b: Int) -> Int {\n  a\n}";
        let out = emit_python_str(src);
        // 生成コードに Python の構文的に壊れた要素がないことを基本チェック
        assert!(out.contains("def add("), "add fn:\n{}", out);
        assert!(!out.contains("syntax error"), "no syntax error text:\n{}", out);
    }

    #[test]
    fn transpile_pyproject_project_name() {
        let py_src = "# generated";
        let content = build_pyproject_content(py_src, "my_pipeline");
        assert!(content.contains("name = \"my_pipeline\""), "project name:\n{}", content);
    }

    #[test]
    fn transpile_pyproject_has_correct_deps() {
        // boto3 + psycopg2 両方含む場合
        let py_src = "import boto3\nimport psycopg2\n# code";
        let content = build_pyproject_content(py_src, "demo");
        assert!(content.contains("boto3>=1.34"), "boto3 dep:\n{}", content);
        assert!(content.contains("psycopg2-binary>=2.9"), "psycopg2 dep:\n{}", content);

        // どちらも含まない場合
        let py_empty = "print('hello')";
        let content2 = build_pyproject_content(py_empty, "demo");
        assert!(!content2.contains("boto3"), "no boto3:\n{}", content2);
        assert!(!content2.contains("psycopg2"), "no psycopg2:\n{}", content2);
    }
}

// ── v11800_tests (v11.8.0) — checker 統合 + lineage コメント ─────────────────

#[cfg(test)]
mod v11800_tests {
    use crate::emit_python::{emit_python_str, emit_python_with_lineage};
    use crate::frontend::parser::Parser;
    use crate::lineage::lineage_analysis;
    use std::collections::HashMap;

    fn make_lineage_comments(src: &str) -> HashMap<String, String> {
        let prog = Parser::parse_str(src, "<test>").unwrap();
        let report = lineage_analysis(&prog);
        report.transformations.iter().map(|entry| {
            let effects = if entry.effects.is_empty() { "Pure".to_string() }
                          else { entry.effects.join(", ") };
            let sources = if entry.sources.is_empty() { "-".to_string() }
                          else { entry.sources.join(", ") };
            let sinks   = if entry.sinks.is_empty()   { "-".to_string() }
                          else { entry.sinks.join(", ") };
            let comment = format!(
                "# [lineage] effects: {} | sources: {} | sinks: {}",
                effects, sources, sinks
            );
            (entry.name.clone(), comment)
        }).collect()
    }

    #[test]
    fn transpile_blocks_on_type_error() { /* Stubbed: behavior removed in v35.5.0 — Effect enum deleted. */ }

    #[test]
    fn transpile_type_check_passes_valid() {
        // 正常コードではエラーなし
        let src = "fn greet(name: String) -> String {\n  name\n}";
        let errors = crate::driver::check_source_str_pub(src);
        assert!(errors.is_empty(), "expected no errors: {:?}", errors);
    }

    #[test]
    fn transpile_lineage_comment_effects() { /* Stubbed: behavior removed in v35.5.0 — Effect enum deleted. */ }

    #[test]
    fn transpile_lineage_comment_pure_fn() {
        // エフェクトなし fn: lineage_analysis は effects なし fn を含まないため
        // テスト側で直接 "Pure" コメントを設定して挿入を確認
        let src = "fn add(a: Int, b: Int) -> Int {\n  a\n}";
        let prog = Parser::parse_str(src, "<test>").unwrap();
        let mut comments = HashMap::new();
        comments.insert("add".to_string(), "# [lineage] effects: Pure | sources: - | sinks: -".to_string());
        let out = emit_python_with_lineage(&prog, "<test>", comments);
        assert!(out.contains("# [lineage] effects: Pure"), "pure fn:\n{}", out);
    }

    #[test]
    fn transpile_no_check_skips_error() {
        // --no-check 相当: emit_python_str は型チェックを呼ばないため、
        // 型エラーのあるコードでも Python が生成される
        let src = "fn run(sql: String) -> Result<String, String> {\n  Postgres.query_raw(sql, \"[]\")\n}";
        let out = emit_python_str(src);
        assert!(out.contains("def run("), "python generated despite type error:\n{}", out);
    }

    #[test]
    fn transpile_lineage_postgres_fn() { /* Stubbed: behavior removed in v35.5.0 — Effect enum deleted. */ }
}

