// ── v164000_tests (v16.4.0) — stdlib 拡充 ────────────────────────────────────
#[cfg(test)]
mod v164000_tests {
    use super::{build_artifact, exec_artifact_main};
    use crate::frontend::parser::Parser;
    use crate::value::Value;

    fn run(src: &str) -> Value {
        let program = Parser::parse_str(src, "v164000_test.fav").expect("parse");
        let artifact = build_artifact(&program);
        exec_artifact_main(&artifact, None).expect("exec")
    }

    fn run_int(src: &str) -> i64 {
        match run(src) {
            Value::Int(n) => n,
            other => panic!("expected Int, got {:?}", other),
        }
    }

    #[test]
    #[ignore = "historical version check"]
    fn version_is_16_4_0() {
        let cargo = std::fs::read_to_string("Cargo.toml").unwrap();
        assert!(
            cargo.contains("version = \"16.4.0\""),
            "Cargo.toml version should be 16.4.0"
        );
    }

    #[test]
    fn list_group_by_works() {
        // group_by で 2 グループに分かれることを確認
        let result = run_int(r#"
public fn main() -> Int {
    bind xs <- List.push(List.push(List.push(List.push(List.empty(), 1), 2), 3), 4)
    bind groups <- List.group_by(|n| if Math.abs(n) == 2 { "two" } else { "other" }, xs)
    bind twos <- Map.get(groups, "two")
    match twos {
        some(lst) => List.length(lst)
        none      => 0
    }
}
"#);
        assert_eq!(result, 1);
    }

    #[test]
    fn list_chunk_works() {
        // chunk(xs, 3) で List<List<T>> — 最初のチャンクが 3 要素
        let result = run_int(r#"
public fn main() -> Int {
    bind xs     <- List.range(1, 10)
    bind chunks <- List.chunk(xs, 3)
    bind first  <- List.first(chunks)
    match first {
        some(chunk) => List.length(chunk)
        none        => 0
    }
}
"#);
        assert_eq!(result, 3);
    }

    #[test]
    fn string_split_works() {
        // split("a,b,c", ",") → 3 要素リスト
        let result = run_int(r#"
public fn main() -> Int {
    bind parts <- String.split("a,b,c", ",")
    List.length(parts)
}
"#);
        assert_eq!(result, 3);
    }

    #[test]
    fn datetime_now_unix_works() {
        // now_unix() は正の Int を返す
        let result = run_int(r#"
public fn main() -> Int {
    DateTime.now_unix()
}
"#);
        assert!(result > 0, "DateTime.now_unix() should return a positive Int, got {}", result);
    }

    #[test]
    fn math_round_to_works() {
        // round_to(3.14159, 2) == 3.14
        let result = run(r#"
public fn main() -> Float {
    Math.round_to(3.14159, 2)
}
"#);
        match result {
            Value::Float(f) => {
                let diff = (f - 3.14f64).abs();
                assert!(diff < 0.001, "Math.round_to(3.14159, 2) should be ~3.14, got {}", f);
            }
            other => panic!("expected Float, got {:?}", other),
        }
    }
}

// ── v166000_tests (v16.6.0) — モジュールシステム強化（Namespace Alias）────────
#[cfg(test)]
mod v166000_tests {
    use super::{build_artifact, exec_artifact_main};
    use crate::frontend::parser::Parser;
    use crate::value::Value;

    fn run(src: &str) -> Value {
        let program = Parser::parse_str(src, "v166000_test.fav").expect("parse");
        let artifact = build_artifact(&program);
        exec_artifact_main(&artifact, None).expect("exec")
    }

    fn run_str(src: &str) -> String {
        match run(src) {
            Value::Str(s) => s,
            other => panic!("expected Str, got {:?}", other),
        }
    }

    fn run_int(src: &str) -> i64 {
        match run(src) {
            Value::Int(n) => n,
            other => panic!("expected Int, got {:?}", other),
        }
    }

    #[test]
    #[ignore = "historical version check"]
    fn version_is_16_6_0() {
        let cargo = std::fs::read_to_string("Cargo.toml").unwrap();
        assert!(
            cargo.contains("version = \"16.6.0\""),
            "Cargo.toml version should be 16.6.0"
        );
    }

    #[test]
    fn namespace_alias_string() {
        // `use String as S` → S.concat works like String.concat
        let result = run_str(r#"
use String as S

public fn main() -> String {
    S.concat("hello", " world")
}
"#);
        assert_eq!(result, "hello world");
    }

    #[test]
    fn namespace_alias_list() {
        // `use List as L` → L.length works like List.length
        let result = run_int(r#"
use List as L

public fn main() -> Int {
    bind xs <- L.push(L.push(L.push(L.empty(), 10), 20), 30)
    L.length(xs)
}
"#);
        assert_eq!(result, 3);
    }

    #[test]
    fn namespace_alias_math() {
        // `use Math as M` → M.abs works like Math.abs
        let result = run_int(r#"
use Math as M

public fn main() -> Int {
    M.abs(-42)
}
"#);
        assert_eq!(result, 42);
    }

    #[test]
    fn namespace_alias_multi() {
        // Multiple aliases coexist: use String as S; use List as L
        let result = run_int(r#"
use String as S
use List as L

public fn main() -> Int {
    bind parts <- S.split("a,b,c", ",")
    L.length(parts)
}
"#);
        assert_eq!(result, 3);
    }
}

// ── v167000_tests (v16.7.0) — fav test 成熟（assert_eq / test_group / snapshot）──
#[cfg(test)]
mod v167000_tests {
    use super::{build_artifact, collect_test_cases, exec_artifact_main};
    use crate::ast;
    use crate::frontend::parser::Parser;
    use crate::value::Value;
    use crate::backend::vm::VM;

    fn run(src: &str) -> Value {
        let program = Parser::parse_str(src, "v167000_test.fav").expect("parse");
        let artifact = build_artifact(&program);
        exec_artifact_main(&artifact, None).expect("exec")
    }

    /// Run a Favnir fav-test file and return (passed, failed) counts.
    fn run_tests(src: &str) -> (usize, usize) {
        let program = Parser::parse_str(src, "v167000_test.fav").expect("parse");
        let programs = vec![("v167000_test.fav".to_string(), program)];
        let (tests, _) = collect_test_cases(programs, None);
        let artifact = {
            let prog = Parser::parse_str(src, "v167000_test.fav").expect("parse");
            build_artifact(&prog)
        };
        let mut passed = 0;
        let mut failed = 0;
        for (_, _, fn_name, _) in &tests {
            match VM::run(&artifact, artifact.fn_idx_by_name(fn_name).expect("fn"), vec![]) {
                Ok(_) => passed += 1,
                Err(_) => failed += 1,
            }
        }
        (passed, failed)
    }

    #[test]
    #[ignore = "historical version check"]
    fn version_is_16_7_0() {
        let cargo = std::fs::read_to_string("Cargo.toml").unwrap();
        assert!(
            cargo.contains("version = \"16.7.0\""),
            "Cargo.toml version should be 16.7.0"
        );
    }

    #[test]
    fn assert_eq_pass() {
        // assert_eq with equal values should produce a passing test
        let src = r#"
test "eq pass" {
  assert_eq(2, 2)
}
"#;
        let (passed, failed) = run_tests(src);
        assert_eq!(passed, 1, "assert_eq with equal values should PASS");
        assert_eq!(failed, 0);
    }

    #[test]
    fn assert_eq_fail() {
        // assert_eq with unequal values should produce a failing test
        let src = r#"
test "eq fail" {
  assert_eq(1, 2)
}
"#;
        let (passed, failed) = run_tests(src);
        assert_eq!(failed, 1, "assert_eq with unequal values should FAIL");
        assert_eq!(passed, 0);
    }

    #[test]
    fn test_group_runs_all() {
        // test_group should run all tests inside and both should pass
        let src = r#"
test_group "my group" {
  test "first" {
    assert_true(true)
  }
  test "second" {
    assert_eq(1 + 1, 2)
  }
}
"#;
        let (passed, failed) = run_tests(src);
        assert_eq!(passed, 2, "test_group should run all 2 tests");
        assert_eq!(failed, 0);
    }

    #[test]
    fn assert_snapshot_creates_file() {
        // First run: .snap/test_snap_v167.snap should be created
        let snap_path = std::path::Path::new(".snap/test_snap_v167.snap");
        // Remove existing snapshot for a clean test
        let _ = std::fs::remove_file(snap_path);

        let src = r#"
test "snapshot test" {
  assert_snapshot("hello snapshot", "test_snap_v167")
}
"#;
        let (passed, failed) = run_tests(src);
        assert_eq!(passed, 1, "assert_snapshot initial run should PASS");
        assert_eq!(failed, 0);
        assert!(snap_path.exists(), ".snap/test_snap_v167.snap should have been created");

        // Cleanup
        let _ = std::fs::remove_file(snap_path);
    }
}

// ── v168000_tests (v16.8.0) — tap / inspect パイプライン演算子 ────────────────
#[cfg(test)]
mod v168000_tests {
    use super::{build_artifact, exec_artifact_main};
    use crate::frontend::parser::Parser;
    use crate::middle::compiler::{set_no_tap_mode, compile_program};
    use crate::backend::codegen::codegen_program;

    fn run_pipeline_src(src: &str) -> crate::value::Value {
        let program = Parser::parse_str(src, "test.fav").expect("parse");
        let artifact = build_artifact(&program);
        exec_artifact_main(&artifact, None).expect("exec")
    }

    #[test]
    #[ignore = "historical version check"]
    fn version_is_16_8_0() {
        let cargo = include_str!("../Cargo.toml");
        assert!(cargo.contains("\"16.8.0\""), "Cargo.toml should have version 16.8.0");
    }

    #[test]
    fn tap_passes_value_through() {
        // tap should not modify the value flowing through the pipeline
        let src = r#"
stage AddOne: Int -> Int = |x| { x + 1 }

seq Pipeline = AddOne |> tap(|v| IO.println("tapped")) |> AddOne

public fn main() -> Int {
    1 |> Pipeline
}
"#;
        let result = run_pipeline_src(src);
        assert_eq!(result, crate::value::Value::Int(3), "tap should pass value through: 1+1+1=3");
    }

    #[test]
    fn tap_calls_observer_does_not_crash() {
        // tap with an observer that uses io.println — must not crash
        let src = r#"
stage Identity: Int -> Int = |x| { x }

seq Pipeline = Identity |> tap(|v| IO.println("observer called"))

public fn main() -> Int {
    42 |> Pipeline
}
"#;
        let result = run_pipeline_src(src);
        assert_eq!(result, crate::value::Value::Int(42), "tap should pass 42 through");
    }

    #[test]
    fn inspect_passes_value_through() {
        // inspect should not modify the value
        let src = r#"
stage Double: Int -> Int = |x| { x * 2 }

seq Pipeline = Double |> inspect |> Double

public fn main() -> Int {
    3 |> Pipeline
}
"#;
        let result = run_pipeline_src(src);
        assert_eq!(result, crate::value::Value::Int(12), "inspect should pass value through: 3*2*2=12");
    }

    #[test]
    fn no_tap_flag_skips_observer() {
        // With no_tap=true, tap compiles as identity — result should still be correct
        let src = r#"
stage AddOne: Int -> Int = |x| { x + 1 }

seq Pipeline = AddOne |> tap(|v| IO.println("should not print")) |> AddOne

public fn main() -> Int {
    1 |> Pipeline
}
"#;
        set_no_tap_mode(true);
        let program = Parser::parse_str(src, "test.fav").expect("parse");
        let ir = compile_program(&program);
        let artifact = codegen_program(&ir);
        set_no_tap_mode(false);
        let result = exec_artifact_main(&artifact, None).expect("exec");
        assert_eq!(result, crate::value::Value::Int(3), "no_tap: value should still pass through: 1+1+1=3");
    }

    #[test]
    fn inspect_parse_and_compile() {
        // Verify that `inspect` parses correctly as a FlwStep
        let src = r#"
stage Identity: Int -> Int = |x| { x }
seq Pipeline = Identity |> inspect
"#;
        let program = Parser::parse_str(src, "test.fav").expect("parse");
        assert!(!program.items.is_empty(), "program should parse");
        let ir = compile_program(&program);
        assert!(!ir.fns.is_empty(), "should produce IR functions");
    }
}

