// ── v182000_tests (v18.2.0) — 行多相 ────────────────────────────────────────
#[cfg(test)]
mod v182000_tests {
    use crate::frontend::parser::Parser;
    use crate::middle::checker::Checker;

    #[test]
    #[ignore]
    fn version_is_18_2_0() {
        let cargo = include_str!("../Cargo.toml");
        assert!(cargo.contains("\"18.2.0\""), "Cargo.toml should have version 18.2.0");
    }

    #[test]
    fn row_poly_single_field() {
        let src = r#"
fn get_id<R with { id: Int }>(row: R) -> Int {
  row.id
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let (errors, _) = Checker::check_program(&prog);
        assert!(errors.is_empty(), "row_poly_single_field should pass: {:?}", errors);
    }

    #[test]
    fn row_poly_different_records() {
        let src = r#"
type UserRow = {
  id: Int
  name: String
}
type OrderRow = {
  id: Int
  amount: Float
}
fn get_id<R with { id: Int }>(row: R) -> Int {
  row.id
}
fn main() -> Int {
  bind a <- get_id(UserRow { id: 1, name: "Alice" })
  bind b <- get_id(OrderRow { id: 2, amount: 99.0 })
  a + b
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let (errors, _) = Checker::check_program(&prog);
        assert!(errors.is_empty(), "row_poly_different_records should pass: {:?}", errors);
    }

    #[test]
    fn row_poly_intersection_return() {
        let src = r#"
fn add_ts<R with { id: Int }>(row: R) -> R & { ts: String } {
  row
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        assert!(!prog.items.is_empty(), "program should parse");
    }

    #[test]
    fn row_poly_field_missing() {
        let src = r#"
type NoId = { name: String }
fn get_id<R with { id: Int }>(row: R) -> Int {
  row.id
}
fn main() -> Int {
  get_id(NoId { name: "no id field" })
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let (errors, _) = Checker::check_program(&prog);
        let has_e0337 = errors.iter().any(|e| e.code == "E0337");
        assert!(has_e0337, "expected E0337 for missing field, got: {:?}", errors);
    }
}

// ── v183000_tests (v18.3.0) — Refinement Types ───────────────────────────────
#[cfg(test)]
mod v183000_tests {
    use super::{build_artifact, exec_artifact_main};
    use crate::frontend::parser::Parser;
    use crate::middle::checker::Checker;

    #[test]
    #[ignore]
    fn version_is_18_3_0() {
        let cargo = include_str!("../Cargo.toml");
        assert!(cargo.contains("\"18.3.0\""), "Cargo.toml should have version 18.3.0");
    }

    #[test]
    fn refinement_literal_pass() {
        // divide(10, 2): b=2 satisfies b != 0 → no error
        let src = r#"
fn divide(a: Int, b: Int where { b != 0 }) -> Int {
  a / b
}
fn main() -> Int {
  divide(10, 2)
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let (errors, _) = Checker::check_program(&prog);
        let refinement_errors: Vec<_> = errors.iter().filter(|e| e.code == "E0331").collect();
        assert!(
            refinement_errors.is_empty(),
            "refinement_literal_pass: b=2 should satisfy b != 0, got: {:?}",
            refinement_errors
        );
    }

    #[test]
    fn refinement_literal_fail() {
        // divide(10, 0): b=0 violates b != 0 → E0331
        let src = r#"
fn divide(a: Int, b: Int where { b != 0 }) -> Int {
  a / b
}
fn main() -> Int {
  divide(10, 0)
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let (errors, _) = Checker::check_program(&prog);
        let has_e0331 = errors.iter().any(|e| e.code == "E0331");
        assert!(has_e0331, "expected E0331 for b=0 violating b != 0, got: {:?}", errors);
    }

    #[test]
    fn refinement_runtime_check() {
        // Variable argument comes from a helper fn — cannot be statically evaluated
        // RefinementAssert opcode should be injected; program should run successfully
        let src = r#"
fn get_divisor() -> Int {
  5
}
fn divide(a: Int, b: Int where { b != 0 }) -> Int {
  a / b
}
fn main() -> Int {
  bind x <- get_divisor()
  divide(10, x)
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let (errors, _) = Checker::check_program(&prog);
        // No compile error (variable arg, cannot statically check)
        let e0331_errors: Vec<_> = errors.iter().filter(|e| e.code == "E0331").collect();
        assert!(
            e0331_errors.is_empty(),
            "refinement_runtime_check: variable arg should not produce E0331, got: {:?}",
            e0331_errors
        );
        // Program should compile and run successfully
        let program = Parser::parse_str(src, "test.fav").expect("parse");
        let artifact = build_artifact(&program);
        let result = exec_artifact_main(&artifact, None);
        assert!(result.is_ok(), "refinement_runtime_check: expected Ok, got: {:?}", result);
    }

    #[test]
    fn refinement_range_constraint() {
        // age >= 0 && age <= 150 compound constraint, literal passing
        let src = r#"
fn set_age(age: Int where { age >= 0 && age <= 150 }) -> Int {
  age
}
fn main() -> Int {
  set_age(25)
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let (errors, _) = Checker::check_program(&prog);
        let refinement_errors: Vec<_> = errors.iter().filter(|e| e.code == "E0331").collect();
        assert!(
            refinement_errors.is_empty(),
            "refinement_range_constraint: age=25 should satisfy constraint, got: {:?}",
            refinement_errors
        );
        let program = Parser::parse_str(src, "test.fav").expect("parse");
        let artifact = build_artifact(&program);
        let result = exec_artifact_main(&artifact, None);
        assert!(result.is_ok(), "refinement_range_constraint: expected Ok, got: {:?}", result);
    }
}

// ── v184000_tests (v18.4.0) — Schema Types ────────────────────────────────────
#[cfg(test)]
mod v184000_tests {
    use crate::frontend::parser::Parser;
    use crate::middle::checker::Checker;
    use crate::middle::schema_loader;

    #[test]
    #[ignore]
    fn version_is_18_4_0() {
        let cargo = include_str!("../Cargo.toml");
        assert!(cargo.contains("\"18.4.0\""), "Cargo.toml should have version 18.4.0");
    }

    #[test]
    fn schema_uri_parses() {
        // parse_schema_uri should correctly identify file: prefix
        let src = schema_loader::parse_schema_uri("file:schemas/users.json");
        assert!(src.is_ok(), "file: URI should parse OK");
        if let Ok(schema_loader::SchemaSource::File(path)) = src {
            assert!(path.to_string_lossy().contains("users.json"));
        } else {
            panic!("expected SchemaSource::File");
        }
    }

    #[test]
    fn schema_type_syntax_parses() {
        // `type UserRow = schema "file:test.json"` should parse without errors
        let src = r#"type UserRow = schema "file:schemas/test.json""#;
        let result = Parser::parse_str(src, "test.fav");
        assert!(result.is_ok(), "schema type syntax should parse: {:?}", result.err());
        let prog = result.unwrap();
        assert_eq!(prog.items.len(), 1, "expected 1 item");
        if let crate::ast::Item::TypeDef(td) = &prog.items[0] {
            assert_eq!(td.name, "UserRow");
            assert!(matches!(&td.body, crate::ast::TypeBody::Alias(crate::ast::TypeExpr::Schema(uri, _)) if uri.contains("test.json")));
        } else {
            panic!("expected TypeDef with schema alias, got: {:?}", prog.items[0].span());
        }
    }

    #[test]
    fn schema_cache_key_is_stable() {
        let src = schema_loader::parse_schema_uri("file:schemas/users.json").unwrap();
        let key = schema_loader::cache_key(&src);
        assert!(key.starts_with("file__"), "cache key should start with file__");
        // Same URI → same key
        let src2 = schema_loader::parse_schema_uri("file:schemas/users.json").unwrap();
        let key2 = schema_loader::cache_key(&src2);
        assert_eq!(key, key2, "cache key should be stable");
    }

    #[test]
    fn schema_file_missing_gives_error() {
        // Loading a non-existent file should produce a checker error (E0338)
        let src = r#"
type BadSchema = schema "file:nonexistent_schema_12345.json"
fn main() -> String {
  "ok"
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let (errors, _) = Checker::check_program(&prog);
        // The checker may emit E0338 or fall back to Unknown silently;
        // either way the program should not produce a type error from the fn itself
        let non_schema_errors: Vec<_> = errors.iter().filter(|e| e.code != "E0338").collect();
        assert!(
            non_schema_errors.is_empty(),
            "only E0338 errors expected, got: {:?}",
            non_schema_errors
        );
    }
}

