// ── v19.7.0: 事前コンパイルキャッシュ ────────────────────────────────────────

/// Compile a Favnir source string to `.favc` bytes (v19.7.0).
/// Embeds a META section with SHA-256 source hash, timestamp, and compiler version.
pub fn cmd_compile_to_bytes(src: &str, filename: &str) -> Result<Vec<u8>, String> {
    use backend::artifact::{FavcMeta, FvcWriter};
    use sha2::{Digest, Sha256};

    let program =
        Parser::parse_str(src, filename).map_err(|e| format!("{e}"))?;
    let artifact = build_artifact(&program);

    let source_hash: [u8; 32] = Sha256::digest(src.as_bytes()).into();
    let compiled_at = chrono::Utc::now().timestamp() as u64;

    let writer = FvcWriter {
        str_table: artifact.str_table,
        globals: artifact.globals,
        functions: artifact.functions,
        type_metas: artifact.type_metas,
        explain_json: artifact.explain_json,
        meta: Some(FavcMeta {
            source_hash,
            compiled_at,
            compiler_ver: env!("CARGO_PKG_VERSION").to_string(),
        }),
    };
    let mut bytes = Vec::new();
    writer.write_to(&mut bytes).map_err(|e| format!("artifact write error: {e}"))?;
    Ok(bytes)
}

/// Compile a Favnir source file to a `.favc` artifact file (v19.7.0).
pub fn cmd_compile(src_path: &str, out_path: Option<&str>) {
    let src = std::fs::read_to_string(src_path).unwrap_or_else(|e| {
        eprintln!("error: cannot read '{}': {}", src_path, e);
        process::exit(1);
    });
    let favc_path = out_path
        .map(|s| s.to_string())
        .unwrap_or_else(|| src_path.replace(".fav", ".favc"));
    let bytes = cmd_compile_to_bytes(&src, src_path).unwrap_or_else(|e| {
        eprintln!("error: {}", e);
        process::exit(1);
    });
    std::fs::write(&favc_path, &bytes).unwrap_or_else(|e| {
        eprintln!("error: cannot write '{}': {}", favc_path, e);
        process::exit(1);
    });
    println!("[fav] compiled: {} ({} bytes)", favc_path, bytes.len());
}

/// Run a pre-compiled `.favc` artifact from bytes (v19.7.0).
pub fn cmd_run_precompiled_bytes(bytes: &[u8]) -> Result<(), String> {
    let artifact = FvcArtifact::from_bytes(bytes).map_err(|e| {
        format!("error: {e}")
    })?;
    exec_artifact_main(&artifact, None).map(|_| ())
}

/// Run a pre-compiled `.favc` artifact file (v19.7.0).
pub fn cmd_run_precompiled(path: &str) {
    let bytes = std::fs::read(path).unwrap_or_else(|e| {
        eprintln!("error: cannot read '{}': {}", path, e);
        process::exit(1);
    });
    cmd_run_precompiled_bytes(&bytes).unwrap_or_else(|e| {
        eprintln!("{}", e);
        process::exit(1);
    });
}

/// v24.0.0: vm.fav 経由でバイトコードを実行する。
/// v25.9.0: FvcArtifact の全 CompiledFn を program JSON 形式にシリアライズする。
/// 出力形式: {"fn_name":{"code":"hexstring","consts":["name1","name2"]},...}
/// consts は Constant::Int/Float/Str/Name の 4 バリアントをすべて文字列変換して格納する。
pub fn build_vm_program_json(artifact: &FvcArtifact) -> String {
    use crate::backend::codegen::Constant;
    let mut map = serde_json::Map::new();
    for global in &artifact.globals {
        if global.kind == 0 {
            // CompiledFn: name_idx → str_table, fn_idx → functions
            let name = artifact
                .str_table
                .get(global.name_idx as usize)
                .cloned()
                .unwrap_or_default();
            let func = &artifact.functions[global.fn_idx as usize];
            let code_hex: String = func.code.iter().map(|b| format!("{:02x}", b)).collect();
            let consts_arr: Vec<serde_json::Value> = func
                .constants
                .iter()
                .map(|c| match c {
                    Constant::Int(n)   => serde_json::Value::String(format!("{}", n)),
                    Constant::Float(f) => serde_json::Value::String(format!("{}", f)),
                    Constant::Str(s)   => serde_json::Value::String(s.clone()),
                    Constant::Name(s)  => serde_json::Value::String(s.clone()),
                })
                .collect();
            let fn_obj = serde_json::json!({
                "code":   code_hex,
                "consts": consts_arr,
            });
            map.insert(name, fn_obj);
        }
    }
    serde_json::Value::Object(map).to_string()
}

/// v25.9.0: vm.fav 経由で multi-function プログラムを実行する。
/// program_json は build_vm_program_json で生成した JSON 文字列。
/// vm.fav の vm_run_program に program_json を渡して結果を文字列として返す。
pub fn run_via_vm(vm_src: &str, program_json: &str) -> String {
    let escaped = program_json
        .replace('\\', "\\\\")
        .replace('"', "\\\"")
        .replace('\n', "\\n")
        .replace('\r', "\\r")
        .replace('\t', "\\t");
    let src = format!(
        r#"{vm_src}
public fn main() -> String {{
  bind run_r <- vm_run_program("{escaped}")
  match run_r {{
    ok(v)  => vmval_display(v)
    err(e) => e
  }}
}}"#
    );
    let tokens = match crate::frontend::lexer::Lexer::new(&src, "vm_runner.fav").tokenize() {
        Ok(t) => t,
        Err(e) => return format!("run_via_vm lex error: {:?}", e),
    };
    let prog = match crate::frontend::parser::Parser::new(tokens).parse_program() {
        Ok(p) => p,
        Err(e) => return format!("run_via_vm parse error: {:?}", e),
    };
    let artifact = build_artifact(&prog);
    match exec_artifact_main(&artifact, None) {
        Ok(crate::value::Value::Str(s)) => s,
        Ok(other) => format!("{:?}", other),
        Err(e) => format!("run_via_vm exec error: {:?}", e),
    }
}

/// vm_src: vm.fav のソースコード（`include_str!("../self/vm.fav")` 等）
/// bytecode_hex: 実行するバイトコードの hex 文字列（例: "12000016"）
/// globals_entries: globals マップに設定する (index, value_str) のリスト
///   例: &[(0, "hello")] → globals[0] = VMStr("hello")
pub fn run_with_vm(
    vm_src: &str,
    bytecode_hex: &str,
    globals_entries: &[(usize, &str)],
) -> Result<Value, String> {
    let mut globals_setup = String::new();
    for (idx, val) in globals_entries {
        let escaped = val
            .replace('\\', "\\\\")
            .replace('"', "\\\"")
            .replace('\n', "\\n")
            .replace('\r', "\\r")
            .replace('\t', "\\t");
        globals_setup.push_str(&format!(
            "  bind _ <- Mut.set(globals, {}, VMStr(\"{}\"))\n",
            idx, escaped
        ));
    }
    let src = format!(
        r#"{vm_src}
public fn main() -> String {{
  bind globals <- Mut.map()
{globals_setup}  bind hex_r <- Bytes.from_hex("{bytecode_hex}")
  match hex_r {{
    ok(bytes) => {{
      bind run_r <- vm_run_named(bytes, globals)
      match run_r {{
        ok(v)  => vmval_display(v)
        err(e) => e
      }}
    }}
    err(e) => e
  }}
}}"#,
        vm_src = vm_src,
        globals_setup = globals_setup,
        bytecode_hex = bytecode_hex,
    );
    let tokens = crate::frontend::lexer::Lexer::new(&src, "vm_runner.fav")
        .tokenize()
        .map_err(|e| format!("lex: {:?}", e))?;
    let prog = crate::frontend::parser::Parser::new(tokens)
        .parse_program()
        .map_err(|e| format!("parse: {:?}", e))?;
    let artifact = build_artifact(&prog);
    exec_artifact_main(&artifact, None).map_err(|e| format!("exec: {:?}", e))
}

// ── v196000_tests (v19.6.0) — WASM バイナリ最適化 ───────────────────────────
#[cfg(test)]
#[cfg(not(target_arch = "wasm32"))]
mod v196000_tests {
    use crate::backend::wasm_dce::{apply_dce, collect_reachable_fns};
    use crate::backend::wasm_opt_pass::{WasmOptLevel, WasmSizeReport};
    use crate::driver::{WasmBuildConfig, WasmTarget, build_wasm_artifact_with_config};
    use crate::frontend::parser::Parser;
    use crate::middle::compiler::compile_program;

    #[test]
    #[ignore]
    fn version_is_19_6_0() {
        let cargo = include_str!("../Cargo.toml");
        assert!(cargo.contains("19.6.0"), "Cargo.toml should have version 19.6.0");
    }

    #[test]
    fn wasm_dce_reduces_fn_count() {
        // Program with an unreachable helper: DCE should remove it.
        let src = r#"
fn unused_helper() -> Int { 42 }
public fn main(ctx: AppCtx) -> Unit {
    IO.println("hi")
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let mut ir = compile_program(&prog);
        let before_count = ir.fns.len();
        let reachable = collect_reachable_fns(&ir, "main");
        let report = apply_dce(&mut ir, &reachable);
        assert!(
            ir.fns.len() < before_count,
            "DCE should remove unreachable functions: before={}, after={}",
            before_count,
            ir.fns.len()
        );
        assert!(report.removed > 0, "DceReport.removed should be > 0, got {}", report.removed);
    }

    #[test]
    fn wasm_size_report_computes() {
        let report = WasmSizeReport { before: 1000, after: 600 };
        let pct = report.reduction_pct();
        assert!(
            (pct - 40.0).abs() < 0.01,
            "Expected 40.0% reduction, got {:.2}%",
            pct
        );
        let zero = WasmSizeReport { before: 0, after: 0 };
        assert_eq!(zero.reduction_pct(), 0.0, "Zero before should give 0.0%");
    }

    #[test]
    fn wasm_output_correct() {
        // Build with DCE enabled, verify wasmtime can execute it.
        let src = r#"
public fn main() -> Unit {
    IO.println("wasm-ok")
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let config = WasmBuildConfig { dce: true, ..WasmBuildConfig::default() };
        let bytes = build_wasm_artifact_with_config(&prog, &config)
            .expect("build wasm with DCE");
        crate::backend::wasm_exec::wasm_exec_main(&bytes)
            .expect("exec wasm with DCE should succeed");
    }

    #[test]
    fn wasm_wasi_target_builds() {
        // wasm32-wasi target should produce a valid WASM with _start export.
        let src = r#"
public fn main() -> Unit {
    IO.println("wasi-ok")
}
"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let config = WasmBuildConfig {
            target: WasmTarget::Wasm32Wasi,
            dce: true,
            ..WasmBuildConfig::default()
        };
        let bytes = build_wasm_artifact_with_config(&prog, &config)
            .expect("build wasm32-wasi");
        assert_eq!(&bytes[..4], b"\0asm", "WASM magic number check");
        // Validate with wasmtime and check for _start export.
        let engine = wasmtime::Engine::default();
        let module = wasmtime::Module::new(&engine, &bytes)
            .expect("should be valid WASM module");
        let has_start = module.exports().any(|e| e.name() == "_start");
        assert!(has_start, "wasm32-wasi target should export _start");
    }
}

