// ── v197000_tests (v19.7.0) — 事前コンパイルキャッシュ ─────────────────────
#[cfg(test)]
mod v197000_tests {
    use crate::backend::artifact::{ArtifactError, FvcArtifact};
    use crate::driver::{cmd_compile_to_bytes, cmd_run_precompiled_bytes};

    #[test]
    #[ignore]
    fn version_is_19_7_0() {
        assert!(
            include_str!("../Cargo.toml").contains("19.7.0"),
            "Cargo.toml should contain version 19.7.0"
        );
    }

    #[test]
    fn compile_produces_favc() {
        let src = r#"public fn main(ctx: AppCtx) -> Unit { IO.println("hi") }"#;
        let bytes = cmd_compile_to_bytes(src, "test.fav").expect("compile");
        assert_eq!(&bytes[..4], b"FVC\x01", "FVC magic");
        assert_eq!(bytes[4], 0x20, "bytecode version should be 0x20");
    }

    #[test]
    fn precompiled_runs() {
        let src = r#"public fn main(ctx: AppCtx) -> Unit { IO.println("precompiled-ok") }"#;
        let bytes = cmd_compile_to_bytes(src, "test.fav").expect("compile");
        cmd_run_precompiled_bytes(&bytes).expect("run precompiled should succeed");
    }

    #[test]
    fn precompiled_same_output() {
        let src = r#"public fn main(ctx: AppCtx) -> Unit { IO.println("v197-output") }"#;
        let bytes = cmd_compile_to_bytes(src, "test.fav").expect("compile");
        cmd_run_precompiled_bytes(&bytes).expect("precompiled same output");
    }

    #[test]
    fn favc_version_check() {
        // A .favc with an unknown future bytecode version (0xFF) should be rejected.
        let mut fake = b"FVC\x01".to_vec();
        fake.push(0xFF); // unknown future version
        fake.extend_from_slice(&[0, 0, 0]); // padding
        fake.extend_from_slice(&[0, 0, 0, 0]); // str_count = 0
        fake.extend_from_slice(&[0, 0, 0, 0]); // fn_count = 0
        fake.extend_from_slice(&[0, 0, 0, 0]); // global_count = 0
        let err = FvcArtifact::from_bytes(&fake)
            .expect_err("unknown version 0xFF should be rejected");
        assert!(
            matches!(err, ArtifactError::BadVersion(0xFF)),
            "expected BadVersion(0xFF), got {:?}",
            err
        );
    }
}

// ── v205000_tests (v20.5.0) — mmap + SIMD CSV パーサー ────────────────────────
#[cfg(test)]
mod v205000_tests {
    use crate::backend::vm::read_csv_mmap;

    // line!() でテストごとに一意なファイルパスを生成（並列実行時の競合回避）
    macro_rules! temp_csv {
        ($content:expr) => {{
            let mut p = std::env::temp_dir();
            p.push(format!("fav_v205_{}_{}.csv", std::process::id(), line!()));
            std::fs::write(&p, $content).unwrap();
            p
        }};
    }

    #[ignore]
    #[test]
    fn version_is_20_5_0() {
        let cargo = include_str!("../Cargo.toml");
        assert!(cargo.contains("20.5.0"), "Cargo.toml should have version 20.5.0");
    }

    #[test]
    fn csv_mmap_reads_row_count() {
        let path = temp_csv!("name,amount\nalice,100\nbob,200\ncharlie,300\n");
        let result = read_csv_mmap(path.to_str().unwrap());
        let _ = std::fs::remove_file(&path); // clean up before any potential panic
        let batch = result.expect("should read CSV");
        assert_eq!(batch.num_rows(), 3, "expected 3 data rows");
    }

    #[test]
    fn csv_mmap_schema_has_headers() {
        let path = temp_csv!("name,amount\nalice,100\n");
        let result = read_csv_mmap(path.to_str().unwrap());
        let _ = std::fs::remove_file(&path); // clean up before any potential panic
        let batch = result.expect("should read CSV");
        let schema = batch.schema();
        let field_names: Vec<&str> = schema.fields()
            .iter()
            .map(|f| f.name().as_str())
            .collect();
        assert!(field_names.contains(&"name"), "schema should have 'name' field, got {:?}", field_names);
        assert!(field_names.contains(&"amount"), "schema should have 'amount' field, got {:?}", field_names);
    }

    #[test]
    fn csv_mmap_int_column_typed() {
        let path = temp_csv!("id,score\n1,95\n2,87\n3,100\n");
        let result = read_csv_mmap(path.to_str().unwrap());
        let _ = std::fs::remove_file(&path); // clean up before any potential panic
        let batch = result.expect("should read CSV");
        let schema = batch.schema();
        let score_field = schema.field_with_name("score").expect("should have 'score' field");
        let dt = score_field.data_type();
        assert!(
            matches!(dt, arrow::datatypes::DataType::Int64 | arrow::datatypes::DataType::Int32),
            "score should be integer type, got {:?}", dt
        );
    }

    #[test]
    fn csv_mmap_returns_arrow_batch() {
        let path = temp_csv!("x,y\n1,2\n3,4\n");
        let result = read_csv_mmap(path.to_str().unwrap());
        let _ = std::fs::remove_file(&path); // clean up before any potential panic
        assert!(result.is_ok(), "read_csv_mmap should succeed for valid CSV");
        assert_eq!(result.unwrap().num_rows(), 2);
    }
}

