// ── v259000_tests (v25.9.0) — vm.fav Phase 6（CallNamed 実装）─────────────
#[cfg(test)]
mod v259000_tests {
    /// vm.fav に CallNamed(Int, Int) opcode が存在することを確認
    #[test]
    fn vm_fav_has_call_named_opcode() {
        let vm_fav = include_str!("../self/vm.fav");
        assert!(vm_fav.contains("CallNamed(Int, Int)"),
            "vm.fav must contain 'CallNamed(Int, Int)'");
        assert!(vm_fav.contains("CallNamed(ni, ac)"),
            "vm.fav must contain 'CallNamed(ni, ac)' in opcode_to_string");
    }

    /// vm.fav に vm_run_program が存在することを確認
    #[test]
    fn vm_fav_has_vm_run_program() {
        let vm_fav = include_str!("../self/vm.fav");
        assert!(vm_fav.contains("fn vm_run_program("),
            "vm.fav must contain 'fn vm_run_program'");
        assert!(vm_fav.contains("build_program_lists"),
            "vm.fav must contain 'build_program_lists'");
    }

    /// vm.fav に 0x56 デコーダーが存在することを確認
    #[test]
    fn vm_fav_decoder_handles_0x56() {
        let vm_fav = include_str!("../self/vm.fav");
        assert!(vm_fav.contains("0x56 => decode_byte_with_u16x2_le"),
            "vm.fav must contain '0x56 => decode_byte_with_u16x2_le'");
        assert!(vm_fav.contains("fn decode_byte_with_u16x2_le"),
            "vm.fav must contain 'fn decode_byte_with_u16x2_le'");
    }

    /// build_vm_program_json が FvcArtifact から JSON を生成してパニックしないことを確認
    #[test]
    fn build_vm_program_json_smoke() {
        use crate::frontend::parser::Parser;
        let src = r#"public fn main() -> Int { 42 }"#;
        let prog = Parser::parse_str(src, "test.fav").expect("parse");
        let artifact = crate::driver::build_artifact_pub(&prog);
        let json = crate::driver::build_vm_program_json(&artifact);
        assert!(json.contains("\"main\""), "program json must contain 'main' key");
        assert!(json.contains("\"code\""), "program json must contain 'code' field");
        assert!(json.contains("\"consts\""), "program json must contain 'consts' field");
    }

    /// multi-function プログラムを vm.fav 経由で実行し正しい結果を返すことを確認
    /// vm.fav は CallNamed(0x56) opcode でユーザー定義関数を呼ぶ。
    /// Rust コンパイラは LoadGlobal+Call を使うため、ここでは手動クラフトした bytecode を使う。
    /// helper: LoadLocal(0) + LoadLocal(0) + Add + Return = x+x
    /// main:   Const(3) + CallNamed(0,1) + Return, consts=["helper"]
    #[test]
    fn run_via_vm_correct_result() {
        // helper(x) = x + x, main calls helper(3) → expects "6"
        // helper bytecode: 10 00 00 10 00 00 20 16
        // main   bytecode: 01 03 00 56 00 00 01 00 16, consts: ["helper"]
        let program_json = r#"{"helper":{"code":"1000001000002016","consts":[]},"main":{"code":"010300560000010016","consts":["helper"]}}"#;
        let vm_src = include_str!("../self/vm.fav");
        let result = crate::driver::run_via_vm(vm_src, program_json);
        assert_eq!(result, "6", "helper(3)=3+3=6 expected, got: {}", result);
    }

    /// CHANGELOG.md に [v25.9.0] エントリが存在することを確認
    #[test]
    fn changelog_has_v25_9_0() {
        let content = include_str!("../../CHANGELOG.md");
        assert!(content.contains("[v25.9.0]"),
            "CHANGELOG.md must contain '[v25.9.0]'");
    }

    /// benchmarks/v25.9.0.json が存在することを確認
    #[test]
    fn benchmark_v25_9_0_exists() {
        let json = include_str!("../../benchmarks/v25.9.0.json");
        assert!(json.contains("25.9.0"), "benchmarks/v25.9.0.json must contain version");
        assert!(json.contains("2035"), "benchmarks/v25.9.0.json must have test_count 2035");
    }
}

